import { useState, useMemo, useEffect, useRef, useCallback } from "react";

// ─── DADOS DO CÓDIGO DE NORMAS JUDICIAIS — TJCE (Provimento 02/2021/CGJCE) ───
const CHAPTERS = [{"num":"I","title":"DISPOSIÇÕES GERAIS","articles":[{"n":"1º","t":"A presente Consolidação de Normas e Procedimentos da Corregedoria-Geral da Justiça do Estado do Ceará reúne todos os normativos expedidos e vigentes, direcionados aos serviços judiciários de primeira instância do Estado do Ceará e às Turmas Recursais.","v":["geral"],"th":[]},{"n":"2º","t":"Sem prejuízo do disposto nesta Consolidação, o magistrado responsável pela Unidade Judiciária ou o Diretor do Fórum, ao seu critério, a fim de atender às circunstâncias locais, poderão baixar normas complementares, comunicando o fato à Corregedoria.","v":["geral"],"th":[]},{"n":"3º","t":"Os magistrados e servidores do Poder Judiciário do Estado do Ceará ficam obrigados a cumprir integralmente as normas desta Consolidação, ressalvadas as disposições em contrário.","v":["geral"],"th":[]}]},{"num":"II","title":"DA CORREGEDORIA-GERAL DA JUSTIÇA","articles":[{"n":"4º","t":"A Corregedoria-Geral da Justiça, Órgão da Administração do Poder Judiciário Estadual, exerce o controle interno sobre a regularidade da função jurisdicional de primeira instância em todo 18 o Estado do Ceará, bem como a fiscalização, disciplina e orientação administrativa, nos termos da Lei de Organização Judiciária do Estado, do Regimento Interno e atos normativos expedidos pelo Conselho Nacional de Justiça.","v":["geral"],"th":[]},{"n":"5º","t":"A estrutura organizacional e o funcionamento da Corregedoria-Geral da Justiça são regulamentadas pela Resolução 02/2019 do Tribunal de Justiça do Estado do Ceará, Lei nº 16.208/2017, Lei nº 16.397/2017, bem como pelo seu Regimento Interno e leis aplicáveis a matéria. Seção II Das Atribuições","v":["geral"],"th":[]},{"n":"6º","t":"As atribuições específicas do Corregedor-Geral da Justiça, dos juízes corregedores auxiliares e demais cargos da estrutura organizacional da Corregedoria-Geral da Justiça estão regulamentadas pelo Regimento Interno. Seção III Da Atividade Fiscalizatória Subseção I Disposições Gerais","v":["geral"],"th":[]},{"n":"7º","t":"As correições e inspeções a cargo da Corregedoria-Geral da Justiça serão realizadas pelo Corregedor-Geral da Justiça, de iniciativa própria ou por determinação do Tribunal de Justiça, do Conselho Superior da Magistratura ou da Corregedoria Nacional da Justiça. Parágrafo único. As correições e inspeções poderão ser realizadas pelos juízes corregedores auxiliares por delegação do Corregedor-Geral.","v":["geral"],"th":[]},{"n":"8º","t":"Fica instituído, conforme a Lei n° 16.397/2017 - Lei de Organização Judiciária do Estado do Ceará, o sistema de zoneamento de Comarcas adjacentes para os fins exclusivos do efetivo desempenho das práticas correcionais, fixando os limites geográficos para elaboração, de maneira a 19 abarcar e a abranger a integridade do Estado.","v":["geral"],"th":[]},{"n":"9º","t":"Para os fins do artigo anterior, ficam estabelecidas 14 (quatorze) Zonas Judiciárias no Estado do Ceará, com as suas Comarcas integrantes e respectivas Sedes, conforme o disposto abaixo: ZONAS JUDICIÁRIAS ZONA 1ª 2ª 3ª 4ª 5ª 6ª 7ª 8ª COMARCA SEDE ÁREA DE JURISDIÇÃO DA ZONA JUDICIÁRIA Abaiara, Altaneira, Antonina do Norte, Araripe, Assaré, Aurora, Barbalha, Barro, Brejo Santo, Campos Sales, Caririaçu, Crato, Farias JUAZEIRO DO Brito, Granjeiro, Jardim, Jati, Juazeiro do Norte, Lavras da NORTE Mangabeira, Mauriti, Milagres, Missão Velha, Nova Olinda, Penaforte, Porteiras, Potengi, Salitre, Santana do Cariri, Tarrafas e Várzea Alegre. Acopiara, Baixio, Cariús, Catarina, Cedro, Icó, Iguatu, Ipaumirim, Jucás, Orós, Quixelô, Saboeiro e Umari. Banabuiú, Choró, Deputado Irapuan Pinheiro, Milhã, Mombaça, Pedra QUIXADÁ Branca, Piquet Carneiro, Quixadá, Quixeramobim, Senador Pompeu e Solonópole. Alto Santo, Ererê, Ibaretama, Ibicuitinga, Iracema, Jaguaretama, Jaguaribara, Jaguaribe, Limoeiro do Norte, Morada Nova, Palhano, RUSSAS Pereiro, Potiretama, Quixeré, Russas, São João do Jaguaribe e Tabuleiro do Norte. Aquiraz, Cascavel, Caucaia, Chorozinho, Eusébio, Guaiúba, CAUCAIA Horizonte, Itaitinga, Maracanaú, Maranguape, Pacajus, Pacatuba, MARACANAÚ Palmácia, Paracuru, Paraipaba, Pindoretama, São Gonçalo do Amarante e Trairi. Amontada, Apuiarés, General Sampaio, Irauçuba, Itapajé, Itapipoca, ITAPIPOCA Miraíma, Pentecoste, São Luís do Curu, Tejuçuoca, Tururu, Umirim e Uruburetama. Alcântaras, Cariré, Coreaú, Forquilha, Graça, Groaíras, Massapé,","v":["geral"],"th":["execucao"]},{"n":"10","t":"A definição das Zonas Judiciárias pelas quais cada juiz corregedor auxiliar ficará responsável para fiscalização, constará em normativo próprio a ser expedido pelo Corregedor-Geral da Justiça no início de cada gestão.","v":["geral"],"th":[]},{"n":"11","t":"A Comarca de Fortaleza e a 5ª (quinta) zona serão de competência de todos os juízes corregedores auxiliares.","v":["geral"],"th":[]},{"n":"12","t":"As Correições-Gerais na Comarca de Fortaleza, Juazeiro do Norte, Crato, Sobral, Caucaia e Maracanaú serão realizadas por, no mínimo, 3 (três) juízes corregedores auxiliares para assegurar a efetividade e a celeridade das atividades locais.","v":["geral"],"th":[]},{"n":"13","t":"Os atos correcionais poderão ser realizados, individualmente ou em conjunto, no âmbito dos destacamentos zonais, a critério e sob a supervisão do Corregedor-Geral da Justiça.","v":["geral"],"th":[]},{"n":"14","t":"As correições serão ordinárias, extraordinárias e permanentes, na forma da lei, e executadas nas modalidades virtuais e presenciais. Parágrafo único. As correições virtuais serão realizadas por meio de sistemas de aferição da produtividade das unidades jurisdicionais e consistirão na análise dos dados captados pela Corregedoria-Geral da Justiça.","v":["geral"],"th":[]},{"n":"15","t":"As correições gerais ordinárias são realizadas anualmente, obedecendo ao calendário previamente elaborado no início de cada gestão do Corregedor-Geral da Justiça, abrangendo os serviços judiciais das comarcas sede e vinculadas. § 1º As correições gerais serão realizadas na sede das comarcas ou na própria Corregedoria-Geral quando se tratar de processos virtuais, por meio de edital do Corregedor-Geral convocando, previamente, as autoridades judiciárias e os servidores, com indicação do dia, hora e local em que os trabalhos serão realizados. § 2º O Corregedor-Geral, ou o Juiz Auxiliar por ele designado, disporá de livre ingresso nos locais onde se processem as atividades sob correição, podendo, se entender conveniente, requisitar e acessar documentos, livros, registros de computadores ou qualquer outro dado ou elemento de prova que repute relevante para os propósitos da correição. 21 § 3º Em todas as correições será intimado a comparecer o Representante do Ministério Público.","v":["geral"],"th":["citacao"]},{"n":"16","t":"Estão sujeitos às correições gerais: I - os processos findos, iniciados no triênio anterior à correição, e os pendentes, exceto: a) os que estiverem com recursos interpostos, se ainda não esgotado o prazo para alegações e remessa; b) os conclusos para julgamento, não excedidos os prazos legais; c) os preparados para o júri, salvo quando não houver sessão convocada; II - todos os livros obrigatórios nas unidades judiciais ainda não integralmente virtualizadas;","v":["geral"],"th":["audiencias","prazos"]},{"n":"17","t":"Na correição, compete ao Corregedor-Geral e aos juízes corregedores auxiliares, por delegação: I - examinar a legalidade dos títulos dos servidores; II - observar a conduta funcional dos magistrados de primeiro grau e dos servidores do Poder Judiciário, com relação ao cumprimento dos deveres e atribuições, bem como à permanência na sede da comarca autônoma, vinculada ou distrito judiciário; III - fiscalizar a: a) administração das pessoas e bens de órfãos, incapazes, ausentes e nascituros; b) execução dos testamentos e administração das fundações; c) execução das leis e regimentos referentes à arrecadação e administração de heranças jacentes; d) existência dos livros obrigatórios na unidade judicial ainda não integramente virtualizada, bem como se devidamente autenticados, encadernados e escriturados; IV - examinar: a) os autos, os livros e os papéis, findos ou em andamento, verificando se adequadamente guardados, conservados e catalogados, bem como se distribuídos e processados na forma da lei; b) o estado de conservação e manutenção do Fórum; c) se há processos sem tramitação regular, físicos e virtuais, detectando as causas, despachando-os em correição; 22 d) se regularmente cobrados emolumentos, taxas e outros tributos devidos à União, ao Estado e ao Município; e) se as custas são cobradas nos estritos termos da Lei; f) se as autoridades judiciárias são assíduas em deferir e ministrar justiça às partes, e se mantêm conduta irrepreensível na vida pública e privada; V - levar ao conhecimento da Ordem dos Advogados, do Procurador-Geral da Justiça, do Chefe da Defensoria Pública e do Secretário de Segurança Pública e Defesa da Cidadania, falta atribuída, respectivamente, a advogado, representante do Ministério Público, Defensor Público e autoridade policial; VI - instaurar processo, na hipótese de abandono de cargo pelo Juiz, verificando se semelhante procedimento foi observado pelo juízo competente, no caso de servidor, notário e registrador;","v":["geral"],"th":["mandados","execucao"]},{"n":"18","t":"Verificada a existência de autos e papéis com antiguidade superior a 20 (vinte) anos, determinará o Corregedor a sua remessa ao Arquivo Público do Estado, podendo propor ao Tribunal de Justiça ou ao Conselho Superior da Magistratura a incineração daqueles sem valor histórico.","v":["geral"],"th":[]},{"n":"19","t":"O Corregedor-Geral e os juízes corregedores auxiliares, por delegação, darão audiência aos presos ou adolescentes internados para receber deles as queixas ou reclamações, providenciando as medidas cabíveis; visitarão estabelecimentos de internação, cadeias, estabelecimentos penitenciários, assim como outros similares existentes na comarca, verificando se: I - os edifícios e dependências são higiênicos, seguros e aparelhados; II - há pessoas detidas ou internadas ilegalmente ou de modo diverso do prescrito em lei, prevendo acerca de sua soltura; III - as pessoas detidas ou internadas são alimentadas, vestidas, abrigadas e tratadas adequadamente. Parágrafo único. Observada a falta de higiene, segurança ou aparelhamento, representará ao Tribunal de Justiça para a adoção das providências indispensáveis.","v":["geral"],"th":["audiencias","presos"]},{"n":"20","t":"O Corregedor-Geral examinará também se há inquéritos paralisados em poder das autoridades policiais ou se elas deixam de instaurá-los, comunicando o fato ao Conselho Superior da Magistratura, ao Secretário da Segurança Pública e Defesa Social e ao Secretário de Administração Penitenciária do Estado do Ceará. 23","v":["geral"],"th":[]},{"n":"21","t":"O Corregedor-Geral e os juízes corregedores auxiliares, por delegação, darão audiência a advogados, a representantes da imprensa e das comunidades do Juízo em correição.","v":["geral"],"th":["audiencias"]},{"n":"22","t":"O Corregedor-Geral fixará prazo razoável para: I - julgamento dos processos conclusos ou aguardando cumprimento de expediente a cargo da secretaria das unidades judiciais com excesso de prazo; II - regularização dos livros exigidos por lei nas unidades não integralmente virtualizadas; III - organização dos arquivos, tombamento de móveis e utensílios; IV - emenda de erros, abusos ou omissões verificados.","v":["geral"],"th":["audiencias","prazos","mandados","secretaria"]},{"n":"23","t":"Ordenará o Corregedor: I - prestação ou reforço de fianças omitidas ou insuficientes; II - registro e inscrição de testamentos e tomadas de contas dos tutores, curadores e testamenteiros, síndicos, liquidatários, administradores de fundações, e demais responsáveis; III - nomeação de tutores e curadores a menores, ausentes, interditos e à herança jacente; IV - especialização da hipoteca legal, nos casos em que couber atuar de ofício; V - conclusão de inventários, arrecadações e partilhas em que haja interesse do Estado ou de incapazes; VI - destinação legal a bens ou valores irregularmente conservados em poder de funcionários ou particulares.","v":["geral"],"th":[]},{"n":"24","t":"Durante a correição, o Corregedor-Geral ou os juízes corregedores auxiliares receberão as reclamações e queixas, escritas ou verbais, apresentadas por auxiliares da Justiça ou qualquer pessoa, mandando reduzir a termo as que forem formuladas verbalmente. § 1º Proceder-se-á na forma disciplinada em lei ou no Regimento Interno da Corregedoria-Geral da Justiça do Estado do Ceará se o reclamado for o juiz. § 2º Se o reclamado for servidor, notário ou registrador, constatada a procedência preliminarmente, determinar-se-á abertura de procedimento administrativo próprio perante a autoridade competente.","v":["geral"],"th":[]},{"n":"25","t":"O Corregedor-Geral verificará se as recomendações baixadas pelos juízes corregedores permanentes e pelas correições gerais, parciais e inspeções anteriores foram cumpridas. 24 Parágrafo único. Observado o não cumprimento das recomendações baixadas, o CorregedorGeral, a depender da gravidade do caso ou hipótese de reiterada desobediência, baixará portaria de abertura de sindicância ou processo administrativo para apuração do fato.","v":["geral"],"th":["mandados","atos_ordinatorios"]},{"n":"26","t":"Findos os trabalhos da correição, o Corregedor-Geral, na presença da autoridade judiciária, do Ministério Público e dos servidores convocados dará conhecimento das cotas e despachos proferidos nos autos, nos livros e nos papéis examinados, fazendo a respectiva leitura. § 1º Em seguida, mandará lavrar, em livro próprio, meio eletrônico ou no termo de audiência, por servidor designado para secretariar os trabalhos, uma ata, em que serão especificados os achados da correição, os exames feitos, as irregularidades verificadas, as cotas e os provimentos expedidos; bem como as medidas adotadas para correção e normalização das atividades. § 2º Proferida a leitura da ata, será colhida a assinatura, por meio físico ou digital, do CorregedorGeral ou, por delegação, dos juízes corregedores auxiliares, das autoridades judiciárias, do representante do Ministério Público e dos servidores judiciais presentes.","v":["geral"],"th":["audiencias","secretaria","atos_ordinatorios"]},{"n":"27","t":"Os provimentos relativos a atos praticados pelos juízes não constarão, especificamente, da ata final, sendo-lhes transmitidos em caráter reservado pelo Corregedor-Geral ou pelos juízes corregedores auxiliares.","v":["geral"],"th":[]},{"n":"28","t":"As correições abrangerão também sindicâncias sobre o procedimento funcional das autoridades judiciárias, servidores e delegatários das serventias extrajudiciais.","v":["geral"],"th":[]},{"n":"29","t":"O Corregedor-Geral da Justiça ou os juízes corregedores auxiliares, por delegação, poderão voltar à sede da comarca, a qualquer tempo, para verificação do cumprimento das recomendações, orientações e provimentos expedidos.","v":["geral"],"th":["mandados"]},{"n":"30","t":"As correições parciais terão por objetivo a apuração de fatos que as determinarem, compreendendo uma unidade judicial, aplicando-se, no que couber, os preceitos das correições gerais.","v":["geral"],"th":[]},{"n":"31","t":"A correição ordinária será geral e periódica. § 1º O calendário das correições gerais será publicado até o dia 15 de fevereiro de cada ano e contemplará as comarcas, as unidades e as turmas recursais a serem fiscalizadas. § 2º A correição periódica independe da fixação de calendário e será realizada pelos juízes e diretores do foro, anualmente, devendo ser comunicada à Corregedoria-Geral da Justiça para anotações pertinentes. 25","v":["geral"],"th":[]},{"n":"32","t":"A correição extraordinária ocorrerá a qualquer tempo por decisão do Corregedor-Geral da Justiça e obedecerá, no que couber, ao procedimento da correição ordinária geral.","v":["geral"],"th":[]},{"n":"33","t":"A correição permanente consiste na fiscalização rotineira das atividades jurisdicionais e administrativas inerentes ao cargo.","v":["geral"],"th":[]},{"n":"34","t":"As inspeções, em que serão aplicadas as normas das correições, no que for cabível, visam a verificação da regularidade dos serviços judiciais de uma ou mais Comarcas, unidades judiciais ou SEJUDs, a partir do exame de parte do acervo processual em tramitação, por amostragem. (Redação conferida pelo Prov. nº 04/2022/CGJCE, DJe de 29/04/2022).","v":["geral"],"th":[]},{"n":"35","t":"As inspeções dos serviços judiciais de 1º grau realizadas pela Corregedoria-Geral da Justiça consistirão na análise, seja no formato virtual ou presencial, de todos os aspectos necessários ao exame da regularidade dos serviços prestados pelas unidades judiciárias e/ou SEJUDs. (Redação conferida pelo Prov. nº 04/2022/CGJCE, DJe de 29/04/2022). § 1º As inspeções judiciais poderão ser realizadas pelo Corregedor-Geral da Justiça ou por juiz corregedor auxiliar por ele designado. § 2º Deverá ser realizada, anualmente, a inspeção em pelo menos 35% (trinta e cinco por cento) das unidades judiciais instaladas, ainda que por amostragem; § 3º Nenhum módulo judicial ou SEJUD poderá permanecer sem inspeção desta Corregedoria por prazo superior a 03 (três) anos. (Redação conferida pelo Prov. nº 04/2022/CGJCE, DJe de 29/04/2022).","v":["geral"],"th":["prazos"]},{"n":"36","t":"O Corregedor-Geral poderá realizar inspeções sobre fatos isolados, independente de comunicação prévia.","v":["geral"],"th":[]},{"n":"37","t":"Durante o procedimento de inspeção das unidades judiciárias serão ordinariamente verificados os aspectos abaixo listados, sem prejuízo de outros cuja relevância venha a ser reconhecida: (Redação conferida pelo Prov. nº 04/2022/CGJCE, DJe de 29/04/2022). I - Acervo processual (físico/eletrônico/digitalizado): 26 a) processos judiciais; b) procedimentos Investigatórios; c) cartas; II - Dados de Produtividade: a) desempenho (sentenças, decisões e audiências); b) fluxo processual (novos, conclusos, julgados pendentes de baixa, suspensos, baixados); III - Gestão administrativa: a) tramitação de processos prioritários; b) processos sem movimentação há mais de 100 (cem) dias; c) saneamento de dados - classes e assuntos em conformidade com as tabelas processuais unificadas - CNJ; d) cumprimento das Metas; e) gerenciamento das filas de trabalho; (Redação conferida pelo Provimento nº 16/2023/CGJCE, DJeA de 19/12/2023) f) alimentação dos dados e informações nos sistemas; g) observância das normas editadas pelo Conselho Nacional de Justiça, Corregedoria Nacional de Justiça, Corregedoria-Geral da Justiça do Estado de Ceará e Tribunal de Justiça do Estado do Ceará; IV - Processos investigatórios relacionados ao serviço extrajudicial (Sindicâncias e PAD); V - Processos de representação por excesso de prazo; VI - Uso do Sistema de Videoconferência.","v":["geral"],"th":["audiencias","prazos","mandados"]},{"n":"37-A","t":"As inspeções das SEJUDs ocorrerão de forma simultânea com as inspeções das unidades judiciárias por elas assistidas, conforme o cronograma inspecional publicizado pela Corregedoria. (Redação conferida pelo Provimento nº 16/2023/CGJCE, DJeA de 19/12/2023)","v":["geral"],"th":[]},{"n":"38","t":"Nas inspeções também se fiscalizará, no que couber: (Redação conferida pelo Prov. nº 04/2022/CGJCE, DJe de 29/04/2022). 27 I - residência de juízes e serventuários de Justiça na sede da comarca ou distrito judiciário, lugares onde servem, assim como cumprimento de todos os deveres com exatidão; II - ausência costumeira de autoridades e serventuários dos postos de trabalho, sem cientificação superior, ou fora dos casos permitidos em lei; III - designação e realização de audiências com regularidade; IV - assiduidade em deferir e ministrar Justiça às partes e manutenção de conduta compatível com as funções públicas exercidas; V - distribuição de processos equitativa e legal.","v":["geral"],"th":["audiencias","mandados","secretaria"]},{"n":"39","t":"Durante a realização das inspeções judiciais pela Corregedoria, não haverá suspensão dos prazos, interrupção de distribuição, transferência das audiências agendadas, nem prejuízo ao atendimento às partes e advogados.","v":["geral"],"th":["audiencias","prazos","secretaria"]},{"n":"40","t":"Encerrados os trabalhos, será elaborado relatório circunstanciado, devidamente preenchido com a inserção dos dados mínimos indicados, contendo, especificada e objetivamente, a descrição das irregularidades encontradas e os esclarecimentos eventualmente prestados por magistrados ou servidores, as determinações para solução dos achados identificados, as recomendações preventivas de erros e/ou que visem ao aperfeiçoamento do serviço judicial, as reclamações recebidas contra a unidade ou o(a) magistrado(a) durante a inspeção, as boas práticas e quaisquer outros registros considerados relevantes. (Redação conferida pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023). § 1º O prazo para a entrega do relatório circunstanciado de que trata este artigo será de até 30 (trinta) dias contados da data do término dos trabalhos da inspeção. § 2º Analisado o relatório de inspeção pelo(a) Corregedor(a), havendo recomendações e/ou determinações a serem atendidas, notificar-se-á o(a) magistrado(a) inspecionado e, ao final do prazo estabelecido, os autos devem ser enviados ao(a) Juiz(a) Corregedor(a) Auxiliar para a emissão de novo parecer. (Redação conferida pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) § 3º Ultimadas as providências, os autos serão remetidos a Coordenadoria de Correição e Monitoramento das Unidades Judiciárias desta Corregedoria (CCMUJ) que, após as anotações de praxe, os encaminhará ao Conselho Superior da Magistratura. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023)","v":["geral"],"th":["prazos"]},{"n":"41","t":"(Revogado pelo Provimento nº 16/2023/CGJCE, DJeA de 19/12/2023) 28","v":["geral"],"th":[]},{"n":"42","t":"As unidades judiciárias/SEJUD incluídas no cronograma de inspeções judiciais realizadas por esta Corregedoria deverão preencher o Formulário Eletrônico de Inspeções Judiciais, nos termos do Anexo I (Unidades Judiciais), Anexo XIX (SEJUD - Fortaleza) e Anexo XX (SEJUD CARIRI) do presente normativo. (Redação conferida pelo Prov. nº 06/2025/CGJCE, DJeA de 04/08/2025) § 1º O(A) Juiz(a) Corregedor(a) Auxiliar responsável pela inspeção deverá remeter a unidade/SEJUD a ser inspecionada, via e-mail, o formulário referido no caput. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) § 2º Fica responsável pelo preenchimento e remessa do formulário eletrônico à Corregedoria, no prazo de 10 (dez) dias, a contar do seu recebimento, o(a) Juiz(a) titular da unidade judiciária ou o(a) Juiz(a) Coordenador(a) da SEJUD inspecionada, ou aquele(a) que esteja respondendo pela mesma. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023)","v":["geral"],"th":["prazos"]},{"n":"42-A","t":"Dentre os instrumentos de fiscalização e correção, poderá a Corregedoria Geral da Justiça instituir o monitoramento de unidade judicial, quando, no exercício de suas regulares atribuições, verificar acúmulo processual, com tendência de aumento de acervo, e/ou quadro de morosidade excessiva nas seguintes situações: (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) a) unidade que tenha sido auxiliada por programa de acompanhamento, força-tarefa ou mutirão; ou b) elevada criticidade de indicadores de desempenho e de produtividade por falta de gestão adequada, procedimentos internos equivocados ou ausência de controle situacional da unidade, e não seja indicada a inclusão no Programa Permanente de Acompanhamento das Unidades Judiciárias. Parágrafo único. Os subsídios para aferição das hipóteses de monitoramento podem ser extraídos dos sistemas processuais e de estatística, bem como do que for apurado em inspeção, correição, autoinspeção ou em qualquer outro procedimento desta Corregedoria Geral da Justiça. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) 29","v":["geral"],"th":[]},{"n":"42-B","t":"A medida tramitará no PJeCor sob a classe Pedido de Providências e dependerá de decisão do(a) Corregedor(a)-Geral da Justiça, que apontará os indicadores críticos da unidade sobre os quais se desenvolverá o monitoramento, fixará prazo mínimo de 90 (noventa) dias para a adequação dos métodos de trabalho e alcance dos resultados iniciais e ordenará a notificação do(a) magistrado(a) responsável. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023)","v":["geral"],"th":["prazos","citacao"]},{"n":"42-C","t":"O processo do monitoramento será estruturado, basicamente, por plano gerencial ou de ação específico por índice de desempenho ou de produtividade a ser melhorado, contendo as providências necessárias e os prazos de conclusão segundo a duração da medida fixada pela Corregedoria Geral da Justiça. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) § 1º O plano gerencial ou de ação será elaborado e encaminhado pelo(a)magistrado(a) no prazo de 10 (dez) dias da notificação da instauração do monitoramento, conforme art. 42-B, e incluirá, caso exista a previsão na estrutura da unidade, a participação do(a) Juiz(a) Auxiliar Privativo. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) § 2º A execução do plano exigirá do(a) magistrado(a) o encaminhamento mensal dos resultados obtidos por sua autogestão controlada, estimulando o senso de responsabilidade e o comprometimento indispensáveis para desincumbir-se da medida fiscalizatória. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023)","v":["geral"],"th":["prazos","citacao","execucao"]},{"n":"42-D","t":"O monitoramento de unidade judicial será acompanhado pelos(as) Juízes(as) Corregedores(as) Auxiliares, conforme critério preestabelecido de distribuição, que, para instrução dos respectivos processos, poderão solicitar relatórios de desempenho e de produtividade à Coordenadoria de Correição e Monitoramento das Unidades Judiciárias (CCMUJ). (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) § 1º Ao final do prazo fixado para o monitoramento, as(os) Juízes(as) Corregedores(as) Auxiliares poderão sugerir a prorrogação da medida ou, havendo tendência de melhora do(s) indicador(es), o seu encerramento. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) § 2º Constatado que os resultados não foram suficientes para neutralizar os entraves de eficiência da atividade jurisdicional, uma vez que mantida a criticidade, ou descumprida alguma formalidade exigida para o monitoramento, deverá ser feita ampla análise sob o enfoque da possível instauração de procedimento no âmbito disciplinar em desfavor do(a) magistrado(a) responsável. (Incluído pelo Prov. nº 16/2023/CGJCE, DJeA de 19/12/2023) 30","v":["geral"],"th":["prazos","secretaria"]},{"n":"43","t":"Funcionará, no âmbito da Corregedoria-Geral da Justiça, o Núcleo de Monitoramento do Perfil de Demandas (NUMOPEDE), instituído com as atribuições abaixo especificadas: I - monitorar demandas dos serviços judiciários; II - identificar demandas fraudulentas e eventos atentatórios à dignidade da Justiça, inclusive por meio da centralização do recebimento de notícias de condutas fraudulentas reiteradas; III - prevenir eventos comprometedores da funcionalidade, a eficiência e/ou a correção dos serviços judiciários; IV - centralizar as informações sobre distribuições de ações, perfis de demandas e práticas fraudulentas reiteradas; V - extrair, colher e tratar dados processuais para disponibilização de informações aos juízes de direito e aos servidores, observados os parâmetros legais; VI - elaborar estudos e publicar subsídios técnicos aos magistrados e servidores visando à identificação de demandas em duplicidade, em desacordo com preceitos legais ou situação de indevida massificação da litigiosidade; VII - apoiar magistrados e servidores no encaminhamento das soluções adotadas; VIII - propor ao Corregedor-Geral de Justiça solicitação de apuração às autoridades competentes, nas hipóteses legais, ou o estabelecimento de cooperação técnica, científica e operacional: a) com outros Órgãos do Poder Judiciário; b) com o Ministério Público, Defensoria Pública, Ordem dos Advogados do Brasil, Tribunais de Contas do Estado do Ceará, Receita Federal do Brasil, Polícias Judiciárias e outras instituições; IX - traçar estratégias de atuação destinadas à redução do ajuizamento de demandas fraudulentas e eventos atentatórios à dignidade da justiça; X - estimular as boas práticas relacionadas à temática; XI - realizar atividades correlatas atribuídas pelo Corregedor-Geral da Justiça; 31 Parágrafo único. Os fatos que tiverem interface total ou parcial com as atribuições do Núcleo de Gerenciamento de Precedentes - NUGEP serão a ele encaminhados, para as providências no seu âmbito de atuação;","v":["geral"],"th":["citacao"]},{"n":"44","t":"O NUMOPEDE será composto pelos seguintes integrantes: I - 2 (dois) Juízes corregedores auxiliares da Corregedoria-Geral da Justiça; II - Diretor-Geral da Corregedoria-Geral da Justiça; III - Gerente de Correição e Apoio às Unidades Judiciárias da Corregedoria-Geral da Justiça; IV - Coordenador de Correição e Monitoramento das Unidades Judiciárias da Corregedoria-Geral da Justiça; V - Coordenador de Orientação e Padronização da Corregedoria-Geral da Justiça. § 1º Os membros do NUMOPEDE serão indicados e designados pelo Corregedor-Geral da Justiça, mediante ato normativo próprio. § 2º Poderão ser, eventualmente, convidados para participar do NUMOPEDE, magistrados e/ou servidores do Poder Judiciário, a fim de contribuir com a execução das atividades previstas no presente provimento.","v":["geral"],"th":["execucao"]},{"n":"45","t":"Os demais setores da Corregedoria-Geral da Justiça, dentro das suas competências, atuarão em auxílio ao NUMOPEDE, quando necessário.","v":["geral"],"th":[]},{"n":"46","t":"O NUMOPEDE deverá encaminhar relatórios trimestrais ao Corregedor-Geral da Justiça, detalhando as ações e os trabalhos desenvolvidos.","v":["geral"],"th":[]},{"n":"47","t":"Fica determinada a obrigatoriedade de uso exclusivo do Sistema PJeCor, do Conselho Nacional de Justiça, no âmbito da Corregedoria-Geral da Justiça do Estado do Ceará, para o protocolo, a autuação, o controle e a tramitação dos procedimentos administrativos, cujas classes se encontram previstas no ANEXO II desta Consolidação, de competência originária desta Corregedoria, em desfavor de magistrados. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) 32 § 1º Os novos procedimentos de pedidos de providências, representações por excesso de prazo, inspeções, correições, sindicâncias, processos administrativos disciplinares e os demais procedimentos de natureza disciplinar, deverão ser autuados no PJeCor, no qual deverão tramitar até a sua conclusão, no âmbito desta Corregedoria. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 2º Determinar a imediata migração para o PJeCOR de todos os processos atualmente em tramitação nesta Corregedoria que possuam natureza disciplinar contra magistrados. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 3º Em caso de indisponibilidade do PJeCor, deverá ser aberto chamado junto ao Conselho Nacional de Justiça, gestor do sistema, através do e-mail sistemasnacionais@cnj.jus.br. (Incluído pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022)","v":["geral"],"th":["prazos","secretaria"]},{"n":"48","t":"Os usuários internos da Corregedoria serão cadastrados junto ao sistema PJeCOR, de acordo com a lotação/cargo, nos perfis de acesso abaixo indicados: (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) I - Perfil de Magistrado – Corregedor-Geral e Juízes Corregedores Auxiliares; II - Perfil de Assessor - Gabinete do Corregedor, Assessoria Jurídica e Auxiliares dos Juízes Corregedores; III - Perfil de Servidor Geral (Seção de cumprimento) – Diretoria-Geral, Núcleo de Governança da Corregedoria, Gerência Administrativa, Gerência de Correição e Apoio às Unidades Extrajudiciais, Gerência de Correição e Apoio às Unidades Judiciais e suas Coordenadorias; IV - Perfil de Servidor Geral (Seção de arquivamento) - Gerência Administrativa; V - Perfil Servidor de Cadastro - Coordenadoria de Orientação e Padronização e Coordenadoria de Organização e Controle das Unidades Extrajudiciais; § 1º Poderá ser autorizado, pelo gestor local do sistema, o cadastro em perfil diverso da lotação do usuário, em virtude de necessidade do serviço. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 2º Os gestores das unidades administrativas da Corregedoria-Geral da Justiça deverão velar para que o acesso ao PJeCor seja feito diariamente, com vistas a evitar atrasos no trâmite de seus respectivos processos e procedimentos. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) 33","v":["geral"],"th":["mandados"]},{"n":"49","t":"As unidades judiciais, as direções do foro, as associações de magistrados, servidores e oficiais de justiça serão cadastrados no PjeCor pela Corregedoria-Geral da Justiça como entes e procuradorias para que possam peticionar e receber as citações, intimações e notificações por meio do referido sistema. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 1º Poderão ser cadastradas como entes e procuradorias os demais órgãos internos do tribunal, inclusive para os atos de comunicação. (Inserido pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 2º Os indicados no caput deverão fornecer os dados pessoais solicitados pela Corregedoria-Geral da Justiça, para fins de cadastro no sistema. (Inserido pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022)","v":["geral"],"th":["citacao"]},{"n":"50","t":"A realização dos cadastros dos magistrados junto ao PJeCOR, nos perfis Procurador Gestor e Jus Postulandi, serão de responsabilidade desta Corregedoria, assim como as alterações necessárias em razão de mudança de titularidade da unidade judicial ou respondências. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 1º As alterações dos cadastros referidas no caput deverão ser solicitadas à Corregedoria, através do e-mail acessoscgj@tjce.jus.br, contendo as seguintes informações: (Inserido pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) I - nome do magistrado; II - unidade de lotação; III - número de matrícula; IV - número do CPF; e V - documentos que comprovem a respondência e seu período equivalente. § 2º O magistrado poderá delegar a um servidor a condição de procurador ou representante da unidade judiciária, cabendo, ao próprio juiz efetivar o cadastramento do respectivo servidor, caso seja de seu interesse. (Inserido pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022)","v":["geral"],"th":[]},{"n":"51","t":"Os documentos e requerimentos de que trata a presente Seção serão protocolizados pelas partes diretamente no sistema PJeCor, conforme indicado na página eletrônica da Corregedoria. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 1º (Revogado pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) 34 § 2º As partes sem acesso ao PJeCor deverão apresentar, preferencialmente por meio eletrônico, requerimento e documentos ao setor de protocolo que se incumbirá do cadastro no PJeCor. § 3º Caso o requerimento e documentos sejam apresentados em meio físico, por partes que não tenham acesso ao PjeCor, o Setor de Protocolo desta Corregedoria digitalizará as peças, devolvendo-os em seguida. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 4º Não sendo possível a entrega imediata do requerimento e documentos na forma do parágrafo anterior, as referidas peças ficarão disponíveis para retirada pelo prazo de 30 (trinta) dias, findo o qual serão descartados.","v":["geral"],"th":["prazos"]},{"n":"52","t":"Para a qualificação das partes envolvidas deverão constar as seguintes informações: I - nome completo; II - número de inscrição no Cadastro de Pessoas Físicas (CPF) ou no Cadastro Nacional de Pessoa Jurídica (CNPJ); III - domicílio (endereço); IV - endereço eletrônico; V - número de telefone móvel (celular); Parágrafo único. Os requisitos dos incisos I, II e III são obrigatórios para a parte autora.","v":["geral"],"th":[]},{"n":"53","t":"No caso de magistrados, unidades judiciais, direções do foro, associações de magistrados, servidores e oficiais de justiça, a distribuição da petição inicial e a juntada da resposta, dos recursos e das petições em geral, todos em formato digital, nos autos de processo eletrônico serão feitas diretamente no sistema PJeCor, sem necessidade da intervenção da Corregedoria-Geral da Justiça (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) Parágrafo único. As peças encaminhadas em desacordo com o caput, por qualquer meio ou formato, serão devolvidas ao remetente ou recusadas pelo mesmo meio de envio. (Inserido pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022)","v":["geral"],"th":["secretaria"]},{"n":"54","t":"Salvo disposição legal em contrário, as citações, as intimações e notificações do PJeCor serão realizadas pelo meio eletrônico na forma do art. 5º e seguintes da Lei nº 11.419/2006. 35 § 1º Caso impossível a intimação por melo eletrônico, dar-se-á preferência à comunicação por email, Malote Digital ou outra forma idônea que permita a plena ciência, a exemplo de telefone ou mensagem eletrônica por aplicativo WhatsApp, sempre com certidão nos autos do PJeCor. § 2º Serão observadas as regras ordinárias para a comunicação quando frustradas as tentativas referidas no parágrafo anterior ou quando impostas pela lei aplicável, providenciando, de qualquer forma, o envio de cartas precatórias ou de ordem por meio eletrônico.","v":["geral"],"th":["citacao"]},{"n":"55","t":"A comunicação da existência do primeiro processo cadastrado no PJeCor em desfavor do requerido será por mensagem eletrônica dirigida ao e-mail funcional ou malote digital, considerando-se intimado na data de recebimento da mensagem eletrônica em sua caixa, aplicandose a Lei nº 11.419/2006 às comunicações dos demais processos. (Redação conferida pelo Prov. nº 08/2022/CGJCE, DJe de 18/07/2022) § 1º Os usuários deverão acessar, obrigatoriamente, de forma regular, o Sistema PJeCOR para fins de conhecimento e acompanhamento de eventuais procedimentos autuados, bem como para responder as solicitações oriundas deste Órgão Correicional. § 2º Em casos de férias, licenças ou afastamentos do magistrado titular, as respostas as citações, intimações e/ou notificações seguem o seguinte procedimento: I - caberá ao juíz em respondência, se direcionada a unidade judicial, não havendo suspensão de prazo; II - caberá ao juiz em respondência ou servidor autorizado, informar a Corregedoria, que decidirá acerca da suspensão do prazo até o retorno do magistrado a suas atividades laborais.","v":["geral"],"th":["prazos","citacao"]},{"n":"56","t":"A contagem dos prazos das comunicações feitas por meio eletrônico se dará na forma do art. 5º, § 3º, da Lei nº 11.419/2006 e do art. 21 da Resolução n. 185/2013-CNJ.","v":["geral"],"th":["prazos"]},{"n":"57","t":"A consulta pública aos feitos em tramitação no PJeCor poderá ser feita por endereço eletrônico definido pela Corregedoria Nacional de Justiça, à exceção dos feitos submetidos a sigilo, de acordo com o disposto na Resolução nº 121/2010-CNJ.","v":["geral"],"th":[]},{"n":"58","t":"A inclusão ou exclusão de classes e/ou assuntos, conforme TPU, dos processos e procedimentos administrativos deverão ser submetidas previamente à análise do Corregedor-Geral da Justiça.","v":["geral"],"th":[]},{"n":"59","t":"O acesso ao PJeCor ocorrerá nos termos do art. 1º da Lei nº 11.419, de 19 de dezembro de 2006, e da Resolução CNJ nº 185/2013. 36","v":["geral"],"th":[]},{"n":"60","t":"As disposições da Lei n. 11.419/2006 e da Resolução CNJ nº 185/2013 aplicam-se ao procedimento do PJeCor, no que couber.","v":["geral"],"th":[]}]},{"num":"III","title":"DOS MAGISTRADOS","articles":[{"n":"61","t":"Os Juízes de Direito e Substitutos, para boa ordem do serviço e fiel cumprimento dos processos legais e das decisões judiciais, devem cumprir e fazer cumprir as regras da Lei Orgânica da Magistratura Nacional, do Código de Ética da Magistratura, da Lei de Organização Judiciária do Estado do Ceará, dos atos normativos do Conselho Nacional de Justiça, do Tribunal de Justiça do Estado do Ceará e da Corregedoria-Geral da Justiça do Estado do Ceará, observando: I - a preservação do bom nome da Justiça, procedendo de modo irreparável e irrepreensível na vida pública e particular, preservando a dignidade de suas atividades e funções; II - a prática proficiente, zelosa e proba dos atos que lhes são afetos; III - a observância dos prazos para decidir ou despachar, determinando as providências necessárias para que os atos processuais se realizem tempestivamente e não permitindo a paralisação de qualquer processo, ressalvados os casos previstos em lei; IV - tratamento com urbanidade dispensado às partes, aos membros do Ministério Público, aos Advogados, às testemunhas, aos funcionários e auxiliares da Justiça, e atendimento aos que o procurarem, a qualquer momento, quando se tratar de providência urgente; V - residência na sede da comarca, salvo quando autorizado pelo Presidente do Tribunal de Justiça ou pelo Conselho Superior da Magistratura; 37 VI - comparecimento pontual ao início do expediente ou da sessão, não se ausentando injustificadamente antes do seu término; VII - fiscalização permanente dos servidores juridicamente subordinados, especialmente no que se refere à cobrança de custas, emolumentos e despesas processuais, mesmo sem reclamação dos interessados; VIII - abstenção de opinião que caracterize discurso discriminatório ou de ódio, especialmente os que revelem racismo, LGBT-fobia, misoginia, antissemitismo, intolerância religiosa ou ideológica, entre outras manifestações de preconceitos concernentes a orientação sexual, condição física, de idade, de gênero, de origem, social ou cultural (Resolução 305 do CNJ, datada de 17/12/2019); IX - abstenção de opinião, por qualquer meio de comunicação, sobre processo pendente de julgamento, seu ou de outrem, ou juízo depreciativo sobre despachos, votos ou decisões de órgãos judiciais, ressalvada a crítica nos autos e em obras técnicas ou no exercício do magistério; X - abstenção de opinião que demonstre atuação em atividade político-partidária ou de apoio ou crítica públicas a candidato, lideranças políticas ou partidos políticos (Resolução 305 do CNJ, datada de 17/12/2019); XI - uso de vestes talares durante os julgamentos no Tribunal do Júri; XII - organização do serviço de distribuição, registrados todos os autos e petições, em estrita adequação aos normativos pertinentes; XIII - especial atenção às cartas rogatórias, precatórias e de ordem; XIV - controle do cumprimento dos mandados de citação, notificação e intimação, no cível e no crime, a fim de se coibir falta injustificada por parte do Oficial de Justiça incumbido da diligência, reclamando a devolução após o prazo previsto no art. 190; (Redação conferida pelo Prov. nº 05/2024/CGJCE, DJeA de 17/04/2024). XV - estímulo da conciliação, mediação e de outros métodos de solução de conflitos, inclusive no curso do processo judicial; XVI - verificação permanente da regular cobrança de custas e/ou emolumentos e, caso identificada, em tese, a prática da infração prevista no art. 317 do Código Penal, requisição de instauração do inquérito policial e instauração de processo administrativo disciplinar, de tudo comunicando à Corregedoria-Geral da Justiça; 38 XVII - acompanhamento do recolhimento das despesas e custas processuais cabíveis nos","v":["geral"],"th":["audiencias","prazos","citacao","mandados","secretaria","execucao","atos_ordinatorios"]},{"n":"62","t":"Ao Juiz Corregedor Permanente, nos termos da Resolução do Tribunal Pleno nº 07/2020, caberá a constante fiscalização dos Serviços Notariais e de Registro das Comarcas de sua jurisdição, objetivando aferir a regularidade dos procedimentos e dos serviços prestados, bem como assegurar à observância das determinações emanadas da Corregedoria-Geral da Justiça, do Conselho Nacional de Justiça e legislação pertinente à matéria.","v":["geral"],"th":[]},{"n":"63","t":"Caberá, ainda, ao Juiz Corregedor Permanente: § 1º Realizar: I - anual e obrigatoriamente, inspeção extrajudicial ordinária em todas as serventias da comarca de sua competência; II - correição especial para transmissão de acervo, quando substituído o responsável pela serventia; 40 §2º Apurar possíveis irregularidades praticadas pelos delegatários de serventias extrajudiciais, decidindo as reclamações e aplicando, quando cabíveis as sanções disciplinares.","v":["geral"],"th":[]},{"n":"64","t":"Os(as) magistrados(as) titulares deverão realizar anualmente a autoinspeção entre os meses de janeiro e junho, ocasião em que deverão ser identificadas as irregularidades ou achados e especificadas as providências adotadas para obtenção dos resultados em prazos predefinidos. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026) §1º Caberá a incumbência ao(à) magistrado(a) em respondência nas hipóteses de vacância ou afastamento do(a) titular, exceto por motivo de férias. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026) §2º O(a) titular da unidade ou o(a) designado(a) para responder em razão de vacância, que estiver com férias programadas para o mês de junho, deverá, obrigatoriamente, concluir a autoinspeção até o mês antecedente. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026) §3º Em ocorrendo sucessivas designações para unidade judicial vaga ou com o(a) titular afastado(a), não tendo sido realizada a autoinspeção até o mês de maio, a obrigação recairá sobre os(as) magistrados(as) que atuarem em respondência no mês de junho do ano em curso. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026) §4º Nas turmas recursais dos Juizados Especiais, a autoinspeção será realizada por todos(as) os(as) magistrados(as) em seus respectivos gabinetes. 02/2026/CGJCE, publicado no DJeA de 30/01/2026) 41 (Redação conferida pelo Prov. nº §5º Em unidades judiciárias com mais de um(a) magistrado(a), a autoinspeção será de responsabilidade do(a) Juiz(a) Titular ou, onde houver, do(a) Coordenador(a) designado(a). (Incluído pelo Prov. nº 02/2022/CGJCE, publicado no DJeA de 30/01/2026) §6º No ano em que ocorrer a implantação ou transformação, ficam as novas unidades judiciárias dispensadas da autoinspeção. (Incluído pelo Prov. nº 02/2022/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":["prazos"]},{"n":"65","t":"O envio das informações advindas da autoinspeção ocorrerá, impreterivelmente, até o dia 30 de junho, por meio do preenchimento de formulário eletrônico único disponibilizado no portal da Corregedoria-Geral da Justiça, que servirá de roteiro para os trabalhos a serem empreendidos, nos termos do Anexo III (Relatório de Autoinspeção) integrante desta Consolidação. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026) Parágrafo único. Fica dispensada a abertura de procedimento no PJeCor ou no sistema de tramitação de feitos administrativos. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"66","t":"A autoinspeção exige a prévia publicação de portaria no Diário da Justiça, a divulgação no quadro de avisos do fórum local e a comunicação, por ofício, à Ordem dos Advogados do Brasil (OAB/CE), ao Ministério Público Estadual e à Defensoria Pública Estadual, constando o dia de início e de término dos trabalhos. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026) Parágrafo único. No decorrer do procedimento, é vedado suspender prazos, a realização de audiências ou a distribuição processual, preservando-se o regular atendimento às partes e advogados(as). (Incluído pelo Prov. nº 02/2022/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":["audiencias","prazos","secretaria","atos_ordinatorios"]},{"n":"67","t":"Decorrido o prazo de envio do formulário eletrônico, a Corregedoria-Geral da Justiça autuará expediente administrativo para conferência do cumprimento da obrigação e adoção das providências cabíveis, inclusive eventual apuração disciplinar. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":["prazos","mandados"]},{"n":"68","t":"A informação do cumprimento ou não das determinações constantes na presente seção, na forma e prazos ora estabelecidos, passará a integrar, expressamente, as certidões da CorregedoriaGeral da Justiça para fins de promoção, remoção ou acesso. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026) 42","v":["geral"],"th":["prazos","mandados"]},{"n":"69","t":"As informações relativas às autoinpeções instruirão os procedimentos das inspeções realizadas pela Corregedoria-Geral da Justiça junto às unidades judiciárias. (Redação conferida pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"70","t":"(Revogado pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"71","t":"(Revogado pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"72","t":"(Revogado pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"73","t":"(Revogado pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"74","t":"(Revogado pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"75","t":"(Revogado pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"76","t":"(Revogado pelo Prov. nº 02/2026/CGJCE, publicado no DJeA de 30/01/2026)","v":["geral"],"th":[]},{"n":"77","t":"É dever dos magistrados, no âmbito de suas competências, diretamente: I - fiscalizar e monitorar a condição de cumprimento de pena e de prisão provisória, recomendando providências necessárias para assegurar que o número de presos não exceda a capacidade de ocupação dos estabelecimentos penais; II - fiscalizar e monitorar a condição de cumprimento de medidas de internação por adolescentes em conflito com a lei, adotando providências necessárias para assegurar que o número de internados não exceda a capacidade de ocupação dos estabelecimentos; III - incentivar e monitorar a realização de inspeções periódicas das unidades prisionais e de internação, sistematizando os relatórios mensais e assegurando sua padronização, garantida a alimentação de banco de dados de inspeções nacional e local, caso este exista, para acompanhar, discutir e propor soluções em face das irregularidades encontradas. 43","v":["geral"],"th":["mandados","presos","execucao"]},{"n":"78","t":"O juiz que decretar a interdição de unidades prisionais e de internação deve, de forma imediata, comunicar a Corregedoria-Geral da Justiça sobre o fato, enviando, inclusive, cópia da decisão correspondente. §1º Se decretada a interdição de unidades prisionais e de internação, antes da transferência dos apenados ou de adolescentes em conflito com a lei, os juízes deverão adotar as seguintes providências: I - realizar audiência de custódia, conforme Resolução nº 213 de 15/12/2015, do Conselho Nacional de Justiça – CNJ, e verificar a situação de todos os presos provisórios, observada a possibilidade de aplicação das medidas cautelares alternativas à prisão e eventual conversão do flagrante em custódia preventiva; II - promover o exame da situação jurídico-processual dos condenados recolhidos na unidade prisional, bem como conferir a regularidade do cumprimento da pena e decidir acerca da possibilidade de adoção de progressão de regime prisional; III - reavaliar as prisões provisórias, nos termos do art. 316, do Código de Processo Penal; IV - reavaliar medidas socioeducativas de internação e semiliberdade, para fins de eventual substituição por medida em meio aberto, suspensão ou remissão; e reavaliar decisões que determinaram a aplicação de internação-sanção, prevista no art. 122, III, do Estatuto da Criança e do Adolescente. § 2º Ultimadas as providências anteriores, compete ao magistrado definir a Comarca próxima onde o preso deverá ser reconduzido, observadas as orientações atinentes ao recambiamento e cooperação da Secretaria de Administração Penitenciária.","v":["geral"],"th":["audiencias","prazos","mandados","secretaria","presos","execucao"]},{"n":"79","t":"Com relação aos flagrantes subsequentes à interdição da unidade prisional, deverá o magistrado realizar a audiência de custódia e sindicar eventual conversão em prisão preventiva, antes de efetuar qualquer transferência, e, após, observar o §1º do art. 78 desta Consolidação.","v":["geral"],"th":["audiencias","presos"]},{"n":"80","t":"Nos casos de superveniência de prisão preventiva ou temporária em comarcas onde a unidade prisional esteja interditada, ao magistrado importará ainda a incumbência do §1º do art. 78 deste normativo. 44","v":["geral"],"th":["presos"]},{"n":"81","t":"Na hipótese de lotação na unidade prisional de destino ou outro motivo de inviável acolhimento de transferidos, o magistrado daquela jurisdição receberá o preso deslocado e, em até 72 horas, exporá as razões à Corregedoria-Geral da Justiça de forma circunstanciada, pelo que deve aguardar a tomada das providências pertinentes pelo Corregedor.","v":["geral"],"th":["presos"]},{"n":"82","t":"A declaração dos bens e valores que integram o patrimônio privado dos magistrados de primeiro grau da Justiça do Estado do Ceará, bem como sua atualização anual, observarão as normas desta Consolidação.","v":["geral"],"th":[]},{"n":"83","t":"A posse e o exercício do juiz substituto dependem da apresentação à Presidência do Tribunal de Justiça de declaração dos bens e valores que compõem o seu patrimônio privado, devendo compreender imóveis, móveis, semoventes, dinheiro, títulos, ações, e qualquer outra espécie de bens e valores patrimoniais, localizados no País ou no exterior, e, quando for o caso, abranger os bens e valores patrimoniais do cônjuge ou companheiro, dos filhos e de outras pessoas que vivam sob a dependência econômica do declarante, excluídos apenas os objetos e utensílios de uso doméstico (art. 150, da Lei Estadual nº 12.342/94; e art. 13, caput e § 1º, da Lei Federal nº 8.429/92). Parágrafo único. A declaração realizada por ocasião da posse instruirá o competente processo de nomeação, dela extraindo-se cópias, uma arquivada no Setor de Pessoal competente, enquanto a outra será encaminhada à Corregedoria-Geral da Justiça para análise da evolução patrimonial do magistrado.","v":["geral"],"th":["execucao"]},{"n":"84","t":"Os magistrados de primeiro grau da Justiça Estadual do Ceará deverão encaminhar à Corregedoria-Geral da Justiça, até 30 (trinta) dias após a data limite fixada pela Secretaria da Receita Federal do Ministério da Fazenda para a apresentação da Declaração de Ajuste Anual do Imposto de Renda Pessoa Física, assim como na data em que deixarem o exercício do cargo, a 45 declaração atualizada de bens e valores que integram o seu patrimônio privado, devendo compreender imóveis, móveis, semoventes, dinheiro, títulos, ações, e qualquer outra espécie de bens e valores patrimoniais, localizados no País ou no exterior, e, quando for o caso, abranger os bens e valores patrimoniais do cônjuge ou companheiro, dos filhos e de outras pessoas que vivam sob a dependência econômica do declarante, excluídos apenas os objetos e utensílios de uso doméstico. § 1º Constitui infração disciplinar o magistrado se recusar a prestar declaração dos bens e valores dentro do prazo determinado, ou apresentar informações falsas (art. 35, inciso I, da Lei Complementar Nº 35, de 14 de março de 1979), devendo a conduta ser apurada por meio do competente processo administrativo disciplinar, sem prejuízo das demais sanções cabíveis; § 2º O declarante, a seu critério, poderá entregar cópia da declaração anual de bens apresentada à Delegacia da Receita Federal na conformidade da legislação do Imposto sobre a Renda e proventos de qualquer natureza, com as necessárias atualizações, para suprir a exigência contida no caput.","v":["geral"],"th":["prazos","secretaria","execucao"]},{"n":"85","t":"A declaração anual de bens e valores de que trata o artigo anterior deverá ser entregue exclusivamente em meio eletrônico, através do Sistema Eletrônico de Informações (SEI), e terá tramitação sigilosa. (Redação conferida pelo Prov. nº 02/2025/CGJCE, publicado no DJeA de 07/04/2025) § 1º Para realizar o cadastro do processo, o magistrado deverá acessar o SEI, mediante uso de login e senha pessoais, escolher o tipo de processo “CGJ: Declaração de Bens de Magistrados” e, em seguida, anexar o arquivo da declaração de imposto de renda, registrando o tipo de documento como “Declaração de Bens”; (Redação conferida pelo Prov. nº 02/2025/CGJCE, publicado no DJeA de 07/04/2025) § 2º Após a finalização do cadastro e a juntada dos documentos necessários, o processo deverá ser encaminhado à unidade “CGJUBENS - CGJ - Declaração Anual de Bens”, para fins de distribuição e tramitação; (Redação conferida pelo Prov. nº 02/2025/CGJCE, publicado no DJeA de 07/04/2025) § 3º Os processos gerados a partir das declarações serão distribuídos, conforme Sistema de Zoneamento regulamentado pelos arts. 8º ao 13 desta Consolidação, entre os juízes corregedores auxiliares, para fins de exame e emissão de parecer, após o que permanecerão arquivados na Corregedoria-Geral da Justiça para análise da evolução patrimonial. (Incluído pelo Prov. nº 02/2025/CGJCE, publicado no DJeA de 07/04/25) 46","v":["geral"],"th":["secretaria"]},{"n":"86","t":"A Corregedoria-Geral da Justiça poderá examinar, sempre que julgar necessário, a evolução patrimonial dos magistrados de primeiro grau, a fim de verificar a compatibilidade desta com os recursos e disponibilidades que compõem a sua renda, na forma prevista na Lei nº 8.429/1992, observadas as disposições especiais da Lei nº 8.730/1993. Parágrafo único. Verificada a incompatibilidade patrimonial, na forma estabelecida no caput, será instaurado, mediante portaria do Corregedor-Geral, procedimento de sindicância patrimonial.","v":["geral"],"th":["atos_ordinatorios"]},{"n":"87","t":"A instauração da sindicância patrimonial também pode ser determinada sempre que o Corregedor tomar conhecimento de fundada notícia ou de indícios de enriquecimento ilícito, inclusive evolução patrimonial incompatível com os recursos e disponibilidades do magistrado, nos termos do art. 9º da Lei nº 8.429/1992.","v":["geral"],"th":[]},{"n":"88","t":"A sindicância patrimonial constituir-se-á em procedimento sigiloso, meramente investigatório, não tendo caráter punitivo, e será conduzido por três juízes corregedores auxiliares, designados por ato específico. § 1º Identificados os fatos, o magistrado será notificado a fim de, no prazo de 5 (cinco) dias, prestar informações, sendo-lhe permitido acompanhar o procedimento; § 2º O prazo para conclusão do procedimento de sindicância patrimonial será de 30 (trinta) dias, contados da data da publicação do ato que constituir a Comissão, podendo ser prorrogado, por prazo certo, pelo Corregedor-Geral, desde que justificada a necessidade; § 3º A Comissão Sindicante poderá efetuar diligências necessárias à elucidação dos fatos, ouvindo o sindicado e as eventuais testemunhas, solicitar diligências, expedir ofícios a órgãos públicos, juntando aos autos a prova documental existente; § 4º O interrogatório do sindicado, precedido de intimação, com antecedência de 48 (quarenta e oito) horas, será realizada após a produção de todas as provas, podendo ser acompanhado por seu procurador.; § 5º Concluídos os trabalhos da sindicância patrimonial, a comissão responsável por sua condução fará relatório sobre os fatos apurados, opinando pelo arquivamento ou, se for o caso, conversão em processo administrativo disciplinar, esta última de acordo com decisão do Tribunal Pleno.","v":["geral"],"th":["prazos","citacao"]},{"n":"89","t":"A Corregedoria-Geral da Justiça adotará as medidas necessárias para ministrar instruções aos magistrados sobre o envio da declaração anual de bens e valores por meio do Sistema Eletrônico de Informações (SEI), inclusive com disponibilização de manuais. (Redação conferida pelo Prov. nº 02/2025/CGJCE, publicado no DJeA de 07/04/2025) 47","v":["geral"],"th":[]},{"n":"90","t":"Constitui obrigação de todos os magistrados comunicar à Corregedoria-Geral da Justiça acerca do exercício de atividade docente. (Redação conferida pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024) Parágrafo único. Fica excluída da obrigatoriedade da comunicação referida no caput, a participação de magistrados na condição de palestrante, conferencista, presidente de mesa, moderador, debatedor ou membro de comissão organizadora, bem como em bancas de concurso público e em comissões de juristas. (Redação conferida pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024)","v":["geral"],"th":[]},{"n":"91","t":"A comunicação referida no artigo precedente deverá ser realizada através do Formulário Eletrônico de Acompanhamento de Atividade Docente Exercida por Magistrados, único meio apto para o registro de informações relativas à prática de atividade docente. (Redação conferida pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024) § 1º O preenchimento do formulário deverá ser realizado por todos os magistrados, independentemente de exercer ou não o magistério, semestralmente, até o dia 15 de fevereiro e 15 de agosto do ano em curso. (Incluído pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024) § 2º As informações encaminhadas abrangerão a instituição de ensino, as disciplinas ministradas e os dias e horários das aulas, fazendo-se acompanhar da devida comprovação. (Incluído pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024) § 3º Havendo modificação relativa à instituição, carga horária ou disciplina, deverá o magistrado promover, de imediato, a atualização das informações. (Incluído pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024)","v":["geral"],"th":[]},{"n":"92","t":"(Revogado pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024)","v":["geral"],"th":[]},{"n":"93","t":"(Revogado pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024)","v":["geral"],"th":[]},{"n":"94","t":"As atividades de coaching, similares e congêneres, destinadas à assessoria individual ou coletiva de pessoas, inclusive na preparação de candidatos a concursos públicos, não são 48 consideradas atividade docente, sendo vedada a sua prática por magistrados, conforme preceitua o Art. 5º-A da Resolução n° 34/2007/CNJ.","v":["geral"],"th":[]},{"n":"95","t":"(Revogado pelo Prov. nº 15/2024/CGJCE, DJeA de 09/10/2024)","v":["geral"],"th":[]},{"n":"96","t":"Ficará a cargo da Gerência Administrativa deste Órgão, o acompanhamento das informações prestadas através da ferramenta eletrônica ora instituída, bem como pelo encaminhamento periódico da relação dos magistrados que exercem a docência, para fins de disponibilização no sítio eletrônico do Tribunal de Justiça do Estado do Ceará, nos termos do art. 5º da Resolução 34/2007/CNJ.","v":["geral"],"th":[]},{"n":"97","t":"O formulário eletrônico em comento será disponibilizado na intranet, no sítio deste Tribunal, vinculado à página da Corregedoria-Geral da Justiça, nos termos do Anexo IV, parte integrante desta Consolidação.","v":["geral"],"th":[]},{"n":"98","t":"Os magistrados deverão, obrigatoriamente, verificar diariamente o correio eletrônico institucional e o malote digital das unidades judiciais, como forma de envio das informações e/ou solicitações expedidas por esta Corregedoria-Geral da Justiça. § 1º Havendo prazo para respostas às solicitações requestadas por esta Corregedoria-Geral, este se iniciará, imediatamente, após, o recebimento do e-mail ou a leitura do malote; § 2º Após, 5 (dias) do envio da correspondência eletrônica, considerar-se-ão lidas, para todos os efeitos, iniciando-se inclusive, a contagem de prazo, quando houver.","v":["geral"],"th":["prazos"]},{"n":"99","t":"A Corregedoria-Geral de Justiça, quando conveniente ou necessário, utilizará meio físico para envio de informações e solicitações.","v":["geral"],"th":[]},{"n":"100","t":"As solicitações à Corregedoria-Geral da Justiça que não dependam de ato formal poderão ser feitas através do seguinte correio eletrônico: corregedoria@tjce.jus.br.","v":["geral"],"th":[]},{"n":"101","t":"O acesso ao correio eletrônico e ao malote digital dar-se-á pela intranet desde Tribunal, ressaltando que o login e a senha utilizados para o acesso são os mesmos para acesso à rede. 49","v":["geral"],"th":[]},{"n":"102","t":"As unidades jurisdicionais devem, obrigatoriamente, alimentar os sistemas nacionais mantidos ou gerenciados pelo Conselho Nacional de Justiça, conforme as suas competências e prazos estabelecidos em suas respectivas resoluções. § 1º O juiz titular da unidade judicial ficará responsável pelo envio desses dados, sendo a responsabilidade transferida ao juiz que por ela estiver respondendo, por motivo de férias, licença, afastamento do titular ou por qualquer outro meio justificável que o impeça de prestar as informações; § 2º A liberação de senhas de acesso aos sistemas nacionais gerenciados pelo Conselho Nacional de Justiça serão fornecidos pela Corregedoria-Geral da Justiça, nos termos estabelecidos em normativo próprio.","v":["geral"],"th":["prazos"]},{"n":"103","t":"Nas certidões expedidas por esta Corregedoria-Geral, para fins de vitaliciedade, remoção, promoção e permuta, constará a informação de quitação das atividades desenvolvidas pelo Conselho Nacional de Justiça - CNJ, cuja execução se dirige aos juizes de 1° Grau.","v":["geral"],"th":["execucao"]},{"n":"104","t":"Os dados estatísticos para acompanhamento da produtividade dos magistrados e das respectivas serventias judiciárias junto ao Sistema de Gerenciamento de Estatística – SGEC serão fornecidos por meio de Formulário Único de Estatística da Corregedoria-Geral da Justiça, cujas variáveis encontram-se listadas nos Anexos V (Turmas Recursais), VI (1º Grau) e VII (Juizados Especiais), partes integrantes do presente normativo. Parágrafo único. O formulário eletrônico, disponível na intranet do Tribunal de Justiça do Ceará TJCE, deverá ser acessado pelas unidades do 1ª Grau e Juizados Especiais, através do Sistema de 50 Gerenciamento Estatístico da Corregedoria (SGEC) e pelas Turmas Recursais por meio do Sistema de Produtividade Mensal.","v":["geral"],"th":[]},{"n":"105","t":"O lançamento da Produtividade Mensal tem como termo final, impreterivelmente, o dia 15 (quinze) do mês subsequente ao período de apuração. Caso recaia em sábados, domingos, feriados ou pontos facultativos decretados pela Presidência do Tribunal de Justiça, o prazo será postergado até o 1º dia útil seguinte. § 1º Estarão disponíveis para preenchimento das unidades judiciárias somente aqueles indicadores que não possuem regra de extração automática implantada; § 2º A inobservância do dever de remessa dos dados estatísticos, por falta de preenchimento ou por ausência de retificação, implica na admissão das informações extraídas ou, ainda, ante a ausência de lançamento dos pontos, na atribuição do quantitativo zero, no campo correspondente; § 3º Os números apurados serão computados na estatística do mês em que forem lançadas as movimentações correspondentes.","v":["geral"],"th":["prazos"]},{"n":"106","t":"Fica disponibilizada a funcionalidade “Cadastro de Divergências” para as unidades judiciárias que utilizem o sistema SGEC, possibilitando informar, individualmente, seja por inclusão ou exclusão, as divergências detectadas a partir dos dados extraídos diretamente dos sistemas processuais em forma de indicadores do Formulário Estatístico. Parágrafo único. Os processos divergentes deverão ser incluídos através da ferramenta acima mencionada no decorrer do mês de apuração da Produtividade Mensal, após a disponibilização dos dados provenientes da extração automática.","v":["geral"],"th":[]},{"n":"107","t":"Os incidentes ocasionados pela redistribuição de processos devem ser cientificados ao setor responsável pela serventia judiciária, para que proceda ao deslocamento do feito do acervo originário para o juízo competente, com os devidos apontamentos nas 2 (duas) unidades envolvidas.","v":["geral"],"th":["secretaria"]},{"n":"108","t":"As retificações dos dados de pessoal (Força de Trabalho), quando necessárias, deverão ser informadas à Secretaria de Gestão de Pessoas (SGP), para a atualização ou correção no Sistema de Gestão de Recursos Humanos (GRH).","v":["geral"],"th":["secretaria"]},{"n":"109","t":"A Corregedoria, no exercício de monitoramento e fiscalização dos juízos, ao perceber movimentações indevidas, inadequadas e incorretas que repercutam no incremento da produtividade da serventia ou do magistrado, de ofício, determinará o cancelamento da ação e o expurgo das impropriedades cometidas, apurando a responsabilidade pessoal do agente. 51 Parágrafo único. Notificada, a própria unidade deverá cancelar a incorreção; na inviabilidade técnica, mediante processo administrativo instaurado pela autoridade judiciária competente, a Secretaria de Tecnologia da Informação - SETIN o fará, com encaminhamento do expediente a esta Corregedoria-Geral da Justiça.","v":["geral"],"th":["secretaria"]},{"n":"110","t":"(Revogado pelo Prov. nº 23/2024/CGJCE, publicado no DJeA de 18/12/2024)","v":["geral"],"th":[]},{"n":"111","t":"(Revogado pelo Provimento nº 23/2024/CGJCE, publicado no DJeA de 18/12/2024)","v":["geral"],"th":[]},{"n":"112","t":"(Revogado pela Resolução nº 07/2021/TJCE, DJe de 18/11/2021)","v":["geral"],"th":[]},{"n":"113","t":"(Revogado pela Resolução nº 07/2021/TJCE, DJe de 18/11/2021)","v":["geral"],"th":[]},{"n":"114","t":"Compete à Corregedoria-Geral da Justiça instruir os processos com os demais dados estatísticos de produtividades de cada candidato, visando atender o quanto possível os parâmetros definidos nas Resoluções regedoras da matéria, emitindo relatório circunstanciado, ressalvando-se as informações indisponíveis em razão das limitações técnicas atuais. 52","v":["geral"],"th":[]},{"n":"115","t":"As certidões expedidas pela Corregedoria-Geral da Justiça, para fins de promoção, remoção, permuta ou acesso ao Tribunal de Justiça, relativas à produtividade dos magistrados, serão elaboradas conforme os seguintes parâmetros: I - celeridade da prestação jurisdicional; II - volume de produção.","v":["geral"],"th":[]},{"n":"116","t":"Na avaliação da estrutura de funcionamento da unidade judiciária serão considerados: I - acervo e fluxo processual; II - competência e especialidade; III - tipo de exercício (Titular ou Auxiliar). § 1º Os dados citados no caput serão extraídos do Sistema de Gerenciamento Estatístico da Corregedoria (SGEC) e do Sistema Estatístico e de Informações do Tribunal de Justiça (SEI) considerando-se a situação da unidade judicial no mês referente à solicitação da certidão; § 2º Caso o requerente seja Juiz Auxiliar, os dados referentes aos incisos I e II, deste artigo serão desconsiderados; § 3º Nas hipóteses em que o magistrado solicitante estiver respondendo por mais de uma unidade, constarão na certidão as seguintes informações: I - dados relativos a unidade judicial - apenas aqueles correspondentes a titularidade do magistrado; II - dados referentes a produtividade - em todas as unidades em que o solicitante respondeu, durante o período avaliado.","v":["geral"],"th":["citacao","execucao"]},{"n":"117","t":"Na avaliação da celeridade na prestação jurisdicional considerar-se-á, unicamente, o tempo médio de duração do processo na unidade judicial entre a distribuição e o julgamento.","v":["geral"],"th":["audiencias","secretaria"]},{"n":"118","t":"A aferição do Volume de Produção do magistrado será mensurada com base nos bancos de dados extraídos do Sistema Estatístico e de Informações do Tribunal de Justiça (SEI) e do Sistema de Gerenciamento Estatístico da Corregedoria (SGEC), considerando-se: 53 I - número de audiências; II - número de conciliações; III - número de sentenças; IV - número de decisões interlocutórias; V - número de acórdãos e decisões em substituição e auxílio ao 2º Grau ou Turma Recursal; VI - tempo médio dos processos na unidade judicial. § 1º A avaliação desses critérios deverá abranger, no mínimo, os últimos 24 (vinte e quatro) meses de exercício; § 2º No caso de afastamento ou de licença legais do magistrado nesse período, será considerado o tempo de exercício jurisdicional imediatamente anterior; § 3º Os juízes em exercício ou convocados no Supremo Tribunal Federal, Tribunais Superiores, Conselho Nacional de Justiça, Conselho da Justiça Federal, Conselho Superior da Justiça do Trabalho e na Presidência, Corregedoria-Geral e Vice-Presidência do Tribunal de Justiça, ou licenciados para exercício de atividade associativa da magistratura, deverão ter a média de sua produtividade aferida no período anterior às suas designações.","v":["geral"],"th":["audiencias"]},{"n":"119","t":"Das certidões constarão, ainda, informações referentes à média do número de sentenças e audiências realizadas durante o período apurado para fins de mensuração do volume de produção do magistrado, nos termos do artigo 118 do presente ato normativo. Parágrafo único. A realização, anual e obrigatória, de inspeção extrajudicial em todas as Serventias da Comarca, com o envio do relatório circunstanciado final das providências adotadas equivalerá, para efeito de produtividade do magistrado, com atribuição de Juiz Corregedor Permanente, a uma sentença de mérito prolatada e comprovará a presteza avaliada nos termos do art. 7º, “alínea g”, da Resolução nº 08, de 3 de maio de 2010, do egrégio Tribunal de Justiça do Estado Ceará, que trata dos critérios para aferição do merecimento para promoção de magistrados.","v":["geral"],"th":["audiencias"]},{"n":"120","t":"Também deverão constar nas certidões expedidas por esta Corregedoria-Geral, para fins de vitaliciedade, remoção, promoção, permuta ou acesso, a informação de: I - inexistência de punição, nos últimos 12 (doze) meses, em processo disciplinar, com pena igual ou superior à de censura, comprovado mediante apresentação de certidão negativa expedida pela Corregedoria-Geral da Justiça; 54 II - quitação das atividades desenvolvidas pelo Conselho Nacional de Justiça - CNJ, cuja execução se dirige aos juízes de 1° Grau; III - realização de autoinspeção na unidade de sua competência; (Redação conferida pelo Prov. nº 01/2024/CGJCE, republicado por incorreção no DJeA de 01/02/2024) IV - implantação e funcionamento do Conselho da Comunidade na Comarca, conforme legislação pertinente; V - cumprimento de carga horária de 40 (quarenta) horas-aula em cada um dos dois períodos de 12 (doze) meses anteriores à data de abertura da lista de promoção na carreira, em curso oficial do Programa de Formação Continuada, ofertado por escola judicial ou de magistratura e credenciado pela Escola Nacional de Formação e Aperfeiçoamento de Magistrados – ENFAM, com a certificação de aproveitamento (Resolução ENFAM nº 2/2019).","v":["geral"],"th":["mandados","execucao"]},{"n":"121","t":"Delegar aos Juízes corregedores auxiliares a orientação, o acompanhamento e a avaliação dos novos Juízes Substitutos para fins de apuração dos requisitos imprescindíveis à outorga da garantia constitucional da vitaliciedade. Parágrafo único. Os delegatários funcionarão como magistrados orientadores, formadores e monitores, em auxílio às atribuições privativas do Corregedor-Geral da Justiça.","v":["geral"],"th":[]},{"n":"122","t":"Cientificar aos juízes em fase de cumprimento de estágio probatório, de que o critério para a identificação do seu respectivo juiz corregedor formador segue o sistema de zoneamento instituído e discriminado nos arts. 9º e 10 do presente normativo, respectivamente.","v":["geral"],"th":["mandados"]},{"n":"123","t":"O juiz corregedor formador desempenhará o mister de modo a depurar, nos Juízes iniciantes, os predicados legais inerentes à função, a saber: a) idoneidade moral, dignidade funcional, retidão de conduta, probidade e independência; b) assiduidade e frequência ao Fórum nos dias úteis e plantões, cumprimento de horário e supervisão das atividades forenses; 55 c) aptidão e qualidade do trabalho, aplicação da melhor técnica aos atos jurisdicionais, atuação eficaz e serena, conhecimento prático e teórico, diligência e observação dos prazos legais; d) disciplina conferida pela percepção do senso de responsabilidade, discrição, observância das normas legais e no relacionamento com o pessoal de apoio; e) Produtividade representada pela efetiva atuação no exercício da magistratura, quantidade de trabalho, remessa dos relatórios para a Corregedoria; f) bom relacionamento com os advogados, Defensores Públicos, membros do Ministério Público, partes e auxiliares da justiça, especialmente, em audiências, prezado o tratamento respeitoso e cordial. § 1º As práticas a serem realizadas pelos juízes corregedores orientadores consubstanciam-se em visitas às Comarcas, reuniões locais e outras formas de contato com os magistrados em formação; § 2º Verificar-se-á o desenvolvimento do desempenho jurisdicional do vitaliciando, com abordagem da atividade judicante, sob a ótica da qualidade e quantidade de trabalho realizado, considerado o contexto em que exercida a função, de modo a fazer apreciações, críticas e sugestões, oportunas e convenientes ao aprimoramento da atividade do magistrado em processo de vitaliciamento; § 3º Após as ações, o juiz orientador deverá elaborar um prontuário com os registros constatados, as eventuais orientações ofertadas, os esclarecimentos prestados, as percepções detectadas e demais considerações importantes ao conhecimento do Corregedor-Geral da Justiça.","v":["geral"],"th":["audiencias","prazos","mandados"]},{"n":"124","t":"Compete ao Juiz não vitalício a iniciativa da abertura de processo administrativo para encaminhar, mensalmente, impreterivelmente, até o dia 10 (dez), ao Corregedor-Geral da Justiça, através de meio eletrônico, relatório circunstanciado dos fatos alusivos às atividades funcionais da sua rotina forense, bem como a realização de expediente excepcional, de modo a gerar um cadastro especial, conforme previsão do art. 158, § 2º, do Código de Divisão e Organização Judiciária do Estado do Ceará. § 1º A exposição deve ser pormenorizada e revelar a atuação funcional no período, o método de trabalho desenvolvido, a assiduidade, a quantidade de audiências, a produtividade, dentre outros aspectos relevantes, inclusive, munida de declaração pessoal de residência na Comarca, além de outros indicativos para atestar o comprometimento com os ideais invioláveis da Justiça; § 2º A narrativa deve ainda consignar a situação da unidade, as medidas empreendidas pelo aspirante à vitaliciedade e os progressos alcançados, inclusive, a providência deve ser acompanhada 56 de, no mínimo, 5 (cinco) amostras de decisões e 5 (cinco) sentenças de mérito proferidas em processos mais emblemáticos, de modo a oportunizar a verificação do atendimento à nota de perfeição técnica das peças confeccionadas.","v":["geral"],"th":["audiencias"]},{"n":"125","t":"Para apuração das reais aptidões do examinado, serão considerados, em conjunto, o prontuário preparado pelo Juiz Formador, os relatórios enviados pelos pretendentes à prerrogativa e os demais elementos levados ao conhecimento do Corregedor-Geral da Justiça.","v":["geral"],"th":[]}]},{"num":"IV","title":"DAS UNIDADES JUDICIAIS","articles":[{"n":"126","t":"Todas as Unidades Judiciárias do Estado do Ceará, efetivamente instaladas e em funcionamento, contarão com um supervisor e um assistente, nomeados em comissão pela Presidência do Tribunal de Justiça após livre indicação do respectivo Juiz Titular ou, no caso de vacância, pelo Juiz em respondência, observadas as condições e atribuições fixadas em legislação específica. Parágrafo único. Na Comarca da Capital, funcionarão Secretarias Judiciárias de 1º Grau, na forma e com a estrutura previstas na Lei nº 16.208, de 3 de abril de 2017.","v":["geral"],"th":["secretaria"]},{"n":"127","t":"Além do(a) Supervisor(a) e do(a) Assistente, cada unidade judiciária contará com servidores ocupantes de cargos de provimento efetivo, integrantes das carreiras do Poder Judiciário, de que trata a Lei nº 14.786, de 13 de agosto de 2010, em número compatível com a lotação paradigma do juízo, a ser calculada de acordo com as normas específicas editadas pelo Conselho Nacional de Justiça, ressalvando-se, quanto aos Oficiais de Justiça, a possibilidade de que estejam lotados nas respectivas Centrais de Cumprimentos de Mandados.","v":["geral"],"th":["mandados"]},{"n":"128","t":"As atribuições do(a) Supervisor(a) e do(a) Assistente das unidades judiciárias, bem como dos demais servidores ocupantes de cargos de provimento efetivo integrantes das carreiras do Poder Judiciário estão regulamentadas em leis específicas que tratam da matéria.","v":["geral"],"th":[]},{"n":"129","t":"O ato ordinatório consiste na movimentação processual praticada de ofício pelos servidores das unidades judiciárias, sob a supervisão do Juiz de Direito, independentemente de despacho, visando: I - regularizar tramitação e andamento dos processos; II - desburocratizar atividades e evitar desnecessária repetição de trabalhos; III - garantir efetividade na prestação jurisdicional. § 1º Na prática dos atos ordinatórios, o servidor certificará a realização de ordem do juiz, com indicação do número deste provimento (Consolidação) e de outro ato no mesmo sentido editado pelo Juízo ou pela Corregedoria-Geral da Justiça; § 2º A prática dos atos ordinatórios deve ser revista, quando necessário, pelo juiz, inclusive a requerimento de parte interessada; § 3º O juízo de admissibilidade da petição inicial, denúncia, queixa ou recurso fica reservado, exclusivamente, ao juiz, devendo o servidor, antes de encaminhar a peça inaugural ao magistrado, observar as hipóteses previstas no Art. 130 desta Consolidação; § 4º As petições iniciais com pedidos urgentes, tais como pedidos liminares, cautelares ou de antecipação de tutela, serão conclusas imediatamente ao juiz após o seu recebimento, sem prejuízo do atendimento das exigências previstas no Art. 130 desta Consolidação.","v":["geral"],"th":["atos_ordinatorios"]},{"n":"130","t":"Os servidores das unidades judiciárias e dos gabinetes, onde houver instalada Secretaria Judiciária compartilhada, poderão praticar os seguintes atos ordinatórios: I - apresentada petição inicial, intimar o autor para: a) subscrever a petição inicial quando apócrifa; 58 b) apresentar o instrumento do mandato conferido ao advogado, ressalvadas as hipóteses de advogado em causa própria, de defensor público, de procurador de órgão ou entidade pública e na hipótese prevista no art. 104, § 1º, do CPC; c) fornecer cópias da petição inicial necessárias para a citação dos réus, nos processos que tramitam em meio físico; d) efetuar o preparo quando a inicial não vier acompanhada do comprovante do recolhimento das custas, ou ocorrer o indeferimento da gratuidade da justiça solicitada; e) indicar o valor da causa; f) indicar o estado civil, o número de inscrição no Cadastro de Pessoas Físicas - CPF ou no Cadastro Nacional de Pessoas Jurídicas - CNPJ, o endereço eletrônico, a profissão do autor e outros requisitos objetivos e formais da petição inicial, em caso de omissão; g) esclarecer divergência entre a qualificação constante na petição inicial e os documentos que a instruem ou complementar a qualificação, especialmente quanto ao Código de Endereçamento Postal (CEP). II - oferecida resposta do réu, exceto no Sistema dos Juizados Especiais: a) no processo de conhecimento, apresentada a contestação e se nela arguidas preliminares ou juntados documentos, abrir vista aos interessados para se manifestarem no prazo de 15 (quinze) dias; b) intimar a parte para apresentar o instrumento do mandato conferido ao advogado, ressalvadas as hipóteses de advogado em causa própria, de defensor público ou de procurador de órgão ou entidade pública e na hipótese prevista no art. 104, § 1º, do CPC; c) intimar o autor reconvindo para apresentar resposta no prazo de 15 (quinze) dias (art. 343, § 1º, do CPC), ressalvada a hipótese de pedido liminar; d) intimar o réu reconvinte para manifestação, quando apresentada resposta à reconvenção, se nesta forem arguidas preliminares ou juntados documentos (art. 350 do CPC). III - em face da produção de provas: a) ressalvado pedido urgente, juntados documentos novos por uma das partes, intimar a parte contrária para ciência e manifestação no prazo de 15 (quinze) dias (art. 437 do CPC); 59 b) recebidas respostas de ofícios relativos às diligências determinadas pelo juiz, intimar as partes para manifestação, no prazo comum de 5 (cinco) dias; c) intimar as partes da nomeação do perito para, querendo, no prazo de 15 (quinze) dias, indicar assistente técnico e apresentar quesitos (art. 465, § 1º, II, CPC), à exceção dos processos que tramitam no Sistema dos Juizados Especiais Cíveis; d) intimar perito para apresentar proposta de honorários no prazo de 5 (cinco) dias, após a proposição dos quesitos; e) intimar as partes da proposta de honorários para, querendo, manifestarem-se no prazo comum de 5 (cinco) dias e, após, fazer conclusão dos autos; f) intimar a parte responsável pelo pagamento dos honorários periciais para comprovar o depósito no prazo de 5 (cinco) dias, após arbitrados ou homologados pelo juiz; g) intimar as partes para, querendo, manifestarem sobre o laudo pericial, no prazo comum de 15 (quinze) dias, bem como para apresentarem, em igual prazo, os pareceres de seus assistentes","v":["geral"],"th":["prazos","citacao","secretaria","atos_ordinatorios"]},{"n":"131","t":"Os expedientes do Juízo serão subscritos, em regra, apenas pelo próprio servidor responsável pela sua elaboração, sob a orientação do Juiz de Direito e do Supervisor da unidade judicial ou da Secretaria Judiciária compartilhada, devendo ser encaminhado, quando for o caso, junto com cópia da decisão judicial. § 1º Compreende-se por expedientes do Juízo as correspondências, os ofícios, as certidões e os mandados judiciais. § 2º Dependem de subscrição do magistrado: a) ofícios e alvarás para levantamento de bens e valores; b) mandados de busca e apreensão de criança e adolescente; c) cartas precatórias, rogatórias e editais; d) nos processos criminais, mandados com ordem de constrição ou constituição de direitos, alvarás, ordens de liberação, ordens de internação e desinternação; mandados de prisão, contramandados de prisão e internação, mandados de busca e apreensão, Guia de Execução Criminal, ofício de aditamento à Guia de Recolhimento e expedientes de ordens de interceptação, quebra de sigilo bancário, fiscal e telefônico, dentre outros; e) atos processuais em que necessária assinatura pessoal do juiz, pelo alcance e repercussão jurídica da medida; f) ofícios dirigidos a outro juiz, a membro de Tribunal de Justiça, ou às demais autoridades constituídas, tais como integrantes do Ministério Público, dos Poderes Legislativo e Executivo, Secretários de governo ou detentores de cargos assemelhados, Conselheiros do Tribunal de Contas, Comandantes de unidades de segurança pública, civis e militares. 66","v":["geral"],"th":["mandados","secretaria","presos","execucao"]},{"n":"132","t":"Cabe ao Juiz de Direito e ao Supervisor responsável pela unidade judicial a adoção das providências necessárias à implementação, concretização, orientação e fiscalização do regramento estabelecido no presente ato normativo, sem prejuízo da adoção, por aquele, de outros pertinentes e cabíveis e complementares sobre prática de atos ordinatórios.","v":["geral"],"th":["atos_ordinatorios"]},{"n":"133","t":"Os servidores integrantes do Núcleo de Produtividade Remota poderão praticar os atos ordinatórios descritos neste provimento, sob supervisão do Juiz responsável pelo referido núcleo de trabalho.","v":["geral"],"th":["atos_ordinatorios"]},{"n":"134","t":"(Revogado pelo Prov. nº 22/2024/CGJCE, publicado no DJeA de 18/12/2024)","v":["geral"],"th":[]},{"n":"135","t":"(Revogado pelo Prov. nº 22/2024/CGJCE, publicado no DJeA de 18/12/2024)","v":["geral"],"th":[]},{"n":"136","t":"(Revogado pelo Prov. nº 22/2024/CGJCE, publicado no DJeA de 18/12/2024)","v":["geral"],"th":[]}]},{"num":"V","title":"DAS RECOMENDAÇÕES AOS SERVIDORES EM GERAL","articles":[{"n":"137","t":"As normas deste capítulo possuem caráter geral e se aplicam às unidades judiciais, observados capítulos específicos desta Consolidação ou disposições em outros atos normativos.","v":["geral"],"th":[]},{"n":"138","t":"É proibido aos servidores e auxiliares do Poder Judiciário o exercício de atos que envolvam interesses próprios ou de cônjuge, parente consanguíneo ou afim, em linha reta ou colateral, até o terceiro grau e nos casos de suspeição. 67 Parágrafo único. Verificado o impedimento ou a suspeição, o ato será praticado por substituto legal. Persistindo o impedimento ou a suspeição, o titular solicitará ao Juiz designação de outra pessoa para a prática do ato.","v":["geral"],"th":[]},{"n":"139","t":"Os atos escritos serão redigidos com clareza, precisão e ordem lógica, observados as recomendações do art. 11, da Lei Complementar nº 95/1998.","v":["geral"],"th":[]},{"n":"140","t":"Nos termos e atos em geral, a qualificação de pessoas conterá os nomes, os prenomes, a filiação, o estado civil, a existência de união estável, a profissão, o número de documento de identidade oficial, o número de inscrição no Cadastro de Pessoas Físicas ou no Cadastro Nacional da Pessoa Jurídica, o endereço eletrônico, o domicílio e a residência.","v":["geral"],"th":[]},{"n":"141","t":"As assinaturas serão apostas em seguida ao encerramento do ato, vedados espaços em branco.","v":["geral"],"th":[]},{"n":"142","t":"Será lançado, abaixo de assinaturas colhidas pela unidade judicial nos autos e termos, o nome por extenso do signatário.","v":["geral"],"th":[]},{"n":"143","t":"É proibida assinatura de atos ou termos em branco, total ou parcialmente.","v":["geral"],"th":[]},{"n":"144","t":"Desaparecimento e danificação de livro ou documento serão comunicados imediatamente ao Juiz, que ordenará e supervisionará a imediata restauração, à vista dos elementos existentes.","v":["geral"],"th":[]},{"n":"145","t":"Ao receber a petição inicial ou a denúncia, a secretaria da unidade judicial deverá registrá-la e autuá-la, sob o número de distribuição, numeradas as folhas eletronicamente, contendo cada uma o número do processo. § 1º Os procedimentos incidentais serão autuados em apenso, conforme o caput deste artigo; § 2º Quando a petição inicial vier desacompanhada de contrafé suficiente à citação, notificação ou interpelação dos requeridos, respectivamente, o Supervisor(a) da unidade deverá intimar o patrono da causa para regularizar a situação. 68","v":["geral"],"th":["citacao","secretaria"]},{"n":"146","t":"Observadas as peculiaridades locais, nos processos físicos, as secretarias de unidade judicial utilizarão na medida do possível, capas de cores diferentes para as diversas naturezas dos feitos e tarjas ou etiquetas para assinalar situações especiais.","v":["geral"],"th":["secretaria"]},{"n":"147","t":"A secretaria da unidade judicial, na falta de protocolo mecânico ou eletrônico, certificará de forma legível, no anverso de petições e fora do campo da sua margem, bem como nos expedientes entregues, a data e a hora do respectivo ingresso na secretaria da unidade judicial, fornecendo recibo ao interessado, registrando-se no livro de protocolo, encerrado diariamente.","v":["geral"],"th":["secretaria"]},{"n":"148","t":"A certidão de recebimento e a numeração das folhas dos autos, com a respectiva rubrica, nunca prejudicará a leitura do conteúdo da petição ou do documento. Se necessário, este será afixado numa folha em branco, nela lançada a numeração e a rubrica.","v":["geral"],"th":[]},{"n":"149","t":"Nos termos de conclusão ao Juiz e vista ao Ministério Público constará de forma legível o nome do Juiz e o do Promotor, bem como a data do efetivo encaminhamento dos autos e da devolução, sendo proibida a conclusão e a vista sem data.","v":["geral"],"th":[]},{"n":"150","t":"Desentranhada dos autos alguma peça, será certificado o fato, renumerando-se as folhas.","v":["geral"],"th":[]},{"n":"151","t":"As peças desentranhadas dos autos, enquanto não entregues ao interessado, serão guardadas em local adequado. Nelas o(a) Supervisor(a) da unidade certificará, em lugar visível e sem prejudicar a leitura do seu conteúdo, o número e a natureza do processo de onde retiradas.","v":["geral"],"th":[]},{"n":"152","t":"Os autos do processo físico não excederão de 200 (duzentas) folhas em cada volume, salvo determinação expressa em contrário. O encerramento e a abertura dos volumes serão certificados em folhas suplementares. Os novos volumes serão numerados de forma destacada e a sua formação também será anotada na autuação do primeiro volume.","v":["geral"],"th":["secretaria"]},{"n":"153","t":"Caberá ao Supervisor da Unidade Judicial, no prazo mínimo de 15 (quinze) dias, antes da audiência, examinar o processo, a fim de verificar se todas as providências para a sua realização foram tomadas. Diante de irregularidade ou omissão, deverá ser suprida a falha e feita conclusão, se for o caso. Esta diligência será certificada nos autos.","v":["geral"],"th":["audiencias","prazos"]},{"n":"154","t":"Toda peça extraída e com devolução normal ao caderno processual será emitida em uma só via (como mandado de intimação, avaliação, etc.), nela anexando-se selo de autenticidade correspondente, caso não assinada digitalmente.","v":["geral"],"th":["citacao","mandados"]},{"n":"155","t":"Se a parte não indicar, no pedido, o prazo exato de suspensão do processo, conforme art. 313 do CPC, para maior celeridade, é adequada a fixação do mínimo possível pelo juiz. 69","v":["geral"],"th":["prazos"]},{"n":"156","t":"Compete ao juiz, por ocasião do saneamento: delimitar as questões de fato sobre as quais recairá a atividade probatória, especificando os meios de prova admitidos; definir a distribuição do ônus da prova, observado o art. 373 do CPC; e delimitar as questões de direito relevantes para a decisão do mérito.","v":["geral"],"th":["secretaria"]},{"n":"157","t":"No caso de adiamento de audiências, seja designada nova data no próprio termo, com pronta intimação de advogados e partes presentes, completados os expedientes, se for o caso, com a expedição de mandados. O processo em fase de audiência tem preferência de tramitação.","v":["geral"],"th":["audiencias","citacao","mandados"]},{"n":"158","t":"A suspensão da execução, determinada pelo art. 40, da Lei nº 6.830/80 (Execução Fiscal), é norma imperativa, não dependendo de requerimento da Fazenda Pública exequente, necessária apenas a intimação da decisão que determinar a suspensão e, no caso de arquivamento (art. 40, § 2º), a intimação do representante judicial da exequente.","v":["geral"],"th":["prazos","citacao","execucao"]},{"n":"159","t":"A fase de cumprimento de sentença constitui direito e faculdade da parte vencedora, a quem compete as iniciativas, vedadas ao juiz fora das autorizações legais.","v":["geral"],"th":["mandados"]},{"n":"160","t":"O valor da causa nos embargos do devedor corresponde ao da execução.","v":["geral"],"th":["execucao"]},{"n":"161","t":"Ofícios, certidões e demais atos do ofício serão redigidos com clareza, precisão e ordem lógica, sem preciosismos, arcaísmos, neologismos e adjetivações dispensáveis. A ideia será expressada, quando repetida no texto, por meio das mesmas palavras, evitado emprego de sinônimos com propósito meramente estilístico. § 1º Na Internet ou recinto da unidade judicial, em lugar visível e de modo legível, haverá tabela das custas dos respectivos atos, bem como aviso de que o prazo máximo para a expedição de certidão é de 24 (vinte e quatro) horas, salvo norma específica em contrário; § 2º Conforme o pedido do interessado e ressalvadas situações especiais, a certidão será lavrada em inteiro teor ou por resumo, sempre autenticada pelo serventuário ou seu substituto legal; § 3º Do pedido de certidão, acompanhado do comprovante de recolhimento do emolumento, FERMOJU, a unidade fornecerá ao interessado protocolo, contendo data e previsão da entrega. 70","v":["geral"],"th":["prazos","mandados"]},{"n":"162","t":"Os ofícios, devidamente numerados, serão claros e objetivos, lançada certidão da remessa e, se for o caso, do recebimento quando retornar o comprovante. § 1º Ofícios dirigidos a outro Juiz, a tribunal ou às demais autoridades constituídas, deverão ser redigidos e assinados pelo juiz remetente; § 2º Ofícios destinados à outras serventias e à pessoas naturais e jurídicas em geral, poderão ser assinados pelo(a) supervisor(a) da unidade, com a observação de que o ato é praticado de ordem do Juiz e por autorização desta Consolidação.","v":["geral"],"th":[]},{"n":"163","t":"As informações referentes a habeas corpus, mandados de segurança, agravos de instrumentos, representações por excesso de prazo e reclamações disciplinares com tramitação na Corregedoria-Geral da Justiça ou no Conselho Nacional de Justiça deverão ser redigidos pelo próprio juiz, a quem incumbe a fiscalização quanto ao seu envio à autoridade competente. Seção IV Da Cobrança de Autos","v":["geral"],"th":["prazos","mandados"]},{"n":"164","t":"O supervisor da unidade judicial deve manter controle do cumprimento do prazo de cargas de autos dos advogados, sendo recomendável regular cobrança mensal mediante intimação pelo Diário da Justiça ou pessoalmente, para devolução no prazo de 3 (três) dias, sob as penas do","v":["geral"],"th":["prazos","citacao","mandados","execucao"]},{"n":"234","t":", § 2º do CPC. Parágrafo único. No caso de não atendimento neste prazo, o supervisor da unidade certificará a ocorrência, levando-a ao conhecimento, ao Juiz, para as providências contidas no Art. 234 do CPC.","v":["geral"],"th":["prazos"]},{"n":"165","t":"Ao receber petição de cobrança de autos, a secretaria de unidade judicial nela certificará a impossibilidade da juntada por indevida retenção dos autos, providenciando a intimação determinada no artigo anterior.","v":["geral"],"th":["citacao","secretaria"]},{"n":"166","t":"No caso de não devolução dos autos, o supervisor da unidade levará a situação ao conhecimento do Juiz, que determinará: § 1º A expedição de “mandado de exibição e entrega dos autos”, no prazo de 24 (vinte e quatro) horas, sob pena de caracterizar o crime de sonegação de papel ou objeto de valor probatório; § 2º No retorno do processo, certificação de que o advogado perdeu o direito de vista dos autos, em questão, fora do cartório; 71 §3º Remessa de peças ao Ministério Público para oferecimento de denúncia contra o advogado pelo crime de sonegação de papel ou objeto de valor probatório, conforme art. 356, do CP.","v":["geral"],"th":["prazos","mandados","secretaria","execucao"]},{"n":"167","t":"Na devolução de autos, o supervisor da unidade, depois de minucioso exame, certificará data e nome de quem retirou e devolveu o processo. Diante da constatação ou suspeita de alguma irregularidade, o fato será pormenorizadamente certificado, fazendo-se conclusão imediata.","v":["geral"],"th":[]},{"n":"168","t":"Aplicam-se, no que couber, as normas desta seção aos autos com carga aos órgãos do Ministério Público, da Defensoria Pública e Representantes da Fazenda Pública.","v":["geral"],"th":[]},{"n":"169","t":"A comunicação dos atos processuais poderá ser feita por: I - diário da Justiça Eletrônico; II - carta; III - oficial de justiça; IV - supervisor da unidade judicial; V - edital; VI - por meio eletrônico idôneo (videoconferência, aplicativo de mensagens, e-mail ou outro), autorizados na legislação processual e normas regulamentares vigentes.","v":["geral"],"th":["audiencias","mandados"]},{"n":"170","t":"As intimações a serem efetuadas pelo Diário da Justiça serão encaminhadas, em relações próprias e pela rede de acesso ao sistema informatizado do Tribunal, pelos supervisores das unidades judiciais ou por servidor das Secretarias Judiciárias, quando por elas assistidos, obedecidos os parâmetros preestabelecidos, no prazo de 2 (dois) dias úteis, contado do recebimento dos autos que necessariamente conterão: natureza e número do processo; nome das partes; informação, de forma precisa, levada a conhecimento de advogados das partes; e nomes de advogados das partes e respectivo número de inscrição na OAB. § 1º No caso de existir mais de um advogado de cada parte, será indicado somente o nome daquele que primeiro subscreveu a petição inicial, ou a contestação, ou a primeira intervenção nos autos, salvo manifestação expressa do advogado em sentido contrário; § 2º Se houver mais de uma pessoa no polo ativo ou no passivo, poderá ser indicado o nome da primeira, acrescido da expressão “e outros(s)”; § 3º Se os litisconsortes tiverem procuradores diferentes, figurará o nome do advogado de cada um; § 4º Com o ingresso de outras pessoas no processo, como no caso de litisconsórcio ulterior, assistência ou intervenção de terceiros, poderá ser indicado o nome da primeira pessoa, em cada uma das hipóteses, com o acréscimo da expressão “e outros(s)”; § 5º Em inventários e arrolamentos, falências e insolvência civil decretada, não se fará menção ao nome de quem iniciou o processo, bastando referência ao “espólio de ...”ou “massa falida de...”; § 6º Não havendo parte contrária, bastará indicação do(s) nome(s) do(s) requerentes(s), evitando-se alusão a “juízo”.","v":["geral"],"th":["prazos","secretaria"]},{"n":"171","t":"Os despachos, decisões e sentenças constarão das relações de intimações com o máximo de precisão, evitadas ambiguidades ou omissões, assim como referências dispensáveis, tais como, “publique-se”,“intime-se”.","v":["geral"],"th":["atos_ordinatorios"]},{"n":"172","t":"Na intimação para pagamento ou depósito de certa quantia, preparo de conta ou mera ciência de cálculo ou conta, haverá expressa referência ao montante.","v":["geral"],"th":["citacao"]},{"n":"173","t":"No despacho de conteúdo múltiplo, que exija prévia realização de certo ato de competência de serventuário ou oficial de justiça, deve-se fazer a intimação dos advogados somente depois da concretização desse ato, para a máxima utilidade da publicação. Parágrafo único. Não haverá publicação de despachos não pertinentes à parte. 73","v":["geral"],"th":["citacao","mandados","atos_ordinatorios"]},{"n":"174","t":"As decisões e sentenças serão publicadas somente na sua parte dispositiva, suprimindo-se relatório, fundamentação, data, nome do prolator e expressões dispensáveis. Parágrafo único. As homologações e a simples extinção do processo dispensam integral transcrição, recomendada concisa menção do fato.","v":["geral"],"th":[]},{"n":"175","t":"Feita a publicação, o supervisor da unidade deverá conferi-la e, em seguida, lançar a correspondente certidão nos autos, mencionando o número do jornal, a data e o número da página.","v":["geral"],"th":[]},{"n":"176","t":"Havendo erro ou omissão de elemento indispensável na publicação, outra será feita, independentemente de despacho judicial ou reclamação da parte. Nesse caso, certificará o fato nos autos do processo.","v":["geral"],"th":["atos_ordinatorios"]},{"n":"177","t":"Os supervisores das unidades judiciais observarão instruções sobre elaboração e remessa de relações de intimações, conferindo-as e subscrevendo-as.","v":["geral"],"th":[]},{"n":"178","t":"Os supervisores das unidades judiciais deverão confeccionar relações para intimações dos advogados.","v":["geral"],"th":[]},{"n":"179","t":"O sistema de intimação pelo Diário da Justiça não exclui outras formas previstas em lei.","v":["geral"],"th":["citacao"]},{"n":"180","t":"O juiz providenciará, nos processos sob segredo de justiça, eventuais intimações adequadas pelo Diário da Justiça, identificados a ação, o número do processo e apenas as iniciais do nome das partes, mas com o nome completo do advogado.","v":["geral"],"th":["execucao"]},{"n":"181","t":"No processo civil as citações e intimações serão feitas por correio, salvo nos casos indicados no art. 247 do CPC ou quando frustrada a citação pelo correio.","v":["geral"],"th":["citacao"]},{"n":"182","t":"Com exceção das microempresas e das empresas de pequeno porte, as empresas públicas e privadas são obrigadas a manter cadastro nos sistemas de processo em autos eletrônicos, para efeito de recebimento de citações e intimações, as quais serão efetuadas preferencialmente por esse meio. 74 Parágrafo único. O disposto no caput aplica-se à União, aos Estados, ao Distrito Federal, aos Municípios e às entidades da administração indireta.","v":["geral"],"th":[]},{"n":"183","t":"Os membros da Defensoria Pública, e do Ministério Público, serão intimados pessoalmente com observância dos prazos legais.","v":["geral"],"th":["prazos","citacao"]},{"n":"184","t":"As Centrais de Cumprimentos de Mandados, subordinadas ao Juiz Diretor do Fórum, são unidades responsáveis pelo recebimento, distribuição e cumprimento dos mandados judiciais; e gerenciamento da atividade dos oficiais de justiça. Parágrafo único. Nas comarcas com mais de 02 (duas) unidades judiciais, observada a necessidade do serviço, deverá ser criada uma Central de Mandados.","v":["geral"],"th":["mandados","secretaria"]},{"n":"185","t":"Competirá à Central de Mandados, sob a supervisão do diretor do Foro, a distribuição dos mandados recebidos, entre os oficiais de justiça, entregando-lhes imediatamente, registrando-se no sistema informatizado, ou em livro próprio, o nome daquele a quem coube a distribuição.","v":["geral"],"th":["mandados","secretaria"]},{"n":"186","t":"As diligências atribuídas ao oficial de justiça são intransferíveis e somente com autorização do juiz ocorrerá substituição. Parágrafo único. Os mandados, após distribuição, não poderão ser trocados entre os oficiais de justiça, sob pena de falta grave, nos termos previstos na Lei de Organização Judiciária do Ceará.","v":["geral"],"th":["mandados","secretaria","execucao"]},{"n":"187","t":"Os mandados serão distribuídos independentemente da natureza do processo e de acordo com a competência territorial definida pelo Juiz Diretor do Fórum, observada a peculiaridade de cada município.","v":["geral"],"th":["mandados"]},{"n":"188","t":"Os oficiais de justiça escalados para plantões diários, se for o caso, ficam proibidos de serem substituídos por outros, salvo por motivo de força maior. Parágrafo único. Quando se tratar de mandados de medidas urgentes, a distribuição será feita, preferencialmente, aos oficiais de justiça da região e na ausência destes, aos plantões, sem prejuízo de posterior compensação. 75","v":["geral"],"th":["mandados","secretaria"]},{"n":"189","t":"Os mandados deverão ser remetidos pelas secretarias das unidades judiciais à Central de Cumprimento de Mandados, onde houver, no mesmo dia da sua expedição e, a sua distribuição e entrega ao oficial de justiça, deve acontecer, impreterivelmente, em igual prazo.","v":["geral"],"th":["prazos","mandados","secretaria"]},{"n":"190","t":"Os mandados, cumpridos ou não, deverão ser devolvidos pelos oficiais de justiça à Central de Mandados, até 72 (setenta e duas) horas antes da data do ato a ser realizado, exceto os que deverão ser cumpridos sob condução coercitiva.","v":["geral"],"th":["mandados"]},{"n":"191","t":"(Revogado pelo Prov. nº 05/2024/CGJCE, DJeA de 17/04/2024).","v":["geral"],"th":[]},{"n":"192","t":"O cumprimento dos mandados ficará sob a fiscalização do juiz do feito, que informará irregularidades eventuais ao Juiz Diretor do Fórum para as providências necessárias. Parágrafo único. No último dia útil do mês ou com menor frequência, se necessário, a secretaria da unidade judicial ou a Central de Mandados relacionará os mandados não devolvidos dentro do prazo ainda em poder do oficial de justiça.","v":["geral"],"th":["prazos","mandados","secretaria"]},{"n":"193","t":"Os oficiais de justiça não ocupantes de cargos de provimento em comissão, e exercendo efetivamente atividades externas de cumprimento de mandados, citações, intimações, notificações e outras diligências emanadas do magistrado, registrarão sua frequência em, pelo menos, 2 (dois) dias por semana, em batida única, observados os horários estabelecidos na Portaria nº 1482/2014/TJCE e ajustados com a chefia imediata, de modo que seja sempre garantida a presença desses servidores para atendimento de eventuais diligências e tarefas necessárias durante o horário de funcionamento das unidades judiciárias mencionadas.","v":["geral"],"th":["mandados","atos_ordinatorios"]},{"n":"194","t":"Os oficiais de justiça efetuarão diligências no horário das 06 (seis) horas às 20 (vinte) horas, exceto nos casos previstos em lei.","v":["geral"],"th":[]},{"n":"195","t":"O oficial de justiça entregará, no prazo de 24 (vinte e quatro) horas, a quem de direito, os bens recebidos em cumprimento de ordem judicial.","v":["geral"],"th":["prazos","mandados"]},{"n":"196","t":"É vedada a nomeação de oficial de justiça “ad hoc” através de portaria. Se necessária, a designação será por despacho nos autos, mediante compromisso específico.","v":["geral"],"th":["mandados","atos_ordinatorios"]},{"n":"197","t":"Ao oficial de justiça é vedado a entrega de mandado para cumprimento por terceiros. 76","v":["geral"],"th":["mandados"]},{"n":"198","t":"Os oficiais de justiça cumprirão, indistintamente, os mandados distribuídos, observadas as seguintes exigências: §1º Ao cumprirem as diligências do cargo, os oficiais de justiça deverão consignar a indicação do lugar e a descrição da pessoa citada ou intimada, o número de seu documento oficial de identidade, o órgão expedidor do documento, se possível o número de inscrição no Cadastro de Pessoas Físicas (CPF) ou no Cadastro Nacional de Pessoa Jurídica (CNPJ), a leitura da petição ou do mandado, a declaração de entrega de contrafé ou a recusa em recebê-la, o nome das testemunhas que presenciaram o ato, se houve recusa na aposição da nota de ciente ou não; § 2º Os oficiais de justiça devem dar fé aos atos que efetuem, datando e assinando as certidões, redigidas com clareza e precisão; § 3º As certidões devem mencionar todas as circunstâncias de interesse, inclusive nome e endereços de pessoas informantes, mencionada a hora exata em que foram procuradas as pessoas para a citação, intimação ou notificação, caso não encontradas: I - para evitar anulação do ato, o oficial de justiça fará diligências no horário mais adequado à localização da pessoa a ser citada ou intimada; II - intimações de réus presos que devam ser notificados de qualquer ato do processo, serão feitas no próprio estabelecimento penal em que se encontrarem, sendo lá também entregues cópias de libelo; III - não encontrada a pessoa, por ser outro seu endereço, na mesma oportunidade cuidará o oficial de justiça de apurar com alguém da família ou da casa, ou vizinho, onde se acha a pessoa procurada para a diligência, dentro ou fora do território da jurisdição, e o seu endereço completo: a) se estiver no território da comarca, no endereço obtido, o oficial de justiça cumprirá a diligência e certificará detalhadamente conforme o § 3º deste artigo; b) se confirmado o endereço, mas a pessoa estiver fora na ocasião, o oficial de justiça indagará o horário do retorno e marcará a hora propícia para renovar a diligência; 77 c) se apurado, na diligência, que a pessoa se encontra em comarca de diversa jurisdição, conseguindo ou não o endereço completo, o oficial certificará no mandado. IV - recusados os pedidos de informações a pessoa da família ou da casa, o oficial de justiça lançará a certidão, e voltará no mesmo dia, em horário propício para nova tentativa; V - não encontrada no local a pessoa a quem se dirige a citação ou intimação, havendo fundada suspeita de ocultação, o oficial de justiça marcará hora para o dia útil imediato e certificará. Retornará, então, a procurá-la, sempre nos horários marcados por três vezes consecutivas: a) a procura poderá ser em mesmos dia e horário ou em dia e horário diferentes; b) se presente em alguma das vezes marcadas a pessoa será citada ou intimada na forma da lei; c) não encontrada, na última oportunidade, será citada ou intimada por meio da pessoa presente, constando da certidão nome, descrição e qualificação, número de documento oficial de identidade, órgão expedidor, se possível o número de inscrição no Cadastro de Pessoas Físicas (CPF), endereço e qual a relação com a pessoa citada ou intimada (parente, funcionário, vizinho). Ficam ressalvados deste procedimento os feitos criminais, respeitando-se o disposto no art. 362, do CPP. VI - na hipótese de intimação de advogados, não localizados, deverá o oficial de justiça diligenciar, junto à OAB/CE, a fim de obter o endereço; VII - efet ua da a diligência, nos termos dos §§1º, 2º e 3º do art. 212, do CPC, deverá o oficial de justiça certificar a hora de sua realização.","v":["geral"],"th":["citacao","mandados","presos","execucao"]},{"n":"199","t":"É vedada a devolução de mandado sem a realização da diligência, a pedido direto de qualquer interessado, sendo possível apenas certificar, no mandado, proposta de autocomposição apresentada por qualquer das partes, na ocasião do cumprimento.","v":["geral"],"th":["mandados","execucao"]},{"n":"200","t":"O mandado desentranhado para cumprimento deverá ser entregue ao mesmo oficial de justiça que iniciou a diligência, salvo quando afastado por gozo de férias ou qualquer outro motivo, caso em que será distribuído a outro oficial de justiça.","v":["geral"],"th":["mandados"]},{"n":"201","t":"Será desentranhado o mandado e entregue ao mesmo oficial de justiça para cumprimento correto, quando não observadas as diretrizes do art. 198 desta Consolidação.","v":["geral"],"th":["mandados"]},{"n":"202","t":"Antes de certificar que o citando ou o intimando se encontra em lugar incerto ou inacessível, o oficial de justiça deverá esgotar todas as possibilidades de localização pessoal. 78","v":["geral"],"th":["mandados"]},{"n":"203","t":"Citações, penhoras e medidas urgentes poderão ser, excepcionalmente, efetuadas aos domingos e feriados e, nos dias úteis, fora do horário estabelecido, desde que conste expressamente no mandado, autorização do juiz, cumprindo ao executor ler à parte os termos dessa autorização e observar a regra constitucional de proteção ao domicílio.","v":["geral"],"th":["mandados"]},{"n":"204","t":"Nos atos que impliquem busca e apreensão ou depósito de bens, especialmente veículos automotores, o oficial de justiça deverá descrever minuciosamente os bens, especificando suas características, tal como marca, estado de conservação, acessórios, funcionamento, quilometragem, entre outras que se mostrem relevantes.","v":["geral"],"th":["mandados"]},{"n":"205","t":"Em ações de nunciação de obra nova, o oficial de justiça deverá lavrar auto circunstanciado, descrevendo o estado em que se encontra a obra.","v":["geral"],"th":["mandados"]}]},{"num":"VI","title":"DOS SERVIÇOS AUXILIARES DA JUSTIÇA","articles":[{"n":"206","t":"Todos os processos estão sujeitos a registro, devendo ser distribuídos onde houver mais de um juiz.","v":["geral"],"th":[]},{"n":"207","t":"A distribuição, que poderá ser eletrônica, será alternada e aleatória, obedecendo-se rigorosa igualdade. Parágrafo único. A lista de distribuição deverá ser publicada no Diário de Justiça.","v":["geral"],"th":["secretaria"]},{"n":"208","t":"À Distribuição, compete: I - distribuição de todos os processos entre os juízes; II - averbações e os cancelamentos de sua competência; III - expedição de certidões de atos e documentos que constem de seus registros. 79","v":["geral"],"th":["mandados","secretaria"]},{"n":"209","t":"Serão distribuídas por dependência as causas de qualquer natureza: I - quando se relacionarem, por conexão ou continência, com outra ajuizada; II - quando, extinto o processo sem resolução de mérito, for reiterado o pedido, ainda que em litisconsórcio com outros autores ou que sejam parcialmente alterados os réus da demanda; III - quando houver ajuizamento de ações nos termos do art. 55, § 3º, do CPC, ao juízo prevento. §1º A reiteração ou a repetição de petição inicial será, obrigatoriamente, distribuída à mesma unidade judicial, ainda que cancelada a distribuição anterior e nas hipóteses de extinção do processo sem julgamento de mérito; § 2º Havendo intervenção de terceiro, reconvenção ou outra hipótese de ampliação objetiva do processo, o juiz, de ofício, determinará a respectiva anotação pelo distribuidor.","v":["geral"],"th":["audiencias","secretaria"]},{"n":"210","t":"É vedado ao distribuidor reter quaisquer processos destinados à distribuição, a qual deve ser feita em ato contínuo e em ordem rigorosamente sucessiva, à proporção que apresentados.","v":["geral"],"th":["secretaria"]},{"n":"211","t":"As petições ou denúncias acompanhadas das respectivas contrafés, e os feitos apresentados à distribuição, serão protocolizados eletronicamente, salvo em unidades judiciais não virtualizadas, quando o protocolo será mecânico ou manual, lançado no livro próprio.","v":["geral"],"th":["secretaria"]},{"n":"212","t":"Nos assentamentos da distribuição constarão dados suficientes à perfeita identificação dos interessados, extraídos da petição e documentos que a instruem, número de documento oficial de identidade e inscrição no Cadastro de Pessoas Físicas (CPF) ou no Cadastro Nacional de Pessoas Jurídicas (CNPJ), assim como nomes e endereços dos advogados, eletrônico e não eletrônico.","v":["geral"],"th":["secretaria"]},{"n":"213","t":"Após a distribuição, nenhuma petição ou feito será confiado a advogado ou a qualquer interessado, até a sua remessa à unidade judicial competente.","v":["geral"],"th":["secretaria"]},{"n":"214","t":"A distribuição poderá ser fiscalizada pela parte, por seu procurador, pelo Ministério Público e pela Defensoria Pública.","v":["geral"],"th":["secretaria"]},{"n":"215","t":"O juiz, de ofício ou a requerimento do interessado, corrigirá o erro ou compensará a falta de distribuição.","v":["geral"],"th":["secretaria"]},{"n":"216","t":"Será cancelada a distribuição do feito se a parte, intimada na pessoa de seu advogado, não realizar o pagamento das custas e despesas de ingresso em 15 (quinze) dias.","v":["geral"],"th":["secretaria"]},{"n":"217","t":"(Revogado pelo Provimento nº 03/2024/CGJCE, DJeA de 22/02/2024)","v":["geral"],"th":[]},{"n":"218","t":"(Revogado pelo Provimento nº 03/2024/CGJCE, DJeA de 22/02/2024)","v":["geral"],"th":[]},{"n":"219","t":"Incumbe ao partidor organizar esboços de partilha e sobrepartilha de acordo com o pronunciamento judicial que os houver deliberado e disposto na legislação processual.","v":["geral"],"th":[]},{"n":"220","t":"Quando do esboço constar a partilha de bem comum a mais de uma pessoa, será registrada a fração ideal do todo e respectivo valor.","v":["geral"],"th":[]},{"n":"221","t":"A guarda e a conservação de bens penhorados, arrestados, sequestrados ou arrecadados serão confiadas a depositário ou a administrador, não dispondo a lei de outro modo. Parágrafo único. Ao receber o bem, o depositário ou o administrador deverá identificá-lo, constando o número do registro, do processo, unidade judicial, nome das partes e a data do recebimento.","v":["geral"],"th":[]},{"n":"222","t":"Por seu trabalho o depositário ou o administrador perceberá remuneração que o juiz fixará levando em conta a situação dos bens, ao tempo do serviço e às dificuldades de sua execução. Parágrafo único. O juiz poderá nomear um ou mais prepostos por indicação do depositário ou do administrador. 81","v":["geral"],"th":["execucao"]},{"n":"223","t":"O depositário ou o administrador responde pelos prejuízos que, por dolo ou culpa, causar à parte, perdendo a remuneração que lhe foi arbitrada, mas tem o direito a haver o que legitimamente despendeu no exercício do encargo. Parágrafo único. O depositário infiel responde civilmente pelos prejuízos causados, sem prejuízo de sua responsabilidade penal e da imposição de sanção por ato atentatório à dignidade da justiça.","v":["geral"],"th":["execucao"]},{"n":"224","t":"É lícito às partes ajustar a forma de administração e escolher o depositário, hipótese em que o juiz homologará por despacho a indicação.","v":["geral"],"th":["atos_ordinatorios"]},{"n":"225","t":"O juiz poderá nomear administrador ou depositário o exequente ou o executado, ouvida a parte contrária, e, não havendo acordo, nomeará profissional qualificado. § 1º O administrador ou depositário submeterá à aprovação judicial a forma de administração e a de prestar contas periodicamente; § 2º Havendo discordância entre as partes ou entre essas e o administrador ou o depositário, o juiz decidirá a melhor forma de administração do bem.","v":["geral"],"th":[]},{"n":"226","t":"Quando os bens depositados forem de fácil deterioração, estiverem avariados ou exigirem grandes despesas para sua guarda, o depositário comunicará o fato ao juiz competente, para fins de decisão sobre alienação judicial antecipada.","v":["geral"],"th":[]},{"n":"227","t":"Na hipótese de constrição anterior sobre o mesmo bem, o depositário ou o administrador certificará, especificamente, a ocorrência no registro e no auto, de todas as constrições, com a correspondente comunicação ao juízo.","v":["geral"],"th":[]},{"n":"228","t":"Os oficiais de justiça são juridicamente subordinados aos Juízes perante os quais servirem, sem prejuízo, todavia, da vinculação administrativa que tiverem com o juiz diretor do fórum, ou com o juiz coordenador da Central de Mandados, onde houver.","v":["geral"],"th":["mandados"]},{"n":"229","t":"A identificação do oficial de justiça, no desempenho de suas funções, será feita mediante a apresentação da carteira funcional, indispensável em todas as diligências, da qual deverá estar obrigatoriamente munido. 82","v":["geral"],"th":["mandados"]},{"n":"230","t":"O oficial de justiça deverá dispensar às partes e advogados a máxima urbanidade e solicitude no desempenho de suas atribuições.","v":["geral"],"th":["mandados"]},{"n":"231","t":"Incumbe ao oficial de justiça: I - fazer pessoalmente citações, prisões, penhoras, arrestos e demais diligências próprias do seu ofício, sempre que possível na presença de 2 (duas) testemunhas, certificando no mandado o ocorrido, com menção ao lugar, ao dia e à hora; II - executar as ordens do juiz a que estiver juridicamente subordinado; III - entregar o mandado em cartório após seu cumprimento; IV - auxiliar o juiz na manutenção da ordem; V - efetuar avaliações, quando for o caso; VI - certificar, em mandado, proposta de autocomposição apresentada por qualquer das partes, na ocasião de realização de ato de comunicação que lhe couber; VII - convocar pessoas idôneas para testemunhar atos de sua função, quando a lei exigir; VIII - ser assíduo e diligente, no fórum ou na Central de Cumprimento de Mandados, onde houver, de acordo com as disposições normativas específicas sobre registro de frequência.","v":["geral"],"th":["mandados","secretaria"]}]},{"num":"VII","title":"DA TRAMITAÇÃO PROCESSUAL","articles":[{"n":"232","t":"Terão prioridade na tramitação em primeira instância os procedimentos judiciais, inclusive cartas precatórias, rogatórias ou de ordem, em que figure como parte ou interessado as indicadas no art. 1.048 do CPC. 83 Parágrafo único. Dentre os idosos, terão prioridade especial de tramitação, os procedimentos judiciais em que figure como parte ou interessado pessoa idosa maior de 80 (oitenta) anos, nos termos da Lei nº 13.466/2017, datada de 12/07/2017.","v":["geral","civel","criminal"],"th":[]},{"n":"233","t":"A pessoa interessada na obtenção do benefício, juntando prova de sua condição, deverá requerê-lo ao juízo competente, que determinará à Secretaria as providências a serem cumpridas.","v":["geral","civel","criminal"],"th":["secretaria"]},{"n":"234","t":"Deferida a prioridade, os autos receberão identificação própria que evidencie o regime de tramitação prioritária. § 1º Concedida a prioridade, essa não cessará com a morte do beneficiado, estendendo-se em favor do cônjuge supérstite ou do companheiro em união estável; § 2º A tramitação prioritária independe de deferimento pelo órgão jurisdicional e deverá ser imediatamente concedida diante da prova da condição de beneficiário.","v":["geral","civel","criminal"],"th":[]},{"n":"235","t":"A designação de audiências, bem como a prolação de despachos, decisões ou sentenças terão caráter prioritário sobre os demais processos que não gozem do benefício ora estabelecido, obedecendo ao contido no art. 12, § 2º, VII do Código de Processo Civil.","v":["geral","civel","criminal"],"th":["audiencias","atos_ordinatorios"]},{"n":"236","t":"As informações requisitadas em sede de habeas corpus, de mandado de segurança e agravo serão redigidas pelo próprio magistrado, devendo o respectivo ofício ser cumprido em caráter prioritário, com a maior celeridade possível, sempre obedecendo o prazo legal.","v":["geral","civel","criminal"],"th":["prazos","mandados"]},{"n":"237","t":"O envio da requisição de informações será feito por malote digital, devendo os magistrados verificar, diariamente, suas caixas de correio eletrônico, com o escopo de identificar os pedidos em comento.","v":["geral","civel","criminal"],"th":[]},{"n":"238","t":"A remessa de senha para acesso dos autos digitais deve ser feita quando expressamente determinada pelo requisitante ou quando a autoridade judiciária requisitada considerar necessária à compreensão do contexto em que a decisão objurgada fora proferida, não tendo o condão de substituir as informações solicitadas. 84","v":["geral","civel","criminal"],"th":[]},{"n":"239","t":"As informações deverão limitar-se a apresentar o contexto processual em que a decisão objeto do habeas corpus, do mandado de segurança ou do agravo fora prolatada, não servindo para veiculação de defesa específica.","v":["geral","civel","criminal"],"th":["mandados"]},{"n":"240","t":"Nos casos em que o magistrado destinatário do pedido de informações vislumbrar falta de atribuição para responder ao pedido de informações, deverá encaminhá-lo, de plano, à autoridade que entender competente, devendo tal fato ser comunicado à autoridade requisitante no prazo máximo de 48 (quarenta e oito) horas.","v":["geral","civel","criminal"],"th":["prazos"]},{"n":"241","t":"Antes do afastamento temporário em decorrência de férias ou assuntos de interesse particular, o juiz da Comarca deverá prestar todas as informações requisitadas em sede de habeas corpus, mandado de segurança e agravo. § 1º Em casos de afastamento em decorrência de situação de extrema necessidade ou motivo de força maior, o magistrado deverá justificar à autoridade requisitante o não cumprimento da diligência no prazo assinalado, tão logo retorne ao exercício de suas atividades; § 2º Nas hipóteses previstas no parágrafo anterior, a Secretaria da Unidade judicial deverá comunicar, imediatamente, ao magistrado substituto, a pendência quanto ao cumprimento dos expedientes de que trata esta seção.","v":["geral","civel","criminal"],"th":["prazos","mandados","secretaria"]},{"n":"242","t":"A expedição de cartas precatórias e rogatórias deverá ser precedida de rigorosa fiscalização para encaminhamento ao juízo deprecado, devidamente instruída, consoante o art. 260 do Código de Processo Civil (Lei nº 13.105/2015), a fim de evitar procrastinações. § 1º O encaminhamento das cartas precatórias no sistema SAJPG, no âmbito do Estado do Ceará, far-se-á exclusivamente pela via eletrônica, com a ferramenta destinada à geração do documento e com as comunicações do próprio sistema, sendo vedada a utilização de outro meio. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) § 2º Para as competências que foram implantadas no PJe, o encaminhamento das cartas precatórias, no âmbito do Estado do Ceará, far-se-á exclusivamente pelo próprio sistema, sendo vedada a utilização de outro meio, atendendo-se às orientações abaixo: (Incluído pelo Prov. nº 85 06/2024/CGJCE, DJeA de 24/05/2024) I - caberá ao servidor da unidade judicial deprecante realizar o cadastro no sistema e indicar a comarca ou juizado de destino; e (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) II - após o cumprimento da diligência, a resposta deverá ser informada ao juízo deprecante por malote digital. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) § 3º Na excepcional hipótese de não funcionamento do sistema, as cartas precatórias para cumprimento de medidas urgentes serão encaminhadas por Malote Digital para o distribuidor, mediante confirmação por qualquer canal de comunicação, o que deverá ser devidamente certificado nos autos. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) § 4º Se a carta precatória, oriunda de uma das comarcas do Estado do Ceará, por seu caráter itinerante, tiver que ser redistribuída para cumprimento em comarca diversa, mas no próprio Estado, utilizar-se-á funcionalidade disponível no sistema informatizado para a redistribuição de processos entre foros, comunicando-se o juízo deprecante acerca do encaminhamento. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) § 5º A expedição de cartas precatórias destinadas a outra unidade da Federação ou outra Justiça deverá observar o regramento pertinente a cada um dos órgãos destinatários, devendo as unidades se certificarem a respeito antes do encaminhamento. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) § 6º É facultado ao procurador da parte interessada retirar a carta precatória destinada a outra unidade da Federação ou outra Justiça, devendo comprovar a distribuição no prazo de até 15 (quinze) dias. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024)","v":["geral","civel","criminal"],"th":["prazos","mandados","secretaria"]},{"n":"243","t":"Ao receber a carta desacompanhada de peças essenciais, o juízo destinatário concederá ao remetente a oportunidade para fornecer o(s) documento(s) faltante(s), no prazo máximo de 10 (dez) dias, devendo a solicitação e a resposta serem enviadas por e-mail ou outro meio eletrônico célere e eficaz. (Redação alterada pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) Parágrafo único. Não havendo resposta no prazo estabelecido no caput deste artigo, a carta deverá ser devolvida, conforme art. 267, inciso I, do Código de Processo Civil (Lei nº 13.105/2015).","v":["geral","civel","criminal"],"th":["prazos","citacao"]},{"n":"244","t":"Na hipótese do encaminhamento de nova carta, fazendo referência à anterior expedida e devolvida sem cumprimento em virtude da falta de documento(s), far-se-á a distribuição, por equidade, não se configurando a prevenção. 86","v":["geral","civel","criminal"],"th":["mandados","secretaria"]},{"n":"245","t":"Recebida a carta precatória, com a devida autuação e distribuição, se não exigido ato específico do juiz para cumprimento da diligência, a secretaria cumprirá a medida solicitada por ato ordinatório, independentemente de conclusão dos autos. § 1º É necessária a prévia deliberação do juiz deprecado nos casos de arresto ou penhora, transferência de valores, prisão, soltura, alteração de guarda, liberação de bens, busca e apreensão, designação de leilão ou de praça e levantamento de constrição (penhora, arresto, caução etc.); § 2º A carta precatória recebida servirá de mandado para cumprimento quando, por si só, atender a sua finalidade. § 3º Quando os pedidos de informação sobre o cumprimento das cartas precatórias não forem respondidos pelo juízo deprecado, estabelecer-se-á contato (telefone, e-mail, balcão virtual ou outros) para obtenção das informações, com certificação nos autos. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) § 4º A intervenção da Corregedoria Geral da Justiça, a fim de obter informações sobre o cumprimento de atos deprecados, somente poderá ser solicitada se instruída com a certidão mencionada no § 3º. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024)","v":["geral","civel","criminal"],"th":["mandados","secretaria","presos","atos_ordinatorios"]},{"n":"246","t":"Cumprida a providência requestada, a secretaria está autorizada a promover a devolução do instrumento processual por meio eletrônico, realizando a movimentação no sistema processual e a baixa devida. (Redação conferida pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024) Parágrafo único. Quando se tratar de carta precatória oriunda de uma das comarcas do Estado do Ceará, a devolução dar-se-á por meio de sistema informatizado, contendo cópia da precatória recebida, os documentos que comprovem os atos praticados no juízo deprecado, e, em anexo, eventuais mídias produzidas em audiência (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024)","v":["geral","civel","criminal"],"th":["audiencias","secretaria"]},{"n":"247","t":"Em todas as hipóteses, o ofício de devolução da carta precatória ao juízo de origem poderá ser assinado por qualquer servidor.","v":["geral","civel","criminal"],"th":[]},{"n":"248","t":"A carta precatória será remetida com a cópia da inicial e/ou peças necessárias, bem assim endereços das partes, dos advogados e até mesmo telefone, reservando-se espaço para o despacho do juiz deprecado, além de informar se a ordem deprecada é abrangida pela gratuidade judiciária.","v":["geral","civel","criminal"],"th":["atos_ordinatorios"]},{"n":"249","t":"No âmbito do Estado do Ceará, a carta precatória só será expedida após o cálculo das custas e porte de retorno, quando for o caso, e sua remessa ao juízo deprecado fica condicionada ao depósito do valor correspondente, a ser também encaminhado. 87 Parágrafo único. Para tanto, será intimada a parte ou advogado e decorrido o prazo de 5 (cinco) dias, sem as providências de que trata o caput deste artigo, será considerado como desistência da diligência objeto da precatória.","v":["geral","civel","criminal"],"th":["prazos"]},{"n":"250","t":"Toda carta precatória, oriunda de outro Estado, deverá ser preparada no prazo de 30 (trinta) dias, quando devido o pagamento, findo o qual será devolvida, sem distribuição.","v":["geral","civel","criminal"],"th":["prazos","secretaria"]},{"n":"251","t":"É proibida a entrega de carta precatória a pessoa estranha ao processo. (Redação conferida pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024)","v":["geral","civel","criminal"],"th":[]},{"n":"251-A","t":"Salvo requerimento de apresentação espontânea, o ofendido, a testemunha e o perito residentes fora do juízo serão inquiridos e prestarão esclarecimentos por videoconferência, na sede do foro de seu domicílio ou no estabelecimento prisional ao qual estiverem recolhidos. (Incluído pelo Prov. nº 05/2023/CGJCE, DJe de 06/03/2023). § 1º No interesse da parte que residir distante da sede do juízo, o depoimento pessoal ou interrogatório será realizado por videoconferência, na sede do foro do seu domicílio. (Incluído pelo Prov. nº 05/2023/CGJCE, DJe de 06/03/2023). § 2º Salvo impossibilidade técnica ou dificuldade de comunicação, deve-se evitar a expedição de carta precatória inquiritória. (Incluído pelo Prov. nº 05/2023/CGJCE, DJe de 06/03/2023). § 3º (Revogado pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024)","v":["geral","civel","criminal"],"th":["audiencias","mandados"]},{"n":"251-B","t":"A distribuição de cartas precatórias nos feitos de atuação da Defensoria Pública deverá ser realizada diretamente pelo juízo deprecante ao juízo deprecado, observando-se o disposto no art. 4º, caput e § 2º da Resolução nº 354, de 19 de novembro de 2020, do CNJ. (Incluído pelo Prov. nº 06/2024/CGJCE, DJeA de 24/05/2024)","v":["geral","civel","criminal"],"th":["secretaria"]},{"n":"252","t":"As sentenças serão proferidas diretamente no Sistema de Automação Judicial - SAJ, tanto eletrônico quanto físico, sob pena de apuração da responsabilidade administrativa e funcional do juiz recalcitrante. 88 Parágrafo único. A imposição é relativa às unidades de primeiro grau de jurisdição cujos processos tramitam no referido sistema.","v":["geral","civel","criminal"],"th":["execucao"]},{"n":"253","t":"A remessa de processos por declínio de competência entre os diferentes sistemas utilizados nas unidades judiciais do Estado do Ceará obedecerá aos procedimentos definidos no Anexo IX desta Consolidação.","v":["geral","civel","criminal"],"th":[]},{"n":"254","t":"Serão observadas, no que couber, as orientações dos Manuais de Baixa Processual disponíveis na intranet, resolvidos os casos omissos pela Corregedoria-Geral da Justiça do Ceará. Seção VI Da Evolução de Classe no Cumprimento de Sentença","v":["geral","civel","criminal"],"th":["mandados"]},{"n":"255","t":"Os pedidos de cumprimento de sentença, apresentados pelas partes interessadas em peticionamento intermediário, deverão ser processados nos próprios autos da ação de conhecimento, não sujeitos à prévia distribuição. Parágrafo único. Serão distribuídos os pedidos de cumprimento provisório de sentença e/ou de cumprimento de sentença propostos em juízo de comarca diversa daquela onde tramitou o processo de conhecimento.","v":["geral","civel","criminal"],"th":["mandados","secretaria"]},{"n":"256","t":"Apresentado pedido de cumprimento de sentença, observada a certidão de trânsito em julgado da sentença no processo de conhecimento, a unidade judiciária efetuará a evolução de classe do processo de conhecimento, adequando o valor da causa e, se necessário, as partes em novos polos processuais, conforme indicado abaixo. EVOLUÇÃO DE CLASSE – CUMPRIMENTO DE SENTENÇA CLASSE CÓDIGO Cumprimento de Sentença 156 89 Cumprimento de Sentença contra a Fazenda Pública 12078 Cumprimento de Sentença de Obrigação de Prestar Alimentos 12246 Cumprimento de Sentença – Lei Arbitral (Lei 9.307/1996) 12231 § 1º Verificando-se a ausência de certidão de trânsito em julgado, se decorridos os prazos, a unidade judiciária certificará o trânsito em julgado antes de efetuar a evolução de classe do processo de conhecimento, de acordo com a explicação do caput; § 2º A expedição da guia para recolhimento de eventuais taxas judiciárias referentes ao processo de conhecimento deverá ser realizada antes da evolução de classe; § 3º É vedada a utilização da funcionalidade “correção de classe” para cadastramento de pedidos de cumprimento de sentença, assim como para prosseguimento dos equivocadamente distribuídos.","v":["geral","civel","criminal"],"th":["prazos","mandados"]},{"n":"257","t":"Se dois ou mais pedidos de cumprimento de sentença, referentes ao mesmo processo de conhecimento, forem propostos em oportunidades distintas, o primeiro deverá ser processado nos autos do processo de conhecimento, conforme previsto nos artigos anteriores e os demais deverão ser analisados pela secretaria da unidade e gabinete, encaminhados à Distribuição/SEJUD, conforme o caso, para cadastramento como novo cumprimento a ser distribuído por dependência ao principal.","v":["geral","civel","criminal"],"th":["mandados","secretaria"]},{"n":"258","t":"O procedimento regulamentado nesta seção deverá ser utilizado somente nos peticionamentos apresentados após a data de publicação do Provimento nº 21/2019/CGJCE (DJe de 14/11/2019). (Redação conferida pelo Prov. nº 13/2023/CGJCE, DJe de 12/06/2023). Parágrafo único. Para fins de regularização dos pedidos de cumprimento de sentença ajuizados em data anterior a expedição do normativo referido no caput, fica autorizada a utilização da funcionalidade “correção de classe”, a ser aplicada no processo de conhecimento respectivo. (Incluído pelo Prov. nº 13/2023/CGJCE, DJe de 12/06/2023).","v":["geral","civel","criminal"],"th":["mandados"]},{"n":"259","t":"No Sistema de Automação Judicial do Primeiro Grau (SAJPG) serão utilizadas tarjas eletrônicas para identificação visual das situações processuais abaixo identificadas: 90 TARJAS PROCESSUAIS SISTEMA DE AUTOMAÇÃO JUDICIAL PRIMEIRO GRAU CÓDIGO COR TARJAS 1006 Adolescente apreendido 1081 Adoção - Cadastro 1082 Anjos da Adoção 1050 Afastamento do lar 22 Análise de Penhora 208 Assunção de Competência (IAC) 1037 Bens apreendidos 1074 Cadastro Conferido 21 Cadastro de Penhora no Rosto dos Autos 1005 Cirurgia, Leito Hospitalar e Medicamentos","v":["geral","civel","criminal"],"th":[]},{"n":"260","t":"As solicitações de inclusão de novas tarjas processuais deverão ser submetidas ao crivo da Comissão Permanente de Padronização de Procedimentos e Processos de Trabalho no âmbito das Unidades Judiciárias de 1º Grau, instituída pela Portaria nº 593/2019/TJCE.","v":["geral","civel","criminal"],"th":["atos_ordinatorios"]},{"n":"261","t":"Recebidos os autos digitais, o setor competente procederá à correção do cadastro inicialmente efetivado pelo advogado, promovendo a devida identificação dos processos que necessitem de tratamento urgente ou tenham prioridade de tramitação processual garantida por lei, com as tarjas especificadas nos termos do presente ato normativo.","v":["geral","civel","criminal"],"th":[]},{"n":"262","t":"Cabe ao supervisor da unidade judicial o cadastro de decretação de segredo de justiça; concessão de gratuidade judiciária; tramitação prioritária do processo - idoso, idoso maior de 80 (oitenta) anos, pessoa com deficiência, portadores de doenças graves ou vítimas de violência doméstica e familiar; e reconhecimento de benefício processual a alguma das partes, no Sistema de Automação Judicial do Primeiro Grau (SAJPG).","v":["geral","civel","criminal"],"th":[]},{"n":"263","t":"A Comissão Permanente de Padronização de Procedimentos e Processos de Trabalho no âmbito das Unidades Judiciárias de 1º Grau deverá analisar e, caso necessário, propor à Corregedoria a exclusão das tarjas atualmente vigentes, desde que não sejam provenientes de cadastro automatizado no sistema SAJPG.","v":["geral","civel","criminal"],"th":[]}]},{"num":"VIII","title":"DA ALIENAÇÃO DE BENS APREENDIDOS","articles":[{"n":"264","t":"Antes de apreciar o recebimento de denúncia ou quando de sua apreciação, o juiz providenciará a intimação do Ministério Público e, se for o caso, do querelante, para que, dentre os bens apreendidos, especifique quais devem ser mantidos sob guarda judicial para a instrução processual ou para as investigações em curso e quais podem ser objeto de devolução, doação, destruição ou alienação antecipada. 93 § 1º A intimação do Ministério Público para os fins do caput poderá ser feita após encerrada a audiência de custódia; § 2º O investigado, durante a fase de inquérito, quando de sua citação ou a qualquer tempo, nos autos da ação penal, deverá ser intimado para os fins do caput, no prazo de 05 (cinco) dias; § 3º Ouvidas as partes, preferencialmente antes do início da instrução, decidirá o juiz sobre a devolução, doação, destruição ou alienação antecipada dos bens apreendidos, com fundamento na Resolução nº 11/2015 do Órgão Especial do TJCE e na legislação correlata; § 4º Antes de decidir pela destinação do bem, ausente indicação prévia de classificação de valor estimado considerável ou restando dúvida sobre a pertinência, o Juiz poderá determinar a avaliação judicial do bem, a cargo de oficial de justiça; § 5º Caso entenda necessária a manutenção do bem apreendido por interesse do processo ou da investigação, deverá o magistrado proferir decisão fundamentada; § 6º Cessada a necessidade de manutenção do bem, poderá o magistrado, a qualquer tempo, realizar a alienação do bem apreendido, nos termos desta Consolidação.","v":["criminal","execucao"],"th":["audiencias","prazos","citacao","mandados","presos","execucao"]},{"n":"265","t":"Determinada a alienação antecipada de bens apreendidos, o juiz ordenará avaliação por oficial de justiça, em prazo não superior a 10 (dez) dias; nomeará leiloeiro dentre os credenciados pelo TJCE para auxílio ao oficial de justiça na avaliação; e ordenará às secretarias de fazenda e aos órgãos de registro e controle as averbações necessárias. § 1º O procedimento de alienação antecipada de bens deverá ser autuado no sistema de processo judicial eletrônico em apartado, registrado sob taxonomia própria; § 2º Caso necessário conhecimentos especializados, em razão da natureza dos bens apreendidos, o juiz poderá nomear avaliador específico; § 3º O arrematante deverá pagar a comissão do Leiloeiro, no importe de 5% sobre o valor da arrematação (art. 24, parágrafo único, do Decreto nº 21.981, de 19.10.1932); § 4º As partes devem ser intimadas da decisão do caput e, em se tratando de bens vinculado a delitos de tráfico de drogas, a Secretaria Nacional Antidrogas (SENAD) também será intimada para se manifestar no prazo de 5 (cinco) dias.","v":["criminal","execucao"],"th":["prazos","mandados","secretaria"]},{"n":"266","t":"Nos casos de alienação antecipada de veículos em que leiloeiros credenciados recusem a nomeação, por inviabilidade econômica ou outro motivo, o juiz determinará que o leilão seja 94 realizado pelo DETRAN/CE, nos termos do Convênio de Cooperação Técnica nº 68/2019, celebrado pelo TJCE com Ministério Público, Polícia Civil e o Departamento Estadual de Trânsito.","v":["criminal","execucao"],"th":[]},{"n":"267","t":"Ao realizar vistoria veicular, deverão ser promovidas ações necessárias junto aos órgãos de trânsito, de forma a tornar os veículos livres e desembaraçados de quaisquer ônus para alienação, atentando o avaliador especialmente para a verificação dos seguintes itens: a) chassi; b) número de motor; c) estrutura veicular; d) confrontação de dados com as informações do sistema informatizado do DETRAN e/ou INFOSEG; e e) verificação de débitos, gravames - alienação fiduciárias ou outro ônus real - e restrições administrativas e/ou judiciais. § 1º Constatado débito ou outra restrição administrativa, o juiz solicitará ao órgão de trânsito, à Secretaria de Fazenda ou a outros órgãos e unidades com gerência sobre a desvinculação de débitos, que seja procedida a baixa anterior à alienação; § 2º Constatado gravame (alienação fiduciária, arrendamento mercantil, entre outros), o juiz solicitará ao órgão de trânsito ou a outros órgãos e unidades com gerência sobre o assunto, a respectiva baixa, anterior à alienação, mediante requerimento a ser referendado ao Sistema Nacional de Gravames-SNG.","v":["criminal","execucao"],"th":["secretaria"]},{"n":"268","t":"Apresentado o laudo de avaliação, o Ministério Público e os interessados serão intimados para fins de manifestação, no prazo de 5 (cinco) dias.","v":["criminal","execucao"],"th":["prazos","citacao"]},{"n":"269","t":"Decorrido o prazo, com ou sem manifestação, devem os autos serem conclusos para deliberação acerca de eventuais divergências, homologação do valor atribuído e autorização para remoção e realização do leilão eletrônico dos bens a serem alienados de forma antecipada. § 1º A decisão será comunicada à autoridade policial responsável pela guarda do bem, quando não recolhido ao Depósito Judicial, e autorizará a disponibilização para remoção pelo Leiloeiro nomeado, em até 10 (dez) dias úteis, devendo este apresentar minuta de edital de leilão, no prazo de 5 (cinco) dias, após efetivada a remoção; § 2º Deverá constar do edital de leilão que os bens serão vendidos no atual estado de conservação, sem garantia, constituindo ônus do interessado verificar as condições antes das datas designadas para a alienação judicial eletrônica; § 3º Aprovada a minuta, o juiz providenciará a publicação do edital de leilão no Diário da Justiça.","v":["criminal","execucao"],"th":["prazos"]},{"n":"270","t":"Impossibilitado o leilão judicial por meio eletrônico, forma preferencial, será permitida a realização na modalidade presencial. 95 Parágrafo único. O leilão poderá ser simultâneo (eletrônico e presencial), cujo endereço será indicado no edital e a modalidade presencial se dará no último dia do período designado para o leilão eletrônico, observadas as disposições da Resolução CNJ nº 236, de 13 de julho de 2016.","v":["criminal","execucao"],"th":[]},{"n":"271","t":"Não alcançado o valor estipulado na avaliação, será realizado novo leilão, em até 10 (dez) dias contados da realização do primeiro, podendo os bens serem alienados por valor não inferior a 80% (oitenta por cento) do estipulado na avaliação judicial (CPP, art. 144-A, § 2º), nos casos de crimes comuns; não inferior a 50% (cinquenta por cento), nos casos de crimes de tráfico de drogas (Art.61, § 11, da Lei nº 11.343/06); e não inferior a 75% (setenta e cinco por cento), nos casos de crimes de \"lavagem\" ou ocultação de bens, direitos e valores (Art. 4º-A, § 3, da Lei nº 9.613/98). Parágrafo único. Deserto ou fracassado o leilão, após a repetição na forma do caput, os bens serão destinados à doação ou à destruição, conforme os procedimentos previstos nos arts. 13 e 14 da Resolução nº 11/2015 do Órgão Especial do TJCE.","v":["criminal","execucao"],"th":[]},{"n":"272","t":"Consumado exitosamente o leilão, com o depósito do lance vencedor e da comissão do Leiloeiro, será expedida carta de arrematação aos arrematantes para fins de registro da aquisição perante os órgãos competentes. Parágrafo único. Na alienação de veículos, embarcações ou aeronaves, o juiz ordenará à autoridade de trânsito ou ao equivalente órgão de registro a expedição de certificado de registro e licenciamento em favor do arrematante, em 30 (trinta) dias, ficando este livre do pagamento de multas, encargos e tributos anteriores, sem prejuízo de execução fiscal contra o antigo proprietário (art. 144-A, § 5º, CPP).","v":["criminal","execucao"],"th":["mandados","execucao"]},{"n":"273","t":"No caso de bens apreendidos em processos criminais não destinados a apurar crime de tóxicos, os valores líquidos apurados com a alienação antecipada, descontados para tanto os valores para o custo operacional do Leiloeiro, deverão ser revertidos ao Fundo Especial de Reaparelhamento e Modernização do Poder Judiciário do Estado do Ceará (FERMOJU), até o julgamento final do processo (Art. 15, caput, da Resolução nº 11/2015 do Órgão Especial do TJCE). § 1º Nos casos referidos no caput, após o trânsito em julgado da sentença que determinou o perdimento, os valores apurados em alienação judicial, e recolhidos na forma do artigo 272, serão revertidos ao Fundo Penitenciário Nacional – FUNPEN, CNPJ 00.394.494/0008-02, mediante Guia de Recolhimento Unificada – GRU Simples, no Banco do Brasil, Unidade Favorecida (UG) 200333, Gestão 00001, com o código 20230-4 (receita referente à Alienação de Bens Apreendidos), juntando-se comprovante nos autos; 96 § 2º Se acolhido pedido de restituição do bem após a alienação antecipada, ou na hipótese de absolvição do acusado em decisão transitada em julgado, o valor apurado na venda, com as devidas atualizações correspondentes, será destinado ao requerente.","v":["criminal","execucao"],"th":["audiencias"]},{"n":"274","t":"Os valores auferidos em decorrência de alienação antecipada ou de numerários apreendidos em processos criminais relacionados ao tráfico de drogas serão depositados na Caixa Econômica Federal, mediante recolhimento de Guia DJE (Documento para Depósitos Judiciais ou Extrajudiciais), sob o código de receita n.º 5680 e operação 635 (Art. 62-A, caput, da Lei nº 11.343/06). § 1º Os valores atualmente depositados em contas judiciais, decorrentes de alienação antecipada ou de apreensão em processos criminais relacionados ao tráfico de drogas deverão ser transferidos para a Caixa Econômica Federal observando-se a sistemática descrita no caput, onde ficarão à disposição do FUNAD; § 2º Na hipótese de absolvição do acusado em decisão judicial, o valor do depósito será devolvido a ele pela Caixa Econômica Federal no prazo de até 3 (três) dias úteis, acrescido de juros, na forma estabelecida pelo § 4º do art. 39 da Lei nº 9.250/1995 (Art. 62-A, § 2º, da Lei nº 11.343/06).","v":["criminal","execucao"],"th":["prazos"]},{"n":"275","t":"Cuidando-se de veículo classificado como sucata, na forma do inciso II do § 1º do art. 328 do Código de Trânsito Brasileiro, e de materiais inservíveis de bens automotores, a entrega do material arrematado ficará condicionada aos procedimentos necessários à descaracterização total do bem e à destinação exclusiva, ambientalmente adequada, à reciclagem siderúrgica, vedado qualquer aproveitamento de peças e partes (art. 328, § 17, CTB), o que deverá ser observado pelo Leiloeiro nomeado e pelo DETRAN. Parágrafo único. Incluem-se na hipótese do caput os veículos sinistrados irrecuperáveis, queimados, adulterados ou clonados, bem como aqueles sem possibilidade de regularização perante o órgão de trânsito, conforme atestado na vistoria.","v":["criminal","execucao"],"th":[]},{"n":"276","t":"Após a retirada de eventuais restrições e cumpridos todos os expedientes necessários para a efetivação da transferência do domínio do bem arrematado, o processo será arquivado, devendo a destinação definitiva dos valores arrecadados ser decidida no julgamento da respectiva ação penal.","v":["criminal","execucao"],"th":["audiencias","execucao"]},{"n":"277","t":"O inquérito policial e o procedimento ou processo criminal não poderão ser arquivados enquanto não for dada efetiva destinação ao bem apreendido, sob pena de responsabilidade funcional (Art. 6º, parágrafo único, da Resolução CNJ nº 63/2008 e art. 9º, parágrafo único, da Resolução nº 11/2015 do Órgão Especial do TJCE). 97","v":["criminal","execucao"],"th":["execucao"]}]},{"num":"IX","title":"DA DESTINAÇÃO DE ARMAS DE FOGO APREENDIDAS","articles":[{"n":"278","t":"As armas de fogo e munições apreendidas em autos submetidos ao Poder Judiciário do Estado do Ceará deverão, após a elaboração do laudo pericial e sua juntada ao processo, ser encaminhadas, pelo juiz competente, ao Comando do Exército, no prazo de 48 (quarenta e oito) horas, para destruição ou doação aos órgãos de segurança pública ou às Forças Armadas, quando não mais interessarem à persecução penal, nos termos previstos no art. 25, da Lei nº 10.826/2003. § 1º O Juiz, excepcionalmente e mediante decisão fundamentada, após a intimação das partes, para que, no prazo de 5 (cinco) dias, se manifestem sobre o resultado do laudo pericial e eventual notificação do proprietário de boa-fé sobre interesse na restituição, no mesmo prazo, poderá determinar a guarda da arma de fogo apreendida ou da munição, caso a medida seja imprescindível para o esclarecimento dos fatos apurados no processo judicial. § 2º Na hipótese da arma apreendida ou da munição ser de propriedade da Polícia Civil ou Militar, ou das Forças Armadas, ordenará a autoridade judiciária a restituída à Corporação, após a elaboração do respectivo laudo pericial e intimação das partes, ressalvada a hipótese do parágrafo anterior.","v":["criminal","execucao"],"th":["prazos","citacao","execucao"]},{"n":"279","t":"Ao receber os objetos apreendidos de que cuida o artigo antecedente e sendo o fato delituoso enquadrado nos tipos penais dos arts. 12 e 14 da Lei nº 10.826/2003, a PEFOCE expedirá ofício à autoridade judicial competente para o fato em apuração através do e-mail, Whatsapp Business ou Malote Digital da Unidade Judiciária, comunicando o recebimento do material e aguardando deliberação do Juízo competente, pelo prazo de 90 (noventa) dias. (Redação conferida pelo Prov. nº 12/2021/CGJCE, DJe de 15/06/2021) § 1º Não havendo manifestação do Ministério Público na denúncia ou representação quanto à necessidade de perícia no objeto apreendido, deverá o Juiz competente ouvir o agente ministerial, no prazo de 5 (cinco) dias, especificamente sobre o tema; § 2º Após a manifestação do Ministério Público o Juiz ouvirá a defesa, no prazo de 5 (cinco) dias, quanto à necessidade da realização do exame pericial; 98 § 3º Adotadas as providências acima, o magistrado decidirá sobre a realização de perícia na arma de fogo, acessório ou munição, determinando sua realização, com justificativa para a excepcionalidade, ou a negando, caso a considere irrelevante, impertinente ou protelatória, na forma do art. 400, §1º, do CPP; § 4º Exarada a decisão referida no parágrafo anterior será expedido ofício à PEFOCE, para que a arma, acessório ou munição seja encaminhada ao Comando do Exército Brasileiro, para os fins do art. 25, da Lei nº 10.826/2003, ou para que seja realizada a perícia excepcionalmente tida por necessária; § 5º As armas de uso permitido ou restrito, acessórios ou munições, devidamente registradas e autorizadas, poderão ser restituídas aos legítimos proprietários, mediante procedimento de restituição de coisa apreendida, com apresentação dos documentos de registro e de autorização de porte; § 6º Ultrapassado o prazo de 90 (noventa) dias sem manifestação específica quanto à destinação dos objetos indicados no caput deverá o Juiz competente apresentar justificativa perante a Corregedoria-Geral da Justiça no prazo de 5 (cinco) dias.","v":["criminal","execucao"],"th":["prazos","execucao"]},{"n":"280","t":"Caso a arma de fogo ou acessório apreendidos não sejam remetidos, de ofício, pela autoridade policial à PEFOCE, deverá o Juiz competente adotar as medidas necessárias de destinação dos respectivos equipamentos.","v":["criminal","execucao"],"th":[]},{"n":"281","t":"As comunicações oriundas do juízo competente requisitando a realização das perícias de que trata este provimento, ou expressamente as dispensando, deverão ser encaminhadas através do seguinte endereço de e-mail: armas@pefoce.ce.gov.br.","v":["criminal","execucao"],"th":[]},{"n":"282","t":"Após a conclusão da perícia, caso seja necessária a permanência da arma apreendida até o final do processo, em razão de justificativa apresentada pela parte, determinará o magistrado o encaminhamento do armamento para a sede do Batalhão da Polícia Militar da Região, nos termos Termo de Cooperação Técnica entre o Tribunal de Justiça do Ceará e a Secretaria da Segurança Pública e Defesa Social do Estado do Ceará, devendo a arma/acessório ficar acautelado e aguardar determinação judicial, salvo a Comarca de Fortaleza, por possuir procedimento próprio.","v":["criminal","execucao"],"th":["secretaria"]},{"n":"283","t":"É vedado, durante o processo ou inquérito, qualquer tipo de carga, cessão ou depósito, em mãos alheias, de armas de fogo e munições apreendidas.","v":["criminal","execucao"],"th":[]},{"n":"284","t":"As armas de fogo e munições que atualmente se encontrem desvinculadas de processos judiciais serão imediatamente encaminhadas ao Comando do Exército, para destruição ou doação. 99 Parágrafo único. Para fins de cumprimento do caput, cópia do presente provimento deverá ser encaminhada às instituições responsáveis pela guarda de armas de fogo e acessórios.","v":["criminal","execucao"],"th":["mandados"]},{"n":"285","t":"O inquérito policial e o procedimento ou processo criminal/infracional não poderão ser arquivados enquanto não for dada efetiva destinação às armas e acessórios apreendidos, sob pena de responsabilidade funcional do magistrado.","v":["criminal","execucao"],"th":["execucao"]}]},{"num":"X","title":"DA ALIMENTAÇÃO DE DADOS NOS PROCESSOS CRIMINAIS","articles":[{"n":"286","t":"Juízes e servidores do primeiro grau do Poder Judiciário do Estado do Ceará devem alimentar e manter atualizados os sistemas judiciais com os dados de qualificação e histórico de partes nos processos de competência criminal, com exatidão, em conjunto com a Evolução de Classe processual, quando necessária, visando à eficiência na busca de consultas e expedição de certidão, bem como para extração de dados estatísticos a serem utilizados como parâmetro na elaboração do planejamento e realização de ações de melhoria das atividades jurisdicionais.","v":["criminal"],"th":["mandados"]},{"n":"287","t":"A constante atualização referida no artigo precedente deve abranger, principalmente, as informações a seguir elencadas: I - dados processuais: a) classe processual; b) assunto(s); c) ocorrência do fato; d) dados da delegacia; e) tipo e número do procedimento policial ou documento que originou o processo judicial. II - dados de qualificação da parte: a) nome completo sem abreviaturas ou caracteres especiais; b) alcunha(s)/outro(s) nome(s); c) filiação; 100 d) data do nascimento/data do óbito; e) nacionalidade; f) naturalidade; g) gênero; h) cor/etnia; i) sinais particulares; h) profissão; i) instrução/escolaridade; j) estado civil; k) documentos oficiais (RG, CPF, título de eleitor e outros); l) tipo de participação (autuado, indiciado, acusado, etc.); m) tipo da parte (passiva). III - eventos: a) prisão; b) soltura; c) concessão de benefícios; d) transação penal; e) sentença; f) aplicação de medidas cautelares alternativas à prisão; g) reabilitação; h) fuga; i) situação da parte; j) alteração de regime de cumprimento da pena; k) transferência do preso; 101 l) livramento condicional; m) extinção da punibilidade; n) medidas cautelares alternativas à prisão; o) outros eventos. §1º As seguintes orientações devem ser consideradas para as informações relacionadas no inciso I deste artigo: I - a unidade judiciária deverá realizar a evolução de classe processual de processo iniciado como Auto de Prisão em Flagrante para Inquérito e, posteriormente, para a classe processual penal correspondente, quando couber; II - o juízo da execução providenciará a evolução da classe de execução provisória para execução","v":["criminal"],"th":["mandados","presos","execucao"]}]},{"num":"XI","title":"DO RECAMBIAMENTO E TRANSFERÊNCIA DE PRESOS","articles":[{"n":"288","t":"São obrigatórios os procedimentos de solicitação de escolta policial, transferência e recambiamento de presos nas comarcas e unidades judiciais com jurisdição em matéria criminal, no âmbito do Estado do Ceará. (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). 103 Parágrafo único. Para o presente normativo: I - ESCOLTA se aplica à movimentação de réu preso para acompanhar ato judicial e imediato retorno ao local onde se encontrava detido, ainda que o transporte seja interestadual; (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). II - RECAMBIAMENTO se aplica à movimentação de preso, em caráter definitivo, entre o Estado do Ceará e outro ente da Federação ou vice-versa. O recambiamento pressupõe sempre a existência de vaga no Sistema Penitenciário de destino do réu. (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). III - TRANSFERÊNCIA se aplica à movimentação de pessoa presa, em caráter definitivo, do estabelecimento prisional em que se encontra para outro estabelecimento prisional, situado na mesma unidade da federação. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["citacao","presos"]},{"n":"289","t":"Antes de pedir escolta, o magistrado deve, dentro das hipóteses legais, utilizar a ferramenta de videoconferência para realização de audiências criminais, em sintonia com os princípios da celeridade processual e eficiência. § 1º O sítio eletrônico do Tribunal de Justiça do Estado do Ceará disponibiliza informações e procedimentos necessários para utilização da videoconferência; § 2º Quando o(s) réu(s)/testemunha(s) estiverem presos em outro Estado, o magistrado deve priorizar a audiência por videoconferência, iniciando contatos por malote digital ou por telefone com o juízo competente e com o Diretor do Presídio, para saber sobre a viabilidade técnicooperacional, tudo com antecedência de, pelo menos, 30 (trinta) dias da data da audiência; § 3º Caso exista termo de cooperação técnica ou convênio com o TJCE em relação à videoconferência, este instrumento deverá ser obedecido e, apenas na sua ausência, será aplicado o disposto no parágrafo anterior.","v":["criminal","execucao"],"th":["audiencias","presos","execucao"]},{"n":"290","t":"Inviabilizada a videoconferência e, havendo necessidade de deslocamento de presos a fim de oitiva em audiência designada em Comarca diversa daquela em que se encontra o réu, o 104 magistrado solicitará a efetiva escolta policial do detento, no prazo mínimo de 10 (dez) dias úteis antes da audiência, oficiando a Secretaria de Administração Penitenciária (SAP) por meio do seguinte endereço eletrônico: escoltas@sap.ce.gov.br. § 1º As comunicações, por endereço eletrônico, serão feitas pelo e-mail funcional de cada Unidade Judicial; § 2º Excepcionalmente, em casos de urgência devidamente justificada, o prazo referido no caput poderá ser reduzido para 5 (cinco) dias úteis; § 3º A SAP responderá ao e-mail do magistrado em até 48 (quarenta e oito) horas após o envio. Caso a SAP não responda ao e-mail no prazo ou a audiência não aconteça pela ausência ou atraso da escolta, deve o juiz consignar o fato no termo de audiência, e remeter cópia deste documento à Corregedoria-Geral da Justiça para os devidos encaminhamentos.","v":["criminal","execucao"],"th":["audiencias","prazos","secretaria","presos"]},{"n":"291","t":"Escoltas de presos em outros Estados da Federação para participar de audiências serão solicitadas à Delegacia de Capturas e Polinter (DECAP), por meio de mensagem enviada ao endereço eletrônico: decap.ce@gmail.com, com antecedência mínima de 15 (quinze) dias da data audiência. Parágrafo único. Na escolta referida no caput, a DECAP poderá requerer apoio à SAP quando o deslocamento acontecer entre Estados vizinhos e o transporte se fizer por via terrestre.","v":["criminal","execucao"],"th":["audiencias","presos"]},{"n":"292","t":"Informado da prisão de réu em outro Estado da Federação, por força de mandado de prisão expedido pela Justiça do Ceará, caberá ao magistrado seguir o seguinte procedimento: (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). I - verificar junto ao Juiz Corregedor de Presídio, caso não seja ele próprio, mediante ofício, com prazo de 5 (cinco) dias, a existência de vaga no Sistema Penitenciário local; (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). 105 II - o Juízo processante também observará a existência de algum motivo de natureza processual que impeça o recambiamento imediato junto ao Juízo onde se encontra o preso; (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). III - manifestação do Ministério Público e da defesa técnica, quando não tiverem apresentado o requerimento; (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). IV - oitiva da pessoa presa, sempre que não for a requerente, zelando-se pela livre manifestação de sua vontade; (Redação conferida pelo Prov. nº 19/2025/CGJCE, DJeA de 19/11/2025). V – finalmente, decidir pelo recambiamento, dando ciência ao representante do Ministério Público em exercício na unidade judiciária e da defesa técnica. (Incluído pelo Prov. 19/2025/CGJCE, DJeA de 19/11/2025).","v":["criminal","execucao"],"th":["prazos","mandados","presos"]},{"n":"293","t":"Em seguida, o Juízo processante comunicará a decisão de recambiamento: (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). I - ao requerente, à pessoa presa e à defesa técnica, para ciência da decisão; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). II - à família da pessoa presa, sempre que presentes informações que possibilitem a medida; e (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). III - à secretaria de estado responsável pela administração penitenciária, para efetivação da transferência da pessoa presa, com o translado de seu prontuário médico e bens pessoais. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). § 1º As comunicações eletrônicas serão estabelecidas utilizando e-mail funcional de cada unidade judicial; § 2º A comunicação apontada neste artigo será instruída com cópias das decisões de que trata o caput e o inciso III do artigo 292 desta Consolidação. (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["secretaria"]},{"n":"294","t":"Caso a comunicação da prisão de réu fora do Estado, por força de mandado de prisão expedido pela Justiça do Ceará, venha por intermédio de Corregedoria-Geral da Justiça, deverá ser adotado procedimento semelhante ao determinado nesta Consolidação.","v":["criminal","execucao"],"th":["mandados","presos"]},{"n":"295","t":"Terá prioridade o pedido de recambiamento oriundo de outro Estado da Federação quando este assumir as despesas de deslocamento do preso, com mandado de prisão expedido pela Justiça do Ceará em aberto, observando-se as determinações constantes desta Consolidação. 106","v":["criminal","execucao"],"th":["mandados","presos"]},{"n":"296","t":"O magistrado somente recorrerá à Corregedoria-Geral da Justiça do Estado do Ceará se não houver confirmação de recebimento da Secretaria de Administração Penitenciária (SAP), no prazo de 48 (quarenta e oito) horas após o envio da mensagem eletrônica; ou se transcorrer o prazo de 60 (sessenta) dias sem manifestação. (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["prazos","secretaria"]},{"n":"297","t":"Havendo captura de presos dentro do Estado do Ceará, em cumprimento de mandados de prisão expedidos por magistrados de outro ente da Federação, a autoridade policial comunicará ao juiz do local da prisão e ao magistrado do juízo que expediu o respectivo mandado, no prazo de 48 (quarenta e oito) horas, a fim de que adotem as devidas providências. Parágrafo único. Inexistindo pedido de recambiamento pelo magistrado processante, em até 30 (trinta) dias após a ciência, deverá o juiz criminal do local da prisão, instaurar procedimento junto a Corregedoria-Geral da Justiça do Estado que determinou a detenção, informando a necessidade de recambiamento.","v":["criminal","execucao"],"th":["prazos","mandados","presos"]},{"n":"298","t":"Deferido o recambiamento, o juízo comunicará à Secretaria de Administração Penitenciária (SAP), por meio de mensagem enviada ao correio eletrônico: ceap@sap.ce.gov.br (Coordenadoria Especial da Administração Penitenciária - CEAP/SAP), a decisão de recambiamento para cumprimento no prazo máximo de 30 (trinta) dias contados do cumprimento do mandado de prisão, nos termos do art. 289, § 3º do CPP, salvo impossibilidade fundamentada. (Redação conferida pelo Prov. nº 06/2022/CGJCE, DJe de 19/05/2021).","v":["criminal","execucao"],"th":["prazos","mandados","secretaria","presos"]},{"n":"299","t":"O magistrado somente recorrerá à Corregedoria-Geral da Justiça do Estado do Ceará se não houver confirmação de recebimento da Secretaria de Administração Penitenciária (SAP) no prazo de 48 (quarenta e oito) horas após o envio da mensagem eletrônica; ou se transcorrer o prazo de 60 (sessenta) dias sem manifestação. (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["prazos","secretaria"]},{"n":"300","t":"A Secretaria de Administração Penitenciária (SAP) do Estado do Ceará realizará a escolta para deslocamento de detentos dentro do Estado e o recambiamento de presos, sempre atentando 107 para o cumprimento da legislação em vigor, em especial a aeroportuária e as regras de transporte referidas no art. 16 da Resolução 404/2021 do Conselho Nacional de Justiça. (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["mandados","secretaria","presos"]},{"n":"301","t":"A Secretaria de Administração Penitenciária (SAP) deverá informar ao Juízo processante acerca da realização do recambiamento solicitado. (Redação conferida pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). Seção IV Da Transferência (Incluída pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021)","v":["criminal","execucao"],"th":["citacao","secretaria"]},{"n":"301-A","t":"Compete ao Poder Judiciário decidir sobre os requerimentos de transferência apresentados em juízo e realizar o controle de legalidade das transferências determinadas no âmbito da administração penitenciária. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":[]},{"n":"301-B","t":"O requerimento de transferência pode ser apresentado: (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). I - pela pessoa presa, por si ou por advogado constituído, advogada constituída ou membro da Defensoria Pública; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). II - pelos familiares da pessoa presa; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). III - por membro do Ministério Público; e (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). IV - por representante de conselho da comunidade, conselho penitenciário ou mecanismo de prevenção e combate à tortura. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). § 1º O procedimento de transferência de pessoa presa pode ser instaurado de ofício, sempre que presente algum dos fundamentos previstos no art. 301-C da presente Consolidação. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). 108 § 2º O requerimento de transferência de pessoa presa pode ser apresentado independentemente do tempo de pena já cumprido no estabelecimento prisional em que se encontra custodiada. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["execucao"]},{"n":"301-C","t":"A transferência de pessoa presa poderá ser efetuada com fundamento em: (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). I - risco à vida ou à integridade da pessoa presa; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). II - necessidade de tratamento médico; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). III - risco à segurança; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). IV - necessidade de instrução de processo criminal; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). V - permanência da pessoa presa em local próximo ao seu meio social e familiar; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). VI - exercício de atividade laborativa ou educacional; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). VII - regulação de vagas em função de superlotação ou condições inadequadas de privação de liberdade; e (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). VIII - outra situação excepcional, devidamente demonstrada. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). Parágrafo único. A transferência de pessoas presas não tem natureza de sanção administrativa por falta disciplinar, nos termos do art. 53 da Lei de Execução Penal. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["execucao"]},{"n":"301-D","t":"Para os fins do art. 301-C, VIII, a autoridade judicial considerará a ocupação dos estabelecimentos de origem e destino, de modo a evitar sobrepopulação nos espaços de privação de liberdade, riscos à segurança, aumento da insalubridade e a propagação de doenças às pessoas 109 privadas de liberdade e aos agentes que laboram na localidade. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). Parágrafo único. No caso do caput, será dada prioridade a outras medidas de redução da população carcerária, em especial àquelas que decorrem da Súmula Vinculante nº 56 do Supremo Tribunal Federal, sem prejuízo de demais iniciativas. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":[]},{"n":"301-E","t":"O requerimento de transferência será apresentado com as informações essenciais à apreciação do pedido e a respectiva motivação e será autuado como procedimento, com tramitação em sistema eletrônico. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). Parágrafo único. O direito de petição da pessoa presa será assegurado de maneira efetiva, observados os direitos de acesso à justiça e à assistência judiciária gratuita, bem como à instrumentalidade das formas. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":[]},{"n":"301-F","t":"A tramitação do procedimento de transferência de pessoa presa contemplará: (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). I - manifestação do Ministério Público e da defesa técnica, quando não tiverem apresentado o requerimento; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). II - oitiva da pessoa presa, sempre que não for a requerente, zelando-se pela livre manifestação de sua vontade; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). III - consulta a órgão da administração penitenciária; e (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). IV - direito de informação da pessoa presa, do requerente e dos demais órgãos da execução penal, sobre o andamento do requerimento. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). Parágrafo único. A publicidade do procedimento de transferência poderá ser restringida, em hipóteses excepcionais, a fim de resguardar a segurança da pessoa presa. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). 110","v":["criminal","execucao"],"th":["execucao"]},{"n":"301-G","t":"A decisão que apreciar o requerimento de transferência de pessoa presa deverá ser fundamentada, com análise das questões de fato e de direito. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). § 1º A autoridade judiciária determinará a intimação do requerente, da pessoa presa e da defesa técnica, para ciência da decisão. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). § 2º Na hipótese de deferimento do requerimento de transferência, a autoridade judiciária comunicará ainda: (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). I - à família da pessoa presa, sempre que presentes informações que possibilitem a medida; e (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). II - à secretaria de estado responsável pela administração penitenciária, para efetivação da transferência da pessoa presa, com o traslado de seu prontuário médico e bens pessoais. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["citacao","secretaria"]},{"n":"301-H","t":"Em situações excepcionais, é possível o deferimento da transferência de pessoa presa de forma cautelar, hipótese em que as providências de que trata o art. 301-F serão realizadas em até 48 (quarenta e oito) horas. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":[]},{"n":"301-I","t":"O controle judicial de legalidade das transferências determinadas no âmbito da administração penitenciária será realizado à luz das diretrizes e princípios elencados no art. 3º da Resolução. 404/2021 do Conselho Nacional de Justiça. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). § 1º O Núcleo de Cooperação Judiciária do TJCE, em cooperação com a Secretaria da Administração Penitenciária e Ressocialização (SAP), atuará pela harmonização de procedimentos e rotinas administrativas, de modo a contemplar: (Redação conferida pelo Prov. nº 19/2025/CGJCE, DJeA de 19/11/2025). I - o procedimento administrativo de acordo com as diretrizes e princípios elencados no art. 3º da Resolução. 404/2021 do Conselho Nacional de Justiça. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). 111 II - hipóteses excepcionais em que a publicidade do procedimento de transferência poderá ser restringida, a fim de resguardar a segurança da pessoa presa; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). III - medidas para coibir o desvio de finalidade e o uso abusivo de transferências, incluída a previsão de responsabilização administrativa. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). IV - a comunicação obrigatória ao juízo competente sobre as transferências realizadas, com a disponibilização de acesso ou o envio de cópia dos procedimentos administrativos correspondentes, em até 48 (quarenta e oito) horas; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). V - a realização do transporte de forma a respeitar a dignidade e integridade física e moral da pessoa presa, observados o art. 16 da Resolução 404/2021 do Conselho Nacional de Justiça e a legislação aplicável; (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). VI - o cumprimento do prazo previsto no art. 289, § 3º, do Código de Processo Penal; e (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). VII - a comunicação aos familiares sobre o local de destino da transferência. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). § 2º Sem prejuízo do disposto no parágrafo anterior, o controle judicial poderá ser provocado pelos interessados de que trata o art. 301-B, I, II, III e VI, da presente Consolidação, observado o disposto no art. 301-E, parágrafo único. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021).","v":["criminal","execucao"],"th":["prazos","mandados","secretaria","execucao"]},{"n":"301-J","t":"As escoltas policiais, transferências e recambiamentos serão realizados de forma a respeitar a dignidade e integridade física e moral das pessoas presas, observando, especialmente o regramento constante do art. 16 da Resolução 404/2021 do Conselho Nacional de Justiça. (Incluído pelo Prov. nº 23/2021/CGJCE, DJe de 17/12/2021). 112","v":["criminal","execucao"],"th":[]}]},{"num":"XII","title":"DA REQUISIÇÃO DE POLICIAIS E BOMBEIROS","articles":[{"n":"302","t":"As requisições de policiais militares, bombeiros militares e policiais civis para comparecimento a ato judicial presencial, independentemente de sua natureza, realizadas por juízes de primeiro grau de jurisdição do Estado Ceará, devem ser feitas por meio eletrônico quando se tratar de policiais militares e bombeiros militares, e intimação eletrônica por meio do sistema processual, quando se tratar de policiais civis. (Redação conferida pelo Prov. nº 05/2022/CGJCE, DJe de 29/04/2022) § 1º Os policiais militares deverão ser requisitados à PMCE – Polícia Militar do Ceará, por e-mail, no seguinte endereço eletrônico: subcmtgeral@policiamilitar.ce.gov.br, mediante preenchimento e envio do formulário constante do Anexo X deste normativo; (Redação conferida pelo Prov. nº 12/2023/CGJCE, DJe de 02/06/2023) § 2º Os bombeiros militares deverão ser requisitados ao CBM – Corpo de Bombeiros Militar, por e-mail, no seguinte endereço eletrônico: cmtgeral@cb.ce.gov.br, mediante preenchimento e envio do formulário constante do Anexo XI deste normativo; § 3º Os policiais civis deverão ser requisitados ao Departamento de Recursos Humanos da Polícia Civil do Ceará (DRH/PCCE) por meio da funcionalidade de intimação eletrônica do sistema processual ou, excepcionalmente, através do e-mail audiencia@policiacivil.ce.gov.br, resguardados, em ambos os casos, os requisitos do formulário constante no Anexo XII deste normativo; § 4º As requisições deverão ser feitas com antecedência igual ou superior a 15 (quinze) dias, entre a data da publicação no Portal Eletrônico ou de envio do e-mail e a data aprazada para a realização do ato judicial. A requisição formal e o prazo mínimo estabelecido neste parágrafo poderão ser dispensados na hipótese da unidade judiciária dispor de outro mecanismo que viabilize contato direto, mais ágil e eficaz com as instituições apontadas nos parágrafos anteriores; 113 § 5º No âmbito do Juízo da Infância e Juventude, as requisições por meio eletrônico destinar-se-ão unicamente aos policiais civis ou militares que necessitem ser ouvidos em procedimento regulado pela Lei Federal nº. 8.069, de 13 de julho de 1990 (Estatuto da Criança e do Adolescente); § 6º As requisições de adolescentes infratores serão feitas pela via convencional diretamente aos estabelecimentos oficiais de internamento.","v":["criminal","execucao"],"th":["prazos","citacao"]},{"n":"303","t":"Não apresentados os policiais militares, bombeiros militares e policiais civis sem a pronta justificativa, o Juiz deverá oficiar à Polícia Militar, ao Corpo de Bombeiros Militar e à Polícia Civil, a fim de que justifiquem o não atendimento da requisição. Parágrafo único. Não apresentada a justificativa, ou não sendo esta acolhida, o Juiz requisitante encaminhará ao Ministério Público, por ofício, as atas comprobatórias da não realização dos atos judiciais em face da não apresentação dos presos, bem como de policiais militares, bombeiros militares e policiais civis, a fim de que adote as medidas pertinentes à espécie.","v":["criminal","execucao"],"th":["presos"]},{"n":"304","t":"As requisições e as comunicações de que trata este capítulo deverão originar-se exclusivamente do sistema informatizado do Tribunal de Justiça do Estado do Ceará e dos e-mails institucionais das respectivas unidades judiciárias, sob a responsabilidade de servidores devidamente habilitados pelo Juiz. § 1º Todas as requisições e comunicações deverão ser enviadas com \"confirmação de leitura\" do email ou da intimação eletrônica por meio do sistema processual, para fins de comprovação do seu recebimento, caso haja necessidade; § 2º As requisições por meio eletrônico ou via sistema processual destinadas a endereço eletrônico diverso dos mencionados neste capítulo não terão efeito obrigacional para a Polícia Militar, Corpo de Bombeiros Militar e Polícia Civil; § 3º As requisições e comunicações por meio eletrônico ou via Portal e-SAJ de que trata este capítulo deverão ser assinadas, digitalmente, pelo magistrado, servidor por ele indicado ou ainda pelo servidor responsável nas Secretarias Judiciárias, desde o momento em que esta ferramenta venha a ser disponibilizada pelo sistema informatizado do TJCE.","v":["criminal","execucao"],"th":["citacao","secretaria"]},{"n":"305","t":"Os Juízes, a fim de evitar congestionamentos de requisições em determinados dias da semana em todo o Estado, distribuirão a pauta de audiências igualmente para todos os dias úteis da semana.","v":["criminal","execucao"],"th":["audiencias"]},{"n":"306","t":"Os Juízes, como gestores de suas unidades jurisdicionais, devem envidar esforços no sentido de entrar em entendimento com a Polícia Militar, Corpo de Bombeiros Militar e Polícia 114 Civil, pessoalmente ou por via telefônica, a fim de planejar, de comum acordo, as datas mais desimpedidas e convenientes à apresentação de policiais militares, bombeiros militares e policiais civis, a fim de evitar a frustração da prática de atos processuais e o desperdício de tempo, recursos humanos e materiais.","v":["criminal","execucao"],"th":[]},{"n":"307","t":"As requisições de policiais militares, bombeiros militares e policiais civis para o comparecimento às audiências realizadas por meio de videoconferência deverão ocorrer mediante a utilização do Sistema de Agendamento de Videoconferência (SIMAV) ou outro que venha a substituí-lo. (Redação conferida pelo Prov. nº 05/2022/CGJCE, DJe de 29/04/2022) Parágrafo único. As audiências virtuais realizar-se-ão exclusivamente por meio da plataforma Microsoft Teams, ferramenta padrão adotada pelo Poder Judiciário Cearense. (Incluído pelo Prov. nº 05/2022/CGJCE, DJe de 29/04/2022).","v":["criminal","execucao"],"th":["audiencias"]}]},{"num":"XIII","title":"DA SUSPENSÃO CONDICIONAL DO PROCESSO","articles":[{"n":"308","t":"Os acusados ou processados obrigados a informar ou justificar suas atividades (art. 78, § 2º, c, do Código Penal; art. 89 da Lei nº 9099/1995 e; art. 132, §1º, b, da Lei nº 7.210/1984), poderão fazê-lo perante o juízo plantonista, nos finais de semana e feriados. § 1º O comparecimento será registrado em livro próprio do plantão e dele será fornecido recibo ao interessado, sem prejuízo de anotação nos autos do processo específico ou em outro sistema de controle utilizado pelo juízo, facultada a designação de voluntários, preferencialmente dentre aqueles dotados de noções de psicologia ou serviço social, para a coleta das informações e justificativas; § 2º O juiz plantonista, no primeiro dia útil após o plantão, comunicará ao juízo processante os comparecimentos registrados.","v":["criminal"],"th":["execucao"]}]},{"num":"XIV","title":"DOS PRESOS","articles":[{"n":"309","t":"A autoridade judiciária deverá comunicar a prisão de qualquer pessoa estrangeira à missão diplomática de seu Estado de origem ou, na sua falta, ao Ministério das Relações Exteriores, e ao Ministério da Justiça, no prazo máximo de 5 (cinco) dias. § 1º A comunicação de que trata o caput deste artigo será acompanhada dos seguintes documentos: I - na hipótese de prisão preventiva definitiva, cópia da sentença penal condenatória ou do acórdão transitado em julgado; II - na hipótese de prisão cautelar, cópia da decisão que manteve a prisão em flagrante ou decretou a prisão provisória. § 2º Caberá ao juiz da execução penal informar à missão diplomática do Estado de origem do preso estrangeiro, ou, na sua falta, ao Ministério das Relações Exteriores, e ao Ministério da Justiça, no prazo máximo de 5 (cinco) dias: I - a progressão ou regressão de regime; II - a concessão de livramento condicional; III - a extinção da punibilidade. § 3º A informação de que trata o caput deste artigo seguirá acompanhada da respectiva decisão.","v":["criminal","execucao"],"th":["prazos","presos","execucao"]},{"n":"310","t":"Sem prejuízo da competência prevista no art. 84 da Lei de Organização Judiciária do Estado do Ceará, devem os Juízes de competência criminal: I - proceder ao levantamento do número de presos provisórios à disposição do Juízo, para tomar conhecimento da situação processual de cada um deles; 116 II - fiscalizar, mensalmente, a regularidade processual dos presos provisórios à disposição do Juízo, independentemente do local da custódia; III - realizar a alimentação correta e imediata de todas as informações necessárias nos feitos criminais nos sistemas de automação pertinentes. § 1º No exercício da fiscalização de que trata esta seção, deverá o magistrado, de ofício, adotar as providências cabíveis, de modo a sanar irregularidades eventualmente verificadas na custódia dos presos provisórios sob sua jurisdição; § 2º Competirá aos Juízes de Direito, fiscalizar em sede de correição permanente o cumprimento das determinações contidas nesta Consolidação, bem como averiguar eventual atraso injustificado na tramitação de processo envolvendo réu preso cautelarmente.","v":["criminal","execucao"],"th":["mandados","presos"]},{"n":"311","t":"É dever dos magistrados que exercem jurisdição criminal e cível no Estado do Ceará fazer constar dos mandados de prisão por eles expedidos um prazo de validade, findo o qual, com ou sem movimentação, os autos do processo deverão obrigatoriamente retornar à conclusão para que verifique se persiste hígida a determinação de constrição da liberdade. § 1º O prazo de validade do mandado de prisão criminal não poderá superar o termo final do prazo prescricional do delito objeto da persecução penal; § 2º O prazo máximo de validade do mandado de prisão civil será de 2 (dois) anos; § 3º Alcançado o termo final do prazo de validade, o mandado de prisão será excluído do sistema e deverá ser expedido um novo mandado se, após examinados os autos, o magistrado concluir pela subsistência da ordem de prisão ainda não cumprida; § 4º Se a prisão civil for deprecada por juiz de outra unidade da Federação, este deverá ser cientificado quanto ao prazo de validade dos mandados de prisão no Estado do Ceará e da consequente necessidade de renovação bienal. 117","v":["criminal","execucao"],"th":["prazos","mandados","presos","execucao"]},{"n":"311-A","t":"O Banco Nacional de Medidas Penais e Prisões (BNMP) é o sistema de uso obrigatório por Juízos e Secretarias para o cadastro de pessoas, a expedição de documentos e o registro de informações relacionados à imposição de medidas cautelares, medidas protetivas, alternativas penais, condenações e restrições de liberdade de locomoção, nos termos e para os fins da Resolução do CNJ que trata da matéria. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º A obrigatoriedade do uso do BNMP refere-se a todas as modalidades de ordem judicial e correspondentes documentos que o sistema funcionalmente ofereça, estendendo-se a outras medidas tão logo disponibilizadas nas novas versões ou atualizações da plataforma eletrônica. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 2º A utilização do BNMP dar-se-á por meio de acesso via web, pelo serviço da Plataforma Digital do Poder Judiciário (PDPJ-Br), ou, com autorização expressa da Corregedoria Geral da Justiça, via integração entre os sistemas eletrônicos, quando a interoperabilidade estiver funcionando de maneira satisfatória. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["mandados","secretaria","execucao"]},{"n":"311-B","t":"Qualquer pessoa a quem se impute alguma das medidas previstas no BNMP deverá ser cadastrada, ainda que seja beneficiada com a liberdade plena em auto de prisão em flagrante. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º O cadastro, sendo único por pessoa, exige prévia consulta ao sistema, evitando duplicidades, e deverá ser alimentado com a inscrição no Cadastro Nacional da Pessoa Física (CPF) e com todos os elementos de identificação existentes nos autos. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 2º Constatando-se omissões ou informações desatualizadas no cadastro, deverão ser realizadas as devidas correções com os dados disponíveis. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 3º A ausência de CPF pela pessoa, a duplicidade desse identificador, a existência de mais de um cadastro e a falta de elementos qualificadores mínimos seguirão o procedimento traçado na Resolução CNJ de regência. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). 118","v":["criminal","execucao"],"th":["presos"]},{"n":"311-C","t":"A expedição de peças fora do BNMP somente será admitida em situação excepcional e momentânea de total indisponibilidade do sistema, única hipótese em que estará autorizada a utilização de documentos sob contingência, disponibilizados nas plataformas de tramitação processual. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º Na eventualidade de o sistema apresentar falha técnica que apenas impossibilite a inserção de algum dado pontual, ainda assim deve ser concluída a elaboração da peça com as informações que permitam individualizar a pessoa e a medida aplicada, sempre preferindo o uso do BNMP em detrimento de outras ferramentas. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 2º Os documentos sob contingência deverão possuir padrão único, destacar essa condição excepcional e esclarecer que o Juízo emissor regularizará a expedição no BNMP assim que cessado o impedimento, além de transitar em fluxo próprio no sistema processual, para o fim de acompanhamento e regularização pela unidade expedidora e de fiscalização pela Corregedoria Geral da Justiça. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 3º Em nenhuma hipótese poderá ser atribuído ao ato judicial o caráter de mandado, de contramandado ou de alvará de soltura para dispensar ou substituir as peças de expedição obrigatória no BNMP ou sob contingência. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["mandados","execucao"]},{"n":"311-D","t":"A redistribuição processual, seja por declínio de competência, desaforamento ou pela rotina dos plantões judiciários e das unidades especializadas em audiências de custódia e em inquéritos policiais, importará na obrigação de o Serviço de Distribuição realizar a mudança de competência junto ao BNMP dos mandados ativos (cumpridos ou pendentes de cumprimento) que imponham alguma restrição à liberdade da pessoa. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º A mesma incumbência caberá ao Serviço de Distribuição SEEU em relação aos referidos mandados e às guias de recolhimento, de execução ou de internação, estendendo-se às unidades com competência em execução penal na redistribuição direta admitida pelo sistema de tramitação processual. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 2º A mudança de competência também será realizada, nos termos do caput, quando da distribuição de guias de recolhimento, de execução ou de internação expedidas pelos Juízos criminais de conhecimento. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["audiencias","mandados","secretaria","presos","execucao"]},{"n":"311-E","t":"Os mandados de prisão ou de internação pendentes de cumprimento não deverão ser encaminhados para Delegacias de Polícia, inclusive especializadas em capturas, bastando, para o 119 cumprimento, o registro no BNMP e a intimação eletrônica no sistema processual, evitando-se a formação de base de dados diversa ou de cadastro de mandados paralelo, conforme inteligência do art. 289-A do Código de Processo Penal. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). Parágrafo único. Excepcionam-se dessa regra os mandados expedidos em caráter restrito ou sigiloso no BNMP e aqueles confeccionados sob contingência. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["citacao","mandados","presos","execucao"]},{"n":"311-F","t":"Existindo mandado de prisão preventiva cumprido, não deverá ser expedido, em razão da condenação na mesma persecução penal, novo mandado de prisão, cabendo tão somente a expedição da respectiva guia. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º Se o mandado de prisão preventiva estiver pendente de cumprimento, a manutenção da ordem prisional em sentença condenatória exige a revogação daquele por contramandado e a expedição de novo mandado, agora decorrente da condenação e tendo como prazo de validade a prescrição em concreto. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 2º Caso seja constatada a existência de mais de um mandado de prisão cumprido contra uma mesma pessoa, em razão do mesmo processo criminal ou de execução penal, o alvará de soltura, quando expedido, deve alcançar todos eles, de modo a permitir a mudança de status no sistema. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["prazos","mandados","presos","execucao"]},{"n":"311-G","t":"O cumprimento das ordens judiciais deve ser registrado no BNMP, mediante certidão própria do sistema, tão logo seja informado pelas autoridades competentes. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º O cumprimento dos alvarás de soltura e dos mandados de desinternação deve ocorrer em 24 (vinte e quatro) horas e fica sempre sujeito a controle judicial, cabendo ao Juízo emissor a adoção das medidas necessárias junto à unidade de custódia para formalização da comunicação e, sobretudo, para observância do mencionado prazo. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 2º A comunicação do cumprimento de mandado de prisão deverá ser autuada sob a classe “Comunicado de Mandado de Prisão” e receber numeração única, para, em seguida, ser distribuída à unidade responsável pela audiência de custódia. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). 120 § 3º Realizada a oitiva do preso, os autos do “Comunicado de Mandado de Prisão” não podem ser arquivados sem a juntada da certidão do registro do cumprimento no BNMP, medida que caberá ao Juízo emissor da ordem prisional. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 4º Nas unidades judiciais com competência em execução penal, após a juntada das peças do “Comunicado de Mandado de Prisão” no SEEU, caberá ao emissor da ordem prisional emitir a certidão de cumprimento e anexar aos respectivos autos processuais. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["audiencias","prazos","mandados","presos","execucao"]},{"n":"311-H","t":"A certidão de extinção de punibilidade por morte é documento obrigatório do BNMP e deve ser emitida pelo Juízo que proferir decisão definitiva que reconheça o falecimento de pessoa em procedimento, processo criminal ou de execução de pena, ainda que não tenha expedido qualquer outra peça no sistema. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º A emissão da certidão de extinção de punibilidade por morte gerará alerta em todos os mandados de prisão pendentes de cumprimento e inativará o cadastro da pessoa falecida. § 2º Havendo nos autos elementos indicativos do óbito, os Juízos deverão diligenciar para obtenção do respectivo comprovante no CRCJud. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["mandados","presos","execucao"]},{"n":"311-I","t":"Na hipótese de pessoa presa pelo processo que resultou em sua condenação, havendo o recebimento de recurso interposto pela acusação e/ou pela própria defesa, deve ser expedida no BNMP a guia de recolhimento provisória para início da execução. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). Parágrafo único. Sobrevindo o trânsito em julgado da condenação, impõe-se a expedição da respectiva guia de recolhimento definitiva pelo Juízo de conhecimento, somente sendo admitida a mera remessa de peças complementares (acórdão, certidão de publicação, certidão de coisa julgada e comunicação ao TRE) ao Juízo da Execução Penal, sem nova guia, na situação excepcional e devidamente justificada nos autos de inviabilidade técnica da plataforma eletrônica. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["mandados","execucao"]},{"n":"311-J","t":"A expedição de guias de recolhimento e de execução para os regimes semiaberto e aberto, respectivamente, prescinde do prévio cumprimento de mandado de prisão, exigindo-se tão somente a intimação da pessoa condenada para que possa dar início ao resgate da pena, sem prejuízo da audiência admonitória e da observância da Súmula Vinculante n.º 56. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). 121","v":["criminal","execucao"],"th":["audiencias","citacao","mandados","presos","execucao"]},{"n":"311-K","t":"As guias de recolhimento, de execução e de internação que apresentarem alguma irregularidade no BNMP, como ausência de mudança de competência de mandados ou peças com situação (cumprida ou pendente de cumprimento) diferente da verificada nos autos, deverão ser devolvidas às respectivas unidades judiciais ou administrativas (Serviço de Distribuição/Distribuição SEEU), com indicação expressa do motivo, para a devida correção no sistema. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["mandados","secretaria","execucao"]},{"n":"311-L","t":"Verificando-se a existência de persecução penal em novos autos formados a partir de desmembramento processual, deve a unidade judicial responsável pelo processamento do feito conferir a regularidade das peças emitidas no BNMP e providenciar, em sendo o caso, o saneamento devido. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["execucao"]},{"n":"311-M","t":"Constitui dever das unidades judiciais a manutenção da integridade das informações do sistema por intermédio de periódica verificação das medidas concedidas e peças emitidas, cabendo-lhes o pronto saneamento assim que constatada alguma omissão ou divergência com a situação processual da pessoa cadastrada, notadamente em relação aos mandados que imponham restrição à liberdade. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 1º Para o saneamento das informações, as unidades judiciais deverão sempre consultar os alertas emitidos pelo sistema. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023). § 2º A manutenção da higidez dos dados do BNMP será objeto de fiscalização da Corregedoria Geral da Justiça por ocasião de suas inspeções e correições. (Incluído pelo Prov. nº 09/2023/CGJCE, DJe de 16/05/2023).","v":["criminal","execucao"],"th":["mandados"]}]},{"num":"XV","title":"DO SISTEMA ELETRÔNICO DE EXECUÇÃO UNIFICADA (SEEU)","articles":[{"n":"312","t":"O Sistema Eletrônico de Execução Unificado - SEEU, desenvolvido pelo Conselho Nacional de Justiça – CNJ, fica definido como o meio de controle informatizado da execução penal, no âmbito da Justiça Comum de Primeiro Grau do Estado de Ceará.","v":["execucao"],"th":["execucao"]},{"n":"313","t":"Fica instituída a distribuição SEEU (Sistema Eletrônico de Execução Unificado), com atribuição para todo o território sob jurisdição deste Tribunal. 122","v":["execucao"],"th":["secretaria","execucao"]},{"n":"314","t":"A guia de execução da pena será expedida pelo juízo de conhecimento por meio do Sistema Eletrônico disponibilizado pelo Tribunal de Justiça do Ceará.","v":["execucao"],"th":["execucao"]},{"n":"315","t":"A Secretaria Judiciária de primeiro grau e a Secretaria Regional de 1º Grau das Comarcas de Crato, Juazeiro do Norte e Barbalha expedirão as guias de execução da pena das unidades judiciais por elas atendidas.","v":["execucao"],"th":["secretaria","execucao"]},{"n":"316","t":"As guias de execução da pena deverão ser encaminhadas para fila de trabalho específica no Sistema Eletrônico disponibilizado pelo Tribunal de Justiça do Ceará.","v":["execucao"],"th":["execucao"]},{"n":"317","t":"Recebida a guia de execução da pena, oriundas de outros Estados da Federação, por meio físico ou eletrônico, deverá ser observado o disposto no artigo 319 desta Consolidação.","v":["execucao"],"th":["execucao"]},{"n":"318","t":"A guia de execução erroneamente preenchida, incompleta ou deficientemente instruída deverá ser devolvida por via eletrônica à unidade judiciária de origem para correção/complementação da deficiência verificada.","v":["execucao"],"th":["execucao"]},{"n":"319","t":"As peças que compõem a guia de execução devem ser emitidas no sistema SAPG/PJE, obedecendo as disposições estabelecidas na Resolução n° 113/2010 do Conselho Nacional de Justiça.","v":["execucao"],"th":["execucao"]},{"n":"320","t":"Para cada pessoa será formado um único processo de execução penal, individual e indivisível, que reunirá todas as condenações impostas, inclusive as que vierem a ocorrer no curso da execução. § 1º A Distribuição SEEU deverá verificar, especialmente, mediante consulta ao Sistema Eletrônico de Execução Unificada - SEEU, a existência de processo de execução em curso, de forma a evitar a 123 duplicidade de execuções da mesma pena ou a execução simultânea em processos diversos. Nenhuma execução será autuada sem a inserção das peças essenciais, conforme o art. 106 da LEP; § 2º Sobrevindo condenação após a extinção do processo de execução anterior, transitado em julgado, será formado novo processo de execução penal, com novo registro numérico único; § 3º Sobrevindo condenação no curso da execução, após o registro da respectiva guia, o Juiz de Direito determinará a soma ou a unificação da pena ao restante da que está sendo cumprida e fixará o novo regime de cumprimento, observando-se, quando for o caso, a detração ou a remição; § 4º Ao final do cadastramento dos dados básicos do processo e do apenado, em se tratando do registro de novas execuções no SEEU, assim como por ocasião da juntada de guias nos processos existentes, faz-se necessária a certificação do ato no processo de conhecimento, informando o número da execução do Sistema Eletrônico de Execução Unificado - SEEU; § 5º Na hipótese a que se refere o § 3º deste artigo, a guia de execução da pena será remetida a Distribuição SEEU, que juntará a guia ao processo de execução em andamento, sem nova autuação, preservando-se a numeração única, certificada no SEEU a inclusão da guia de execução no processo correspondente; § 6º Sobrevindo trânsito em julgado da condenação, com guia de execução de pena provisória expedida, o juízo de conhecimento encaminhará as peças complementares diretamente ao juízo da execução em que tramita o processo de execução da pena, via malote digital; § 7º As guias de execução nos regimes fechado e semiaberto deverão apresentar comprovação de cadastro do BNMP 2.0, salvo existência de decisão judicial fundamentada sobre a ausência do referido documento; § 8º As guias de execução de Penas e Medidas Alternativas receberão cadastro e numeração próprios no Sistema Eletrônico de Execução Unificado - SEEU, para as comarcas que possuem unidades judiciais privativas dessa espécie, ressalvados os casos em que exista na referida unidade outra execução em nome do sentenciado, a qual deverá ser juntada a guia de nova condenação, de forma a evitar a duplicidade de execuções da mesma pena ou a execução simultânea em processos diversos. 124","v":["execucao"],"th":["mandados","secretaria","presos","execucao"]},{"n":"321","t":"A implantação do processo de execução da pena no SEEU caberá à vara de execução penal competente, salvo os casos em que o apenado possua outra guia de execução em andamento. § 1º A guia de execução erroneamente implantada ou incompleta será devolvida por via eletrônica à unidade judiciária de origem para correção/complementação, mediante despacho judicial, com indicação expressa da deficiência verificada. § 2º O servidor da unidade judicial responsável pelo recebimento da guia de execução providenciará o cadastro dos dados constantes nos autos no SEEU, e, automaticamente, o cálculo de liquidação da pena, com informações quanto ao término da pena e provável data de benefícios, tais como progressão de regime e livramento condicional. § 3º As informações sobre processos criminais, eventos e incidentes devem ser registradas e mantidas atualizadas no SEEU de forma que reflitam a realidade da situação executória. § 4º Sempre que houver alteração no cumprimento da pena, a Unidade Prisional deverá ser informada para que entregue ao sentenciado cópia do atestado de pena a cumprir ou do relatório da situação processual executória, juntando-se ao SEEU - CNJ o comprovante de entrega.","v":["execucao"],"th":["mandados","presos","execucao","atos_ordinatorios"]},{"n":"322","t":"Alterada a competência para o processamento da execução penal, a redistribuição dos autos será realizada pela Distribuição SEEU, mantendo-se a numeração única. Parágrafo único. Modificada a competência, caso necessário, a classe processual deverá ser alterada no sistema, antes da remessa ao juízo competente. 125","v":["execucao"],"th":["secretaria","execucao"]},{"n":"323","t":"Aos Juízos das Varas de Execução Penal e Corregedoria dos Presídios da Comarca de Fortaleza, ressalvada a competência da Vara de Execução de Penas e Medidas Alternativas, competem executar as sentenças condenatórias privativas de liberdade, inclusive as proferidas pelos juízos das comarcas do interior, quando a pessoa condenada estiver recolhida em uma das seguintes unidades: I - Centro de Triagem e Observação Criminológica (CTOC); II - Centro de Detenção Provisória (CDP); III - Unidade Prisional Professor José Sobreira de Amorim; IV - Centro de Execução Penal e Integração Social Vasco Damasceno Weyne (CEPIS); V - Unidade Prisional Irmã Imelda Lima Pontes; VI - Penitenciária Francisco Hélio Viana de Araújo (Pacatuba); VII - Instituto Penal Feminino Auri Moura Costa (IPF); VIII - Instituto Penal Professor Olavo Oliveira II (IPPOO II); IX - Hospital Geral e Sanatório Penal Professor Otávio Lobo; X - Instituto Psiquiátrico Governador Stênio Gomes; XI - Unidade Prisional Desembargador Adalberto de Oliveira Barros Leal (Caucaia); XII - Unidade Prisional Agente Luciano Andrade Lima (CPPL 1); XIII - Casa de Privação Provisória de Liberdade Professor Clodoaldo Pinto (CPPL 2); XIX - Casa de Privação Provisória de Liberdade Professor Jucá Neto (CPPL 3); XX - Casa de Privação Provisória de Liberdade Agente Elias Alves da Silva (CPPL 4).","v":["execucao"],"th":["execucao"]},{"n":"324","t":"As guias de execução penal das penas privativas de liberdade referentes aos sentenciados recolhidos na Penitenciária Industrial Regional de Sobral (PIRS) e Penitenciária Industrial Regional 126 do Cariri (PIRC) são de competência da 2ª Unidade Judicial Criminal de Sobral e 2ª Unidade Judicial Criminal de Juazeiro do Norte, respectivamente.","v":["execucao"],"th":["execucao"]},{"n":"325","t":"No caso de recolhimento em cadeia pública, a competência é do juízo da comarca local.","v":["execucao"],"th":[]},{"n":"326","t":"As cartas precatórias destinadas às Varas de Execução de Pena Privativa e Vara de Execução de Penas e Medidas Alternativas devem ser recebidas de forma eletrônica, em regra, pelo SEEU. § 1º Caso a comarca do juízo deprecante ainda não utilize o SEEU, a carta precatória será recebida excepcionalmente por via eletrônica, através do Sistema Hermes - Malote Digital, pela Distribuição SEEU. § 2º As cartas precatórias recebidas via malote digital, oriundas dos juízos que utilizem o SEEU, serão devolvidas ao juízo deprecante, a fim de que promova o reenvio por via eletrônica, através do SEEU. § 3º As cartas precatórias com finalidade de execução da pena não serão recebidas, devendo ser devolvidas ao juízo deprecante, sem prejuízo de remessa do processo executório, mediante declínio da competência. § 4º Os processos que foram migrados do SAJ para o SEEU como cartas precatórias com finalidade de execução da pena, ainda em tramitação, deverão ser devolvidos por malote digital, com arquivamento no SEEU, sem prejuízo da previsão do parágrafo anterior.","v":["execucao"],"th":["secretaria","execucao"]},{"n":"327","t":"As cartas precatórias expedidas nas Varas de Execução de Pena Privativa e Vara de Execução de Penas e Medidas Alternativas devem ser confeccionadas de forma eletrônica, em regra, pelo SEEU. Parágrafo único. Caso o juízo deprecado ainda não utilize o SEEU, a carta precatória deverá ser remetida por via eletrônica, através do Sistema Hermes - Malote Digital.","v":["execucao"],"th":["execucao"]},{"n":"328","t":"As cartas de ordem serão recebidas, preferencialmente, por via eletrônica, através do Sistema Hermes – Malote Digital - e distribuídas no SEEU pela Distribuição SEEU. 127","v":["execucao"],"th":["secretaria"]},{"n":"329","t":"Nas Varas de Execução de Pena Privativa e Vara de Execução de Penas e Medidas Alternativas, o agravo em execução será processado no SEEU, nos autos a que se refere. Parágrafo único. O juízo encaminhará o recurso em formato PDF, via malote digital, ao Departamento de Serviços Judiciários de Apoio do Tribunal de Justiça - Setor de Protocolo - Agravo em Execução Penal.","v":["execucao"],"th":["execucao"]},{"n":"330","t":"As informações, eventualmente, requisitadas aos juízos de primeiro grau, nos agravos em execução de pena que tramitam no segundo grau de jurisdição, serão realizadas via sistema Malote Digital.","v":["execucao"],"th":["execucao"]},{"n":"331","t":"Julgado o Agravo, a Coordenadoria de Recursos Criminais do Segundo Grau remeterá o acórdão e a certidão de trânsito em julgado ao Juízo da EXECUÇÃO, via sistema malote digital.","v":["execucao"],"th":["execucao"]},{"n":"332","t":"Em razão do que dispõe o art. 28-A, § 6º, do Código de Processo Penal, o processamento dos acordos de não persecução penal dar-se-á, obrigatoriamente, em meio eletrônico, mediante o uso do SEEU, sendo da competência do juízo da Vara de Execução de Penas e Medidas Alternativas, de acordo com a Portaria Conjunta PRES/CGJCE nº 865, de 26 de junho de 2020.","v":["execucao"],"th":["execucao","atos_ordinatorios"]},{"n":"333","t":"As guias para a execução da pena de multa cumulativamente aplicada, destinadas às varas de execução penal, devem ser recebidas de forma eletrônica pelo SEEU com numeração distinta da guia de execução de pena privativa de liberdade ou pena restritiva de direito. 128 § 1º A distribuição da execução da pena de multa deve ser realizada por dependência à guia de execução de pena privativa de liberdade ou pena restritiva de direito; § 2º No caso de título judicial por condenação exclusiva a pena de multa, a distribuição da guia será realizada por sorteio; § 3º Na superveniência de nova execução de pena privativa ou restritiva de direitos, em havendo processo de execução de pena de multa em curso no Estado do Ceará, não ocorrerá prevenção, devendo a nova guia se distribuída mediante sorteio.","v":["execucao"],"th":["secretaria","execucao"]},{"n":"334","t":"A expedição e a devolução dos mandados ordenados pelos juízos da execução penal deverão ser realizadas exclusivamente pelo SEEU.","v":["execucao"],"th":["mandados","execucao"]},{"n":"335","t":"As manifestações, petições, agravos e outros documentos oriundos do Ministério Público, Defensoria Pública, Administração Penitenciária e demais entidades cadastradas somente serão recebidas de forma eletrônica no SEEU (https://seeu.pje.jus.br/seeu), nos termos da Lei nº 11.419/2006, ressalvados os casos de indisponibilidade, devidamente comprovados.","v":["execucao"],"th":[]},{"n":"336","t":"Implantado o SEEU na comarca e encerrado o ciclo de migração dos dados dos processos da unidade judicial do Sistema de Automação da Justiça (SAJ) para o Sistema Eletrônico de 129 Execução Unificada - SEEU, pela Secretaria de Tecnologia da Informação - SETIN, se identificados processos não migrados, a respectiva unidade judicial, quando couber o cadastramento no SEEU, deverá: I - mover o processo para a fila de trabalho. Execução Migração para o SEEU; II - realizar o cadastramento manual do processo de execução penal no SEEU; III - juntar o arquivo em PDF das imagens do SAJ no respectivo processo de execução SEEU. Parágrafo único. Caso a situação do processo não indique “Remetido a outro Foro”, após realizar o item I, deverá ser aberto um chamado na CATI para que a área de informática providencie a alteração da situação de forma automática.","v":["execucao"],"th":["secretaria","execucao"]},{"n":"337","t":"Após a migração dos dados, os processos de execução penal e seus incidentes tramitarão exclusivamente no SEEU, sem prejuízo da manutenção dos dados e peças eletrônicas no Sistema de Automação da Justiça - SAJ, apenas para consulta.","v":["execucao"],"th":["execucao"]},{"n":"338","t":"O número da execução do SEEU será informado, pela Distribuição SEEU, no cadastro do processo do conhecimento no Sistema de Automação da Justiça (SAJ), na aba “outros números”.","v":["execucao"],"th":["secretaria","execucao"]},{"n":"339","t":"Quanto à matéria de que tratam os artigos 326 a 328, cumprida integralmente a diligência deprecada ou ordenada, os documentos comprobatórios serão enviados por malote digital ao Juízo Deprecante, com o arquivamento no SEEU dos autos nos quais processada a diligência.","v":["execucao"],"th":[]},{"n":"340","t":"Após o recebimento da guia de execução pela unidade judicial competente, a ela competirá a realização dos atos jurisdicionais e de secretaria.","v":["execucao"],"th":["secretaria","execucao"]},{"n":"341","t":"As atribuições da Secretária Judiciária de Primeiro Grau e da Secretaria Regional de 1º Grau das Comarcas de Crato, Juazeiro do Norte e Barbalha, previstas nas Portarias nº 1044/2019 (D.J.E 01.07.2019) e Portaria nº 115/2019 (D.J.E 24/01/2019), respectivamente, relativas aos processos que versem sobre execuções de pena, passam a ser realizadas pelas varas competentes, observadas as regras desta Portaria.","v":["execucao"],"th":["secretaria","execucao","atos_ordinatorios"]},{"n":"342","t":"Compete a Secretaria de Tecnologia da Informação realizar os ajustes necessários nos sistemas de informática para operacionalização da Distribuição SEEU.","v":["execucao"],"th":["secretaria"]}]},{"num":"XVI","title":"DOS TERMOS CIRCUNSTANCIADOS DE OCORRÊNCIA","articles":[{"n":"343","t":"Os magistrados dos juizados especiais criminais e os demais juízos com competência criminal do Ceará ficam autorizados a receber, mandar distribuir e processar os Termos Circunstanciados de Ocorrência - TCO, para o fim de deflagrar procedimento de natureza penal, lavrado por qualquer agente público regularmente investido na função de policiamento (art. 69, Lei 9099/95), a exemplo dos policiais militares, policiais rodoviários federais, escrivães e inspetores de Polícia Civil. Parágrafo único. Para observância da disposição inserta no caput deste artigo, não importa o meio de veiculação do expediente, se eletrônico ou físico.","v":["criminal","juizado"],"th":["execucao"]},{"n":"344","t":"Os Termos Circunstanciados de Ocorrência e demais peças que o equivalham, mesmo com diferente nomenclatura ou até sob classificação diversa, devem ser enviados diretamente ao Poder Judiciário ou por intermédio do Ministério Público.","v":["criminal","juizado"],"th":[]},{"n":"345","t":"O órgão receptor do Termo, após os registros que aprouver a instituição, no prazo de 5 (cinco) dias, deve encaminhá-lo à respectiva Delegacia (circunscricional ou especializada), a fim de que possa ser cadastrado, homologado, ratificado ou eventualmente aditado, à vista de investigações ou exames complementares. Parágrafo único. Os Termos confeccionados por policiais militares ou rodoviários federais prescindem da homologação da autoridade de Polícia Judiciária a que se refere o art. 144, § 4º, CRFB/88, preservados os demais atos pertinentes ao regular processamentos citados no caput.","v":["criminal","juizado"],"th":["prazos","citacao"]}]},{"num":"XVII","title":"DO ACORDO DE NÃO PERSECUÇÃO PENAL (ANPP)","articles":[{"n":"346","t":"Este normativo regulamenta o trâmite do Acordo de Não Persecução Penal (ANPP) de que trata o art. 28-A do Decreto-Lei nº 3.689, de 3 de outubro de 1941, Código de Processo Penal CPP, no âmbito do Poder Judiciário do Estado do Ceará.","v":["criminal"],"th":["execucao"]},{"n":"347","t":"Após a proposta do acordo de não persecução penal, na forma do art. 28-A do Código de Processo Penal, o Juiz competente para o processo de conhecimento deverá designar audiência para a sua homologação.","v":["criminal"],"th":["audiencias","execucao"]},{"n":"348","t":"Homologado o acordo de não persecução penal no juízo competente, com utilização obrigatória do movimento processual específico previsto nas Tabelas Processuais Unificadas do 131 CNJ (12733 - HOMOLOGAÇÃO DE ACORDO DE NÃO PERSECUÇÃO PENAL), deve o gabinete adotar as seguintes providências: (Redação conferida pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) I - atualizar o histórico de partes do(s) beneficiado(s) com o código 334. SUSPENSÃO - ACORDO DE NÃO PERSECUÇÃO PENAL; (Redação conferida pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) II - lançar a movimentação com o código 12065 - CUMPRIMENTO DE SUSPENSÃO OU SOBRESTAMENTO, em caso de benefício concedido a todos os investigados ou réus; (Redação conferida pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) III - determinar a abertura de vista ao Ministério Público, para que promova o início da execução; (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) IV - determinar a intimação da vítima, quando houver, utilizando-se de quaisquer meios idôneos para tal finalidade. (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) § 1º A competência para a execução do Acordo de Não Persecução Penal é da Vara de Execução de Penas e Medidas Alternativas, quando o beneficiado for residente na Comarca de Fortaleza, e das respectivas varas competentes para a execução penal, nas demais Comarcas, nos termos da lei estadual n.º 16.397/2017. § 2º Nos casos de cumprimento em até 60 (sessenta) dias das condições fixadas no acordo (v.g. renúncia a bens e direitos; restituição do bem à vítima; prestação pecuniária em parcela única etc.) dispensa-se o ajuizamento de ação de execução perante o juízo competente, devendo o próprio Juízo de conhecimento extinguir a punibilidade do agente. (Redação conferida pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022)","v":["criminal"],"th":["prazos","citacao","mandados","execucao"]},{"n":"349","t":"Cumprido o acordo e após a decisão declaratória de arquivamento por parte do juízo da execução, será dada ciência ao juízo de conhecimento, para decisão extintiva de punibilidade do beneficiado. (Redação conferida pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) Parágrafo único. Ao receber a comunicação de cumprimento do acordo, o juízo de conhecimento ouvirá o Ministério Público e, em seguida, concluindo pelo efetivo cumprimento, proferirá sentença extinguindo a punibilidade do beneficiado, com a utilização obrigatória do movimento processual específico previsto nas Tabelas Processuais Unificadas do CNJ (12735 - EXTINÇÃO DA 132 PUNIBILIDADE EM RAZÃO DO CUMPRIMENTO), devendo o gabinete adotar as seguintes providências: (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) I - atualizar o histórico de partes do(s) beneficiado(s) com o código 336 - EXTINÇÃO DA PUNIBILIDADE – CUMPRIMENTO DO ACORDO DE NÃO PERSECUÇÃO PENAL; (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) II - lançar a movimentação com o código 12066 - LEVANTAMENTO DO CUMPRIMENTO DE SUSPENSÃO OU SOBRESTAMENTO, em caso de benefício concedido a todos os investigados ou réus. (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022)","v":["criminal"],"th":["prazos","mandados","execucao"]},{"n":"349-A","t":"Havendo descumprimento de quaisquer das condições estipuladas no acordo de não persecução penal, o juízo da execução ouvirá o beneficiado, em 5 dias e, sucessivamente, abrirá vista ao Ministério Público, para manifestar-se no mesmo prazo, proferindo decisão logo em seguida. (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) § 1º Acolhida a justificativa do beneficiado, a execução prosseguirá normalmente. (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) § 2º Não sendo o caso de acolher a justificativa apresentada, o juízo da execução comunicará ao juízo do conhecimento, para a decisão cabível, sem a necessidade de nova oitiva do Ministério Público atuante no respectivo juízo do conhecimento. (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) § 3º Rescindido o acordo, deverá o gabinete do juízo do conhecimento tomar as seguintes providências: (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) I - lançar o movimento processual específico previsto nas Tabelas Processuais Unificadas do CNJ movimentação com o código 12734 (REVOGAÇÃO DO ACORDO DE NÃO PERSECUÇÃO PENAL); (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) II - atualizar o histórico de parte do(s) interessado(s) com o código 335 - REVOGAÇÃO ACORDO DE NÃO PERSECUÇÃO PENAL; (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) III - lançar a movimentação com o código 12066 - LEVANTAMENTO DO CUMPRIMENTO DE SUSPENSÃO OU SOBRESTAMENTO; (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) 133 IV - comunicar a rescisão ao juízo da execução; (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) V - determinar a intimação da vítima, quando houver, acerca da rescisão do acordo, utilizando-se de quaisquer meios idôneos para tal finalidade; (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) VI - determinar a abertura de vista ao Ministério Público, para os devidos fins. (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022) § 4º Recebida a comunicação mencionada no inciso IV do parágrafo anterior, o juízo da execução arquivará a execução. (Incluído pelo Prov. nº 15/2022/CGJCE, publicado no DJe de 07/10/2022)","v":["criminal"],"th":["prazos","citacao","mandados","execucao"]},{"n":"349-B","t":"(Revogado pelo Prov. Conj. nº 01/2024/CGJCE, publicado no DJeA de 31/10/2024)","v":["criminal"],"th":[]}]},{"num":"XVIII","title":"DOS COLEGIADOS PARA JULGAMENTO DE ORGANIZAÇÕES CRIMINOSAS","articles":[{"n":"350","t":"As reuniões presenciais serão realizadas na sede da comarca do juiz que requereu a instalação do colegiado, formado, continuado ou não extinto, nos termos da Resolução do TJCE nº 13/2018, publicada em 6 de setembro de 2018, cabendo-lhe a designação de data com a consequente intimação dos demais membros do colegiado, caso não designado conjuntamente o ato. Parágrafo único. Deverá ser lavrada ata da reunião para juntada ao processo, consignando-se a data e hora do ato, bem como o nome dos juízes participantes.","v":["criminal"],"th":["citacao"]},{"n":"351","t":"A reunião poderá ser sigilosa sempre que houver risco de que a publicidade resulte em prejuízo à eficácia da decisão judicial.","v":["criminal"],"th":[]},{"n":"352","t":"A reunião do colegiado composto por juízes domiciliados em cidades diversas poderá ser feita pela via eletrônica (videoconferência).","v":["criminal"],"th":["audiencias"]},{"n":"353","t":"O juiz sorteado deverá, mediante decisão fundamentada, informar ao juiz que preside o processo a impossibilidade de se fazer presente à reunião. Parágrafo único. Caberá ao magistrado reitor, em aceitando as escusas, convocar o suplente, observando a ordem do sorteio. 134","v":["criminal"],"th":[]},{"n":"354","t":"A designação do colegiado será mantida até que se conclua a realização do ato que a ensejou, cabendo à Corregedoria-Geral o sorteio e o envio de expediente à Presidência do Tribunal de Justiça do Estado do Ceará para fins de designação de novo magistrado, nos casos de impedimento, suspeição, remoção, promoção, aposentadoria, licença ou morte de um dos membros do colegiado, mediante provocação de qualquer de seus integrantes. (Redação conferida pelo Prov. nº 13/2021/CGJCE, DJe de 16/06/2021)","v":["criminal"],"th":[]},{"n":"355","t":"As decisões do colegiado devem ser firmadas, sem exceção, por todos os seus integrantes e de forma fundamentada, não constando referência a voto divergente de qualquer membro. § 1º As decisões poderão ser assinadas de próprio punho por todos os magistrados, através de certificação digital ou outro meio digital que garanta autenticidade à conformação do membro ao ato. § 2º As decisões produzidas pelo colegiado serão inseridas no sistema de controle processual pelo juiz do processo, resguardando-se eventual sigilo de justiça decretado nos autos. § 3º Caso o colegiado entenda necessária a prática de atos não elencados na decisão inicial de instauração, poderá haver o necessário aditamento, preservando-se o princípio do juiz natural.","v":["criminal"],"th":[]},{"n":"356","t":"Na hipótese de o colegiado verificar cessação dos motivos de sua constituição, requererá ao Corregedor-Geral da Justiça o cancelamento das designações, que, por sua vez, encaminhará o pedido à Presidência. Parágrafo único. Praticado o ato para o qual convocado, o colegiado será mantido nas hipóteses de embargos de declaração, de reexame de matéria em virtude de recurso com juízo de retratação, de pedido de revogação de prisão processual decretada anteriormente pelo colegiado ou do aditamento previsto no § 3º do art. 355 desta Consolidação.","v":["criminal"],"th":["presos"]},{"n":"357","t":"As comunicações entre os integrantes do colegiado poderão ser realizadas por meio eletrônico seguro, registrando-se nos autos, resumidamente, sua ocorrência.","v":["criminal"],"th":[]},{"n":"358","t":"Os atos processuais serão praticados, sempre que possível, pelo sistema de videoconferência, mantendo-se os investigados, indiciados, réus ou condenados, no estabelecimento prisional em que custodiados.","v":["criminal"],"th":["audiencias"]},{"n":"359","t":"Em situações excepcionais, plenamente justificadas pelas circunstâncias, admitir-se-á a expedição de carta precatória para a realização de ato processual, preferindo-se, no entanto, realizações por videoconferência. 135","v":["criminal"],"th":["audiencias","mandados"]},{"n":"360","t":"Não participarão do sorteio previsto no art. 4º da Resolução nº 04/ 2014, do Órgão Especial do Tribunal de Justiça do Estado do Ceará, os juízes que se enquadrarem nas seguintes hipóteses: I - tenham participado de 2 (dois) outros colegiados no mesmo ano do sorteio; II - em gozo de férias; III - afastados do exercício da jurisdição por período igual ou superior a 30 (trinta) dias; IV - não sejam titulares de juízos que tenham competência na área criminal. § 1º Os Juízes Auxiliares participarão do sorteio, desde que estejam designados para Juízo que exerça competência criminal. § 2º Os magistrados que estejam impossibilitados de participar do colegiado por força do caput deste artigo serão excluídos da base de dados que servirá para o sorteio.","v":["criminal"],"th":[]},{"n":"361","t":"A percepção de diárias observará as prescrições normativas do Tribunal de Justiça.","v":["criminal"],"th":[]},{"n":"361-A","t":"Caberá ao Juiz Presidente do Colegiado de 1º Grau, prestar informações, anualmente, no período de 01 a 31 de julho do ano de referência, acerca do andamento dos procedimentos investigatórios, processos judiciais e execuções penais em curso, para fins de acompanhamento por esta Corregedoria. (Incluído pelo Prov. nº 13/2021/CGJCE, DJe de 16/06/2021) § 1º As informações referidas no caput deverão ser encaminhadas, exclusivamente, por meio do preenchimento de formulário, constante do Anexo XVII desta Consolidação, disponibilizado no sítio eletrônico da Corregedoria-Geral da Justiça do Estado do Ceará, na aba Formulários Eletrônicos. (Redação conferida pelo Prov. nº 01/2024/CGJCE, republicado por incorreção no DJeA de 01/02/2024) § 2º Ficará a cargo da Gerência de Correição e Apoio às Unidades Judiciárias deste Órgão, o acompanhamento das informações prestadas através da ferramenta referida no parágrafo antecedente. (Incluído pelo Prov. nº 13/2021/CGJCE, DJe de 16/06/2021)","v":["criminal"],"th":["execucao"]}]},{"num":"XIX","title":"DA PROTEÇÃO DE VÍTIMAS E TESTEMUNHAS","articles":[{"n":"362","t":"O juiz de direito, o representante do Ministério Público e o delegado de polícia, no âmbito de suas competências, durante a investigação ou processo criminais, estão autorizados a procederem de acordo com o disposto neste capítulo, visando preservar o nome, endereço e demais dados de qualificação da vítima ou testemunha, assim como do investigado ou acusado-colaborador nos casos de coação ou grave ameaça em decorrência da colaboração a ser prestada durante a investigação policial ou instrução criminal.","v":["criminal","infancia"],"th":[]},{"n":"363","t":"Os dados pessoais da vítima e/ou da testemunha e do réu-colaborador deverão ser anotados em autos apartados dos autos de seus depoimentos e depositados em procedimento sigiloso em pasta própria, sob a guarda do(a) escrivão(ã) policial ou do(a) supervisor(a) de unidade judiciária, no âmbito de suas atribuições. § 1º Os documentos e dados deverão ser remetidos, com o devido destaque de seu caráter confidencial (carimbo ou etiqueta), pelo representante do Ministério Público ou pela autoridade policiai ao juiz competente, após a conclusão da investigação criminal; § 2º Protocolada a denúncia na distribuição com essas características. deverá o distribuidor comunicar ao(à) supervisor(a) de unidade judiciária que fará conclusão imediata dos autos ao magistrado para análise da adequação da medida; § 3º O pedido de acesso a tais documentos deverá ser formulado ao delegado de polícia, ao representante do Ministério Público ou ao magistrado condutor do feito, no âmbito da esfera de suas competências, que decidirá a respeito; § 4º É proibida a cópia ou reprodução dos documentos mencionados no § 1º deste artigo; § 5º As pastas deverão ser abertas e encerradas pelo escrivão, tendo no máximo 200 (duzentas) folhas, devidamente numeradas e rubricadas. Após o termo de encerramento, deverão ser lacradas e arquivadas, ressalvadas as regras contidas nos atos normativos da Corregedoria-Geral da Justiça do Ceará, atinentes à eliminação de autos e documentos.","v":["criminal","infancia"],"th":["secretaria"]},{"n":"364","t":"Os processos de que trata esta Consolidação deverão conter identificadores da pasta onde se encontram depositados os dados reservados.","v":["criminal","infancia"],"th":[]},{"n":"365","t":"O mandado de intimação da pessoa que estiver sob o amparo deste ato normativo será elaborado em separado para que os demais convocados a prestarem depoimento não tenham acesso às informações protegidas. Parágrafo único. Após o cumprimento do mandado, o oficial de justiça deverá juntar aos autos somente a certidão do ato, sem identificação de endereços, entregando o original do mandado 137 cumprido ao(à) supervisor(a) de unidade judiciária, que o arquivará na pasta, juntamente com os dados pessoais da vítima e/ou testemunha.","v":["criminal","infancia"],"th":["citacao","mandados"]},{"n":"366","t":"As anotações no SAJ/PG dos dados das pessoas que estiverem sob o amparo deste ato administrativo, deverão ser efetuadas de acordo com as regras referentes ao segredo de justiça.","v":["criminal","infancia"],"th":[]},{"n":"367","t":"As comunicações de atos processuais (citação, intimação, notificação, comunicado e ofício) pertinentes às hipóteses de vítimas, testemunhas ameaçadas e acusados-colaboradores por contribuírem com a investigação ou instrução criminais não poderão ser realizadas através de meios eletrônicos (telefone, fax, e-mail, internet), salvo por ordem judicial devidamente fundamentada. § 1º Por ocasião da comunicação dos atos processuais, sendo a audiência realizada por meio de videoconferência, a vítima ou testemunha protegida deverá ser: (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). I - cientificada acerca da possibilidade de ser ouvida em local diverso das dependências do Fórum, nos termos do §2º do art. 368-A, devendo manifestar interesse de imediato; II - orientada sobre a forma de realização da audiência e de todos os cuidados necessários para apresentação no dia e local designado. § 2º Qualquer que seja o rito processual criminal, o juiz, após a citação, tomará antecipadamente o depoimento das pessoas incluídas nos programas de proteção, devendo justificar a eventual impossibilidade de fazê-lo no caso concreto ou o possível prejuízo que a oitiva antecipada traria para a instrução criminal, nos termos da Lei nº 12.483/2011. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022).","v":["criminal","infancia"],"th":["audiencias","citacao"]},{"n":"368","t":"Os processos que estiverem sob o amparo desta Consolidação deverão tramitar com prioridade. § 1º Os processos judiciais deverão receber identificação na capa dos autos utilizando-se a nomenclatura PROVITA/CE, de forma a possibilitar, prontamente, visualização de prioridade pelos magistrados e serventuários da Justiça; § 2º Os processos deverão tramitar privativamente sob o pálio da responsabilidade do magistrado e supervisor(a) da unidade judicial, sucessivamente, evitando-se contato com demais servidores, ressalvados os casos previstos em Lei.","v":["criminal","infancia"],"th":[]},{"n":"368-A","t":"A oitiva de pessoa protegida, quando esta estiver localizada em Comarca diversa daquela onde é praticado o ato ou quando o Juiz, por questões de segurança, entender conveniente, 138 poderá ser realizada por meio do sistema de videoconferência adotado como padrão pelo Tribunal de Justiça do Estado do Ceará. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). § 1º As audiências por videoconferência devem ser realizadas, preferencialmente, nas dependências do Fórum, com a adoção de todos os cuidados necessários para garantir a segurança e integridade física do depoente/vítima. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). § 2º A pessoa protegida poderá optar por prestar depoimento em sua própria residência ou em outro local diverso daquele estabelecido no parágrafo anterior, onde entenda estar mais segura, desde que possua os recursos tecnológicos necessários para a realização do ato e manifeste interesse na forma prevista no inciso I, do § 1º, do art. 367 desta Consolidação. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). § 3º Será vedado o registro de imagens quando for necessária a preservação da identidade do depoente, nos termos da Lei nº 9.807/1999, cabendo ao Juiz avaliar a conveniência do registro apenas do áudio do depoimento. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). § 4º Na hipótese prevista no parágrafo anterior, a testemunha ou vítima será orientada a permanecer com o vídeo desabilitado durante toda a sua oitiva, que será gravada em arquivo específico. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). § 5º Poderá também ser utilizado para o depoimento de pessoa protegida pela PROVITA/CE, meios tecnológicos, se disponíveis, para desfocar a imagem e/ou distorcer a voz do depoente. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022).","v":["criminal","infancia"],"th":["audiencias","execucao"]},{"n":"368-B","t":"A identificação de pessoa sob proteção será realizada mediante exibição de documento oficial original com foto, apenas com a participação do Juiz ou de servidor por ele indicado. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). § 1º A gravação do vídeo de identificação será feita em arquivo diverso daquele utilizado para armazenar o depoimento, devendo o fato ser consignado na ata de audiência. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). § 2º O acesso ao arquivo de identificação deverá observar o sigilo necessário e somente ocorrerá, quando for devido, após a expressa autorização do Magistrado, devendo ser encaminhado por e- 139 mail apenas à parte autorizada com link exclusivo. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022).","v":["criminal","infancia"],"th":["audiencias","execucao"]},{"n":"368-C","t":"Sendo necessária a apresentação em juízo da pessoa protegida, o Juiz poderá, com antecedência, comunicar a realização do ato ao Diretor do Foro, solicitando-lhe adoção das providências necessárias no sentido de garantir a segurança e a integridade física do depoente/vitima, devendo, obrigatoriamente, haver o controle do acesso ao local onde se realizará a audiência, sendo vedada a informação de sua localização. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022). Parágrafo único. Caberá à Diretoria do Foro a expedição de portaria disciplinando o procedimento a ser adotado para garantir o acesso e oitiva das vítimas/testemunhas sob proteção, com a segurança e sigilo necessários, considerando-se a realidade de cada Comarca. (Incluído pelo Prov. n° 03/2022/CGJCE, publicado no DJe de 04/04/2022).","v":["criminal","infancia"],"th":["audiencias","mandados","atos_ordinatorios"]},{"n":"368-D","t":"As unidades judiciárias que realizam oitivas de crianças e adolescentes vítimas ou testemunhas de violência deverão observar as determinações e especificações constantes neste normativo. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023).","v":["criminal","infancia"],"th":[]},{"n":"368-E","t":"No âmbito do Judiciário Cearense, aplicar-se-á a metodologia do Depoimento Especial, realizado por autoridade judiciária, ainda que nas dependências das delegacias, por ocasião da Antecipação de Prova, mediante celebração de Acordo de Cooperação Técnica Interinstitucional. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). Parágrafo único. O(a) magistrado(a) deverá velar pela estrita observância do direito de crianças e adolescentes vítimas ou testemunhas de violências a serem ouvidas, obrigatoriamente, na forma do Depoimento Especial, não se tratando de faculdade procedimental, conforme art. 25, da Resolução nº 299/2019, do Conselho Nacional de Justiça.","v":["criminal","infancia"],"th":[]},{"n":"368-F","t":"O Depoimento Especial será colhido por entrevistador(a) forense, capacitado(a) pelo Tribunal de Justiça do Estado do Ceará ou pelo Conselho Nacional de Justiça, com certificação 140 específica, nos termos do art. 15 da Resolução nº 299/2019, do CNJ. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). § 1º O(a) entrevistador(a) forense será designado por ato normativo expedido pela Presidência do TJCE, passando a integrar o Cadastro de Entrevistadores Forenses, vinculado ao Núcleo do Depoimento Especial - NUDEPE. § 2º Deverá o entrevistador(a) participar de formação continuada e supervisão técnica por profissional capacitado pelo CNJ, visando o seu constante aperfeiçoamento.","v":["criminal","infancia"],"th":["citacao"]},{"n":"368-G","t":"A oitiva das crianças e adolescentes vítimas ou testemunhas de violências deverá ocorrer em sala específica e adequada, com a presença do depoente e do entrevistador, garantida a segurança, a privacidade e o conforto do depoente. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). § 1º Compete ao NUDEPE a orientação acerca da adequação da estrutura física e mobiliário das salas utilizadas para a coleta dos depoimentos, bem como a estruturação do fluxo de atendimento das demandas oriundas das comarcas da capital e do interior. § 2º No curso do processo judicial, o depoimento especial será transmitido, em tempo real, para a sala de audiência, por meio de videoconferência, conforme prevê o art. 10 c/c o inciso III e VI do art. 12, da Lei 13.431/2017. § 3º O Depoimento Especial é uma prova testemunhal, não gerando nenhum tipo de documento escrito elaborado pelo entrevistador forense. § 4º A criança ou adolescente vítima de infração penal ou testemunha de crimes violentos não deve ser submetida a procedimentos desnecessários, repetitivos ou invasivos, que a leve a reviver, sem estrita necessidade, a situação de violência ou outras situações potencialmente geradoras de sofrimento ou estigmatização, conforme previsão do art. 2º, da Lei nº 14.321/2022, que tipifica o crime de violência institucional.","v":["criminal","infancia"],"th":["audiencias","execucao"]},{"n":"368-H","t":"A oitiva por meio do Depoimento Especial deverá seguir o protocolo de entrevista, composto das seguintes fases: (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). I - planejamento e preparação; II - acolhimento inicial; III - aplicação do Protocolo Brasileiro de Entrevista Forense (Estágio 1 e 2); e 141 IV - encaminhamentos, quando necessário.","v":["criminal","infancia"],"th":[]},{"n":"368-I","t":"Na fase do PLANEJAMENTO E PREPARAÇÃO, o Núcleo de Depoimento Especial – NUDEPE, diretamente ou por meio das Centrais de Entrevistadores Forenses, deverá: (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). I - realizar o agendamento dos depoimentos solicitados pelas Unidades Judiciárias, conforme disponibilidade dos Entrevistadores Forenses cadastrados, critérios de prioridade, distância entre a comarca demandante e a lotação do servidor entrevistador forense e do entrevistador forense externo, quando regulamentada essa última modalidade, autorização de diárias e transporte; II - designar Entrevistadores Forenses aptos para o atendimento das oitivas requeridas; III - requisitar à unidade judiciária as providências para que o Entrevistador Forense tenha acesso aos autos do processo, para fins de estudo e análise da complexidade e/ou especificidades da demanda, por meio do fornecimento de senha de consulta, no prazo mínimo de 20 (vinte) dias de antecedência; IV - orientar a unidade demandante: a) acerca das condições estruturais para funcionamento da Sala de Acolhimento e da Sala do Depoimento Especial, bem como, dos equipamentos de videoconferência, para a adoção das medidas necessárias, a fim de sanar possíveis deficiências; b) sobre a necessidade de oficiar o Setor de Segurança do Fórum, visando a disponibilização de reforço policial, a depender da complexidade do caso, para fins de garantia da integridade física de todos os envolvidos no procedimento; c) para solicitar o fornecimento de transporte ao Conselho Tutelar ou Secretaria de Assistência Social, em caso de necessidade de deslocamento da vítima ou testemunha residente em localidades distantes do Fórum, contudo, na mesma comarca.","v":["criminal","infancia"],"th":["audiencias","prazos","citacao","secretaria"]},{"n":"368-J","t":"Na fase de ACOLHIMENTO INICIAL, os depoentes e seus responsáveis deverão ser recepcionados na unidade demandante e encaminhados, imediatamente, à sala de espera/acolhimento, especialmente reservada, a fim de evitar o contato da vítima ou testemunha, ainda que visual, com o(a) acusado(a) ou quaisquer pessoas que representem ameaça, coação ou constrangimento, nos termos do artigo 9º da Lei nº 13.431/2017. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). 142 § 1º Se a criança/adolescente não concordar em depor sobre os fatos do processo ou apresentar limitações em sua capacidade de expressão que inviabilizem a participação no Depoimento Especial, o entrevistador(a) forense deverá informar ao(a) magistrado(a). § 2º Após o acolhimento inicial, e antes de iniciar a gravação, o(a) entrevistador(a) forense deve: I - fornecer ao(a) depoente as informações sobre seus direitos, nos termos do art. 5º, incisos V, VI e VII; arts. 9º e 12, §§ 1º e 3º, da Lei nº 13.431/2017 e arts. 18, 19, 23 e 25 da Resolução nº 299/2019, do CNJ. II - informar a vítima ou testemunha de violência com idade entre 18 (dezoito) e 21 (vinte e um) anos, o direito de optar por ser ouvida na metodologia do depoimento especial, conforme disposto no art. 3º, parágrafo único, da Lei nº 13.431/2017.","v":["criminal","infancia"],"th":[]},{"n":"368-K","t":"A fase de APLICAÇÃO DO PROTOCOLO BRASILEIRO DE ENTREVISTA FORENSE - PBEF, recomendado pelo CNJ e adotado pelo TJCE, será realizada em dois estágios, a saber: (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). I - Estágio 1 - refere-se à construção do vínculo entre depoente e Entrevistador Forense, bem como, ao esclarecimento das regras e diretrizes para a condução da entrevista, sendo composto pelas seguintes fases: a) Introdução; b) Construção da empatia; c) Regras básicas/Diretrizes; d) Prática narrativa; e e) Diálogos sobre a família. II - Estágio 2 - refere-se à parte substantiva, momento em que ocorre o relato sobre a situação de violência, sendo composto das seguintes fases: a) Transição; b) Descrição narrativa; c) Seguimento e detalhamento; d) Interação com a sala de audiência ou sala de observação; e e) Fechamento. 143 Parágrafo único. No Estágio 1 deverá ser observado, obrigatoriamente, se a criança/adolescente apresenta limitações de expressão verbal e características psicológicas, comportamentais, desenvolvimentais, capacidade cognitiva para acesso mnemônico (prejuízos de memória) que possam prejudicar o depoimento, comunicando-se a ocorrência ao magistrado, a fim de subsidiar decisão sobre a dispensa da oitiva ou outra providência, fazendo de tudo constar no termo de audiência.","v":["criminal","infancia"],"th":["audiencias"]},{"n":"368-L","t":"Durante a aplicação do protocolo referido no artigo precedente deverão ser observados os seguintes procedimentos: (Incluído pelo Prov. nº 15/2023/CGJCE, publicado no DJeA de 09/11/2023). § 1º Devem ser assegurados os esclarecimentos preliminares, a livre narrativa e as questões complementares, cabendo ao magistrado zelar pela fiel observância do referido protocolo, na forma do disposto no art. 11 da Lei nº 13.431/2017, art. 25 do Decreto nº 9.603/2018 e art. 20 da Resolução nº 299/2019 do CNJ. § 2º A aplicação do protocolo deverá ser gravado nos dois estágios e transmitido em tempo real para a sala de audiência, conforme art. 24 da Resolução nº 299/2019 do CNJ. § 3º Durante o procedimento de acolhimento, se o entrevistador obtiver informações trazidas pelo depoente, expressando constrangimento diante da presença do réu na sala de audiência, mesmo que virtual, deverá informar ao juiz para providenciar o seu afastamento, se for o caso, conforme dispõe o artigo 12, parágrafo 3º, da Lei nº 13.431/2017. § 4º A aplicação do protocolo far-se-á apenas entre o Entrevistador Forense e a vítima ou testemunha, não sendo permitida a presença de outras pessoas, ainda que sejam os pais, responsáveis ou pessoa por eles indicada, na sala onde serão realizados os Estágios 1 e 2, com exceção de intérpretes e/ou profissionais dos quais a criança ou adolescente necessite em função de problemas de saúde; § 5º A possibilidade da participação dos pais ou responsáveis na sala de audiência física ou virtual, para onde será realizada a transmissão simultânea do depoimento, deverá ser analisada por magistrado(a) com base na expressa vontade da vítima ou testemunha, na avaliação inicial do Entrevistador Forense, na circunstância em que o acusado faz parte do contexto familiar do depoente e na possibilidade de ocasionar risco para a vítima ou testemunha, consoante previsto no art. 100, parágrafo único, do Estatuto da Criança e do Adolescente – ECA, e no art. 2º, incisos I e VI, do Decreto nº 9.603/2018; 144 § 6º O Depoimento Especial não poderá ser assistido, através de sala de observação ou virtual, por pessoa estranha ao processo legal, sob pena de configurar crime de violação do sigilo do ato, salvo autorização judicial, além do consentimento do depoente ou de seu representante legal, de acordo com o artigo 24 da Lei nº 13.431/2017; § 7º A aplicação do PBEF não deve sofrer interrupções de qualquer natureza, em nenhum dos estágios, sob pena de influenciar na interação e estabelecimento de vínculo entre o(a) Entrevistador(a) Forense e a criança ou o adolescente, bem como trazer importantes prejuízos para a tomada do depoimento; § 8º É vedada a leitura da denúncia ou de outras peças processuais para a criança ou o adolescente na tomada do seu depoimento especial, conforme disposição constante do inciso I do art. 12 da Lei 13.431/2017; § 9º Deve ser garantido à criança ou ao adolescente o direito ao silêncio e a não prestar o depoimento, esclarecendo-os de maneira adequada ao seu desenvolvimento, conforme art. 5º, VI, da Lei nº 13.431/2017; art. 22, §3º e art. 26, §1º, VI, ambos do Decreto nº 9.603/2018, c/c o art. 19 da Resolução nº 299/2019, do CNJ; § 10. Cabe a(o) magistrado(a) zelar pela fiel observância do referido protocolo, na forma do disposto no art. 11 da Lei nº 13.431/2017, art. 25 do Decreto nº 9.603/2018 e art. 20 da Resolução nº 299/2019, do CNJ;","v":["criminal","infancia"],"th":["audiencias","execucao"]},{"n":"368-M","t":"O(a) Entrevistador(a) Forense deverá conduzir livremente a oitiva da criança/adolescente, não sendo permitidas interrupções nesta fase, para garantia da autonomia profissional e respeito aos códigos de ética e às normas profissionais, conforme art. 26, §1º, inciso III, do Decreto nº 9.603/2018. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). Parágrafo único. As perguntas realizadas pelo(a) Entrevistador(a) Forense devem ser formuladas com base nas informações verbalizadas pela criança durante o relato livre, sendo vedada a introdução de perguntas com elementos alheios ao relato.","v":["criminal","infancia"],"th":[]},{"n":"368-N","t":"As indagações oriundas da sala de audiência, devem obedecer aos critérios especificados nos normativos vigentes e ocorrerão após a fase de detalhamento do Estágio 2, devendo-se atentar para o seguinte: (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). 145 I - se necessário, serão reformuladas pelo(a) Entrevistador(a) Forense, sendo adaptadas ao PBEF, sempre que possível; II - as perguntas que possam induzir o relato e/ou respostas do(a) depoente, atentar contra a sua dignidade, com conotação de juízo de valor ou apreciação moral, que possam caracterizar constrangimento ou atentar contra seus interesses, deverão ser evitadas e não repassadas pelo(a) Entrevistador(a) Forense à criança ou adolescente, conforme art 26, §1º, incisos I e II, do Decreto nº 9.603/2018; III - não é recomendado repassar perguntas repetidas ou que a criança ou adolescente já tenha verbalizado durante seu relato livre, além de perguntas sobre fatos ou situações estranhos ao processo, consoante disposto no art. 212, do Código de Processo Penal; IV - as perguntas direcionadas à criança ou adolescente deverão ser adaptadas à sua linguagem e ao seu desenvolvimento cognitivo e emocional, de acordo com seu interesse superior, conforme art. 26, §1º, inciso V, do Decreto nº 9.603/2018; V - o(a) magistrado(a) deverá velar para que as perguntas formuladas pelas partes sejam concentradas, tanto quanto possível, em apenas um bloco, ressalvada necessidade excepcional, conforme art. 12, inciso IV, da Lei nº 13.431/2017 e art. 22 da Resolução nº 299/2019, do CNJ; VI - durante a oitiva, as perguntas formuladas pelos operadores do Direito e repassadas à vítima ou testemunha pelo(a) Entrevistador(a) Forense, não devem ser conduzidas por este de forma a caracterizar uma inquirição/interrogatório, tendo em vista que o formato tradicionalmente utilizado viola os direitos das crianças e adolescentes, à medida que transfere a sua condição de vítima para culpado; VII - durante a oitiva da criança/adolescente deverão ser respeitadas as pausas prolongadas, os silêncios e os tempos de que o depoente necessitarem, conforme art. 26, §1º, inciso VI, do Decreto nº 9.603/2018; VIII - no caso do(a) Entrevistador(a) contraindicar uma pergunta que não esteja em conformidade com o disposto na Lei nº 13.431/2017 e/ou no Protocolo Brasileiro de Entrevista Forense, oriunda de qualquer profissional da sala de audiência, este poderá apresentar a fundamentação por escrito ao juiz, caso este solicite, no prazo de 15 (quinze) dias úteis, a partir da disponibilização da gravação (vídeo) da oitiva no sistema pela unidade judiciária ao Entrevistador Forense. 146 IX - as perguntas realizadas pelo(a) magistrado(a) ao(a) entrevistador(a), poderão ser repassadas diretamente, de forma manuscrita, whatsapp, utilizando-se um aparelho telefônico ou pelo chat da plataforma de videoconferência utilizada pelo Tribunal de Justiça do Estado do Ceará. X -em caso de ocorrência de problemas técnicos ou de bloqueio emocional que impeçam a continuação do Depoimento Especial, a oitiva da criança ou adolescente deverá ser reagendada, respeitando as particularidades da vítima ou testemunha, com base no art. 26, inciso VI e parágrafo 3º, do Decreto nº 9603/2018).","v":["criminal","infancia"],"th":["audiencias","prazos","execucao"]},{"n":"368-O","t":"Em atendimento ao Protocolo Brasileiro de Entrevista Forense, deve-se observar que: (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). § 1º Em hipótese alguma será permitida a participação da criança ou adolescente em procedimento de acareação com o acusado, testemunhas ou vítimas; § 2º É vedado a(o) Entrevistador(a) Forense confrontar a vítima ou testemunha, no caso de esta apresentar, durante a oitiva, versão diferente da anteriormente relatada em outro órgão do Sistema de Justiça ou Rede de Proteção, sob pena de causar prejuízo emocional, constrangimento e revitimização; § 3º caso o(a) Entrevistador(a) Forense identifique que a continuidade do procedimento poderá acarretar significativo prejuízo psicológico à criança ou adolescente, solicitará a(o) magistrado(a) o imediato encerramento do ato; § 4º Após o encerramento do depoimento especial, o(a) entrevistador(a) deverá promover um acolhimento final, certificando-se sobre o estado emocional da criança ou do adolescente. § 5º Concluída a audiência, a vítima ou testemunha deve ser preservada de ter qualquer contato, ainda que visual, com o(a) acusado(a) ou quaisquer pessoas que representem ameaça, coação ou constrangimento, nos termos do art. 9º da Lei nº 13.431/2017.","v":["criminal","infancia"],"th":["audiencias","execucao"]},{"n":"368-P","t":"A fase de ENCAMINHAMENTOS, quando necessário, ocorre após o encerramento da entrevista, devendo o(a) entrevistador(a) forense comunicar ao(a) magistrado(a) a necessidade de aplicação de Medidas Protetivas e/ou da realização de encaminhamentos da criança ou adolescente e seu responsável para atendimento em órgãos da Rede de Proteção. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023).","v":["criminal","infancia"],"th":[]},{"n":"368-Q","t":"Os procedimentos preparatórios para as oitivas objeto da presente seção, realizadas nas unidades judiciárias serão de responsabilidade do juízo demandante, observando-se o seguinte: (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). 147 § 1º Deverão ser, obrigatoriamente, designados entrevistadores forenses integrantes do cadastro do Núcleo de Depoimento Especial - NUDEPE, sendo vedada a convocação de outros profissionais para a realização de oitivas com depoimento especial. § 2º Os expedientes relativos às intimações (mandados judiciais) deverão conter a determinação para o comparecimento da criança ou adolescente vítima ou testemunha de violência ao local da audiência com Depoimento Especial, 30 (trinta) minutos antes do horário designado para a oitiva. § 3º Por ocasião do agendamento das audiências, deve-se observar que: I - as audiências com Depoimento Especial deverão ser agendadas, respeitando-se o intervalo de 01 (uma) hora, entre as oitivas a serem realizadas individualmente com cada depoente, a fim de que sejam aplicados todos procedimentos de acolhimento, Estágios I e II do PBEF, encaminhamentos necessários e higienização do ambiente antes de cada oitiva; II -o agendamento de 3 (três) oitivas por dia por entrevistador, excepcionalmente, 4 (quatro), quando devidamente justificado e submetido à análise do NUDEPE, considerando-se a eventual necessidade de encaminhamentos, oitivas de testemunhas ou procedimentos extraordinários decorrentes da complexidade do caso; III - o juízo demandante deve atentar para os critérios como a idade, limitações físicas, psicológicas, emocionais ou outras que requeiram tratamento diferenciado para as crianças e adolescentes vítimas ou testemunhas de violência, minimizando-se, portanto, a influência de fatores estressores e revitimização, as quais podem caracterizar ato de violência institucional; IV - as crianças e adolescentes vítimas ou testemunhas e seus responsáveis receberão atendimento prioritário e serão encaminhadas diretamente da recepção do fórum à sala de acolhimento, acompanhadas de proteção policial, providenciado pela unidade judiciária, quando necessário; V - o conteúdo do depoimento será gravado e armazenado, conforme art. 12, inciso VI, da Lei nº 13.437/2017 e do art. 23 do Decreto nº 9603/2018, ficando sob a guarda e responsabilidade da unidade demandante, devendo proceder a vinculação do depoimento aos autos correspondentes com medidas que lhe preservem o sigilo e confidencialidade; VI -é vedada a utilização ou o repasse a terceiro das declarações feitas pela criança e pelo adolescente, salvo para os fins de assistência à saúde e de persecução penal, na forma do inciso XIV, do art. 5º, da Lei nº 13.431/2017; 148 VII - as vítimas ou testemunhas com limitações na capacidade de fala ou escuta têm o direito de prestar declarações em formato adaptado à sua condição, inclusive, em idioma diverso do português, se for o caso, conforme inciso XV, do art. 5º, da Lei nº 13.431/2017; VIII - à criança e adolescente de origem indígena ou que pertençam a minorias étnicas ou linguísticas, será garantido intérprete ou outro meio eficaz, providenciado pela unidade judiciária demandante, conforme art. 2º, §2º, da Resolução nº 299/2019, do CNJ; IX - as unidades judiciárias que dispuserem de uma equipe técnica (psicólogo, assistente social ou pedagogo) deverão oferecer atendimento padronizado a todas as crianças ou adolescentes convocados e seus responsáveis, procedendo aos encaminhamentos necessários à Rede de Proteção e/ou Sistema de Justiça, com base nos arts. 14 e 16 da Lei nº 13.431/2017;","v":["criminal","infancia"],"th":["audiencias","mandados","execucao"]},{"n":"368-R","t":"O depoimento especial deverá ser realizado, preferencialmente, na comarca em que o(a) depoente reside, visando o melhor interesse da criança ou adolescente. (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). § 1º No caso de Carta Precatória, se o juízo deprecado for presidir a audiência, este procederá da seguinte forma: I - designação da data e hora da oitiva, em comum acordo com o NUDEPE; II - envio da solicitação de Entrevistador Forense, via CPA ou outro sistema adotado pelo TJCE, ao NUDEPE ou a Central de Entrevistadores Forenses correspondente; e III - adequação das salas de espera e de coleta do depoimento, bem como adoção de medidas de proteção da vítima e adolescente, nos termos da Lei nº 13.431/2017. § 2º No caso de Carta Precatória, se o juízo deprecante for presidir a audiência, deverão ser seguidos os seguintes procedimentos: I - caberá ao juízo deprecante proceder à: a) designação da data e hora da oitiva, em comum acordo com o NUDEPE e o juízo deprecado; b) envio da solicitação de Entrevistador Forense, via CPA ou outro sistema adotado pelo TJCE, ao NUDEPE ou a Central de Entrevistadores Forenses correspondente e, c) informar o link da audiência ao juízo deprecado. 149 II - caberá ao juízo deprecado proceder a adequação das salas de espera e de coleta do depoimento, bem como adoção de medidas de proteção da vítima e adolescente, nos termos da Lei nº 13.431/2017 § 3º Nas duas situações, o(a) Entrevistador(a) Forense e a criança ou adolescente vítima ou testemunha de violências deverão comparecer de forma presencial nas instalações do Fórum, sendo vedada a participação por videoconferência ou no formato telepresencial. § 4º O(a) magistrado(a), advogado(a), representante do Ministério Público e da Defensoria Pública, bem como as partes e demais participantes da audiência, poderão participar por meio do link disponibilizado para a videoconferência.","v":["criminal","infancia"],"th":["audiencias","citacao"]},{"n":"368-S","t":"Para a adequação da infraestrutura necessária à realização do Depoimento Especial, exigir-se-á necessariamente a adoção das seguintes providências: (Incluído pelo Prov. n° 15/2023/CGJCE, publicado no DJeA de 09/11/2023). I - nas comarcas em que não haja ambiente instalado para fins de Depoimento Especial, haverá a necessidade de adaptar duas salas próximas, para realização do Acolhimento Inicial e da oitiva da criança e/ou adolescente, conforme recomendações técnicas assentadas no PBEF; II - verificação prévia dos equipamentos de informática que serão utilizados durante a oitiva, realizando-se testes para observar a qualidade de imagem e som.","v":["criminal","infancia"],"th":[]}]},{"num":"XX","title":"DOS JURADOS","articles":[{"n":"369","t":"Os indivíduos que atuam neste Estado, como jurados, estão dispensados do cumprimento do expediente de trabalho na repartição pública, no estabelecimento empresarial ou outro local em que desempenhe a sua atividade laboral, sem qualquer prejuízo em seus vencimentos, nos dias em que devam comparecer à sessão de julgamento no Tribunal do Júri, independentemente de comporem o conselho de sentença. Parágrafo único. Ainda que, por qualquer motivo, a sessão de julgamento não se realize no dia designado, estará o jurado dispensado de, naquela data, exercer as suas atividades laborais, sendo vedado desconto em seus vencimentos. 150","v":["criminal"],"th":["audiencias","mandados"]},{"n":"370","t":"Nos dias que não forem reservados para a realização de sessão de julgamento do Tribunal do Júri na unidade judicial em que o jurado estiver lotado, deverão estes comparecer aos seus locais de trabalho para o desempenho regular de suas atividades laborais.","v":["criminal"],"th":["audiencias"]},{"n":"371","t":"No caso de ausência injustificada do jurado à sessão de julgamento, este não ficará dispensado de cumprir o seu expediente de trabalho.","v":["criminal"],"th":["audiencias"]}]},{"num":"XXI","title":"DOS ATOS INFRACIONAIS","articles":[{"n":"372","t":"Todos os processos que envolvem apuração de conduta de adolescente por ato infracional, no âmbito das Comarcas do Estado Ceará, deverão ser registrados e autuados como feitos de natureza cível, inclusive no sistema informatizado, tanto os processos em trâmite quanto os vindouros. Parágrafo único. As informações constantes nos feitos deverão ser alteradas em conformidade com as modificações insertas no caput deste artigo, devendo as respectivas modificações serem concluídas, no prazo de 30 (trinta) dias, contados da publicação deste ato normativo.","v":["infancia"],"th":["prazos"]}]},{"num":"XXII","title":"DO CREDENCIAMENTO DE AGENTES DA INFÂNCIA E JUVENTUDE","articles":[{"n":"373","t":"Para fiscalizar o fiel cumprimento do Estatuto da Criança e do Adolescente, bem como das determinações da autoridade judicial, poderá o juízo com jurisdição em matéria da Infância e da Juventude providenciar o credenciamento de agentes voluntários de proteção à criança e ao adolescente, os quais gozarão de fé pública no exercício da função. (Redação conferida pelo Prov. nº 07/2023/CGJCE, publicado no DJe de 14/04/2023). § 1º O credenciamento de voluntários para a prestação dos serviços previstos neste artigo, com fulcro no caput do art. 194 do Estatuto da Criança e do Adolescente, não gera vínculo empregatício, nem obrigações de natureza trabalhista, previdenciária ou afim, e será realizado de acordo com a 151 oportunidade e a conveniência do juízo competente. (Renumerado pelo Prov. nº 07/2023/CGJCE, publicado no DJe de 14/04/2023). § 2º O auto de infração administrativa previsto no art. 194 do Estatuto da Criança e do Adolescente poderá, ainda, ser realizado por membros do Conselho Tutelar, devidamente capacitados, sem prejuízo da atuação do Ministério Público. (Incluído pelo Prov. nº 07/2023/CGJCE, publicado no DJe de 14/04/2023).","v":["infancia"],"th":["citacao","mandados"]},{"n":"374","t":"Caso a autoridade judicial opte pela realização do credenciamento, o número de agentes voluntários de proteção à criança e ao adolescente será fixado considerando a população da comarca, podendo ser credenciado 1 (um) agente voluntário para cada 5.000 (cinco mil) habitantes em cada um dos municípios que a compuserem. (Redação conferida pelo Prov. nº 07/2023/CGJCE, publicado no DJe de 14/04/2023). § 1º Independente do número de habitantes, haverá, pelo menos, 3 (três) agentes voluntários de proteção à criança e ao adolescente, nas comarcas cuja autoridade judicial decidir pela realização do credenciamento. (Redação conferida pelo Prov. nº 07/2023/CGJCE, publicado no DJe de 14/04/2023). § 2º Para os fins do disposto no caput, será computado o número da população constante do último censo geral do Instituto Brasileiro de Geografia e Estatística - IBGE. (Redação conferida pelo Prov. nº 07/2023/CGJCE, publicado no DJe de 14/04/2023).","v":["infancia"],"th":[]},{"n":"375","t":"O candidato deverá peticionar ao Juiz de Direito da Infância e da Juventude requerendo seu credenciamento. São requisitos para o credenciamento: I - maioridade civil e gozo de todos os direitos civis; II - instrução de nível médio completo ou superior, salvo se provado o exercício da atividade voluntária de proteção à criança e ao adolescente há mais de 2 (dois) anos; III - não possuir antecedentes criminais; IV - ausência de vínculo, a qualquer título, com os locais ou estabelecimentos sujeitos à fiscalização pelo juízo da Infância e da Juventude; V - domicílio na comarca em que pretende atuar; VI - não estar exercendo e nem concorrendo a cargo eletivo; VII - não exercer a função de agente de proteção em outra comarca. 152","v":["infancia"],"th":[]},{"n":"376","t":"O pedido de credenciamento deve ser instruído com: I - questionário, em modelo padronizado pela Corregedoria-Geral da Justiça, devidamente preenchido e assinado pelo candidato; II - cópias da cédula de identidade e da inscrição no Cadastro de Pessoas Físicas (CPF); III - cópia de comprovante de endereço residencial; IV - cópia de diploma ou certificado de escolaridade, salvo a hipótese prevista na parte final do art. 375, inciso II, caso em que deverá ser comprovado o exercício da atividade voluntária de proteção à criança e ao adolescente há mais de 2 (dois) anos; V - duas fotos 3x4 cm; VI - folha de antecedentes e certidão dos distribuidores cível e criminal dos locais onde o candidato tenha residido nos últimos 5 (cinco) anos; VII - prova de quitação com as obrigações eleitorais e, se do sexo masculino, com o serviço militar; VIII - termo de compromisso do candidato em modelo padronizado pela Corregedoria-Geral da Justiça. § 1º Para o atendimento ao previsto no inciso VIII do caput deste artigo, o candidato deverá declarar, no ato de sua candidatura, ciência de todos os deveres e obrigações impostos ao agente voluntário de proteção à criança e ao adolescente, firmando, ainda, o compromisso de: I - cumprir as tarefas atribuídas pelo juiz de direito da Infância e da Juventude; II - exercer a função com equilíbrio, prudência, educação e urbanidade; III - não auferir ou tentar auferir qualquer tipo de vantagem material para si ou para terceiros, no exercício da função; IV - não exercer qualquer atividade, ainda que gratuitamente, nem possuir qualquer vínculo com os locais sujeitos à fiscalização do juízo com jurisdição em matéria da Infância e da Juventude. § 2º No caso de falta de documentação, o juiz de direito da Infância e da Juventude poderá conceder prazo para sua complementação.","v":["infancia"],"th":["prazos"]},{"n":"377","t":"Verificada a regularidade do requerimento e da documentação, o juiz de direito, ou servidor por ele indicado, realizará a entrevista pessoal do candidato. 153 §1º Constatada a ausência de condições objetivas ou a presença de condição impeditiva, o pedido será apreciado de plano, desnecessária a entrevista. §2º Será facultado ao Juízo de Direito da Comarca, competente ao processamento e julgamento das causas da Infância e da Juventude, para a viabilização da prestação dos serviços inerentes ao quadro de agentes de proteção, a escolha de candidatos que não residam na Comarca, podendo recrutar candidatos de Comarcas contíguas, os quais se submeterão aos requisitos estampados no art. 375, com base nos seguintes critérios objetivos: I - ausência de candidatos aptos ao exercício da função, residentes na Comarca; II - ausência de pessoas para se candidatar ao quadro de agentes de proteção, residentes na Comarca.","v":["infancia"],"th":["audiencias"]},{"n":"378","t":"A nomeação do diretor do serviço voluntário deverá recair em servidor efetivo do Poder Judiciário, e será feita pela Corregedoria-Geral da Justiça, mediante indicação pelo Juiz da vara ou Comarca. Parágrafo único. Os voluntários somente poderão realizar diligências munidos de portarias específicas ou mandados expedidos, em cada caso, pela autoridade competente.","v":["infancia"],"th":["mandados","atos_ordinatorios"]},{"n":"379","t":"É vedado ao voluntário, no exercício das funções, o porte de arma de fogo, armas brancas, algemas ou qualquer outro instrumento de dissuasão, bem como participar de atividades ou diligências de cunho policial.","v":["infancia"],"th":[]},{"n":"380","t":"O chefe do serviço voluntário deverá apresentar ao respectivo Juiz, até o 5º dia útil de cada mês, relatório dos serviços desenvolvidos do mês, imediatamente anterior, cuja cópia será encaminhada à Corregedoria-Geral da Justiça.","v":["infancia"],"th":[]},{"n":"381","t":"A pedido do interessado, por conveniência do Juízo, ou por justa causa, o Juiz poderá a qualquer momento exonerar o voluntário, comunicando o fato, imediatamente, à CorregedoriaGeral da Justiça, para homologação e anotação.","v":["infancia"],"th":[]},{"n":"382","t":"Sempre que houver notícia de irregularidade praticada por voluntário no exercício da função, ou na hipótese de negligência ou omissão funcional, deverá o Juiz cassar o credenciado e comunicar o fato à Corregedoria-Geral da Justiça. 154","v":["infancia"],"th":[]}]},{"num":"XXIII","title":"DA UTILIZAÇÃO DE CADÁVERES NÃO RECLAMADOS","articles":[{"n":"383","t":"A utilização de cadáver não reclamado, para estudo e pesquisa, será precedida de autorização judicial e lavratura de óbito.","v":["criminal"],"th":[]},{"n":"384","t":"O pedido de autorização para utilização de cadáver para ensino e pesquisa deverá ser feito pela Escola de Medicina interessada diretamente ao Juiz Corregedor Permanente da comarca onde ocorreu a morte, mediante apresentação de declaração da ausência de identificação do extinto ou de ausência de endereço ou de qualquer parente vivo. Parágrafo único. Somente será concedida autorização às instituições credenciadas e reconhecidas pelo MEC, que provarem possuir condições necessárias para guarda do corpo em condições apropriadas e especificarem a necessidade de utilização do cadáver.","v":["criminal"],"th":[]},{"n":"385","t":"O Juiz Corregedor Permanente determinará a expedição de editais, às expensas da Escola de Medicina requerente, os quais deverão ser publicados em jornal de grande circulação, em 10 (dez) dias alternados, contendo todos os dados de identificação disponíveis do cadáver, de maneira tão completa quanto possível, e a possibilidade de serem dirigidas reclamações de familiares ou responsáveis ao Juízo Corregedor Permanente.","v":["criminal"],"th":["mandados"]},{"n":"386","t":"Comprovada a publicação e passado o prazo de 20 (vinte) dias da última, dar-se-á vista dos autos ao Ministério Público para manifestação acerca do pedido, em seguida os autos serão remetidos ao Juiz Corregedor Permanente, para julgamento de reclamações porventura apresentadas e a eventual concessão de autorização para lavratura do assento de óbito, onde ficará consignada a destinação específica do cadáver.","v":["criminal"],"th":["audiencias","prazos"]},{"n":"387","t":"Somente depois de autorização do Juiz Corregedor Permanente, o cadáver poderá ser entregue à instituição de ensino superior (Faculdade de Medicina) requerente, para fins de ensino e de pesquisa de caráter científico.","v":["criminal"],"th":[]},{"n":"388","t":"A instituição de ensino requerente e seus representantes legais responderão civil e criminalmente por todos os atos, fatos e procedimentos que caracterizem eventual desvio de finalidade ou violação dos termos desta Consolidação ou que possam ferir as normas legais e de ética pertinentes.","v":["criminal"],"th":[]},{"n":"389","t":"É vedada a cessão de cadáver ou de parte deste a qualquer outra instituição. 155","v":["criminal"],"th":[]}]},{"num":"XXIV","title":"DO PROTESTO DE DECISÕES JUDICIAIS","articles":[{"n":"390","t":"Admite-se o protesto extrajudicial de crédito decorrente dos provimentos jurisdicionais abaixo relacionados, observado o seguinte: I - sentença judicial condenatória transitada em julgado, que represente obrigação pecuniária líquida, certa e exigível, transcorrido o prazo de quinze (15) dias para o pagamento voluntário, nos termos dos artigos 517 c/c 523 do CPC; II - decisão irrecorrível sobre alimentos provisórios ou provisionais, transcorrido o prazo estipulado para o pagamento espontâneo, nos termos do art. 528, §1º, do CPC; III - decisão que fixar honorários advocatícios, salvo se: a) houver mais de um advogado e, entre eles não existir sociedade civil, nos termos do art. 15 da Lei nº 8.906/94; b) o advogado anuir, expressamente, quanto ao protesto conjunto de seu crédito e o do cliente.","v":["geral","civel","criminal","fazenda"],"th":["prazos"]},{"n":"391","t":"Fica instituída a Certidão de Crédito Judicial (CCJ), documento essencial para os fins descritos no presente normativo (art. 517, §1º do CPC), nos termos do Anexo XIII, parte integrante do presente normativo.","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"392","t":"A certidão de que trata o artigo precedente, será expedida pelos Gabinetes ou Secretarias Judiciárias Únicas, quando existentes, mediante requerimento escrito do credor, devidamente acompanhada de planilha de cálculos atualizados da dívida, devendo constar, obrigatoriamente, as seguintes informações: I - qualificação do credor: nome ou razão social, endereço, número de inscrição no cadastro do Ministério da Fazenda (CPF/CNPJ) e do documento oficial de identificação; II - qualificação do devedor: nome ou razão social, endereço, número de inscrição no cadastro do Ministério da Fazenda (CPF/CNPJ) e do documento oficial de identificação; III - natureza e número do processo judicial, bem como a identificação do juízo de origem e do responsável pela emissão da Certidão de Crédito Judicial para fins de Protesto; 156 IV - o valor líquido e certo da dívida, de forma discriminada - valor da condenação, honorários advocatícios e multas - constando a data da última atualização, conforme memorial de cálculo apresentado pelo requerente no momento do pedido de expedição da Certidão de Crédito Judicial; V - a data da sentença e do trânsito em julgado ou, quando se tratar de decisão interlocutória relativa à dívida de alimentos, a data da decisão e do decurso do prazo para recurso; VI - a data em que, após intimação do devedor, decorreu o prazo legal para pagamento voluntário; VII - a referência de que a parte devedora é beneficiária da gratuidade judiciária, quando for o caso; VIII - a informação de que o protesto não impede a regular execução judicial do débito. § 1º As Certidões de Créditos Judiciais para fins de protesto extrajudicial serão expedidas no prazo de três (03) dias, contados da data do recebimento do respectivo pedido (art. 517, § 2º do CPC); § 2º A certidão poderá ser emitida eletronicamente e assinada digitalmente pelo magistrado, servidor por ele indicado ou ainda pelo servidor responsável nas Secretarias Judiciárias Únicas, e deverá acompanhar cópia da decisão judicial que gerou o débito e da certidão do trânsito em julgado; § 3º A expedição de certidão de processos em segredo de justiça dependerá de despacho do juiz competente; § 4º Cópia da certidão emitida deverá ser juntada aos respectivos autos, obrigatoriamente; § 5º Em todos os casos, a certidão será levada a protesto, no tabelionato da comarca de domicílio do devedor ou na localidade de tramitação do processo, sob a exclusiva responsabilidade do credor, comparecendo diretamente ao Cartório Distribuidor da respectiva Comarca ou mediante acesso a Central Nacional de Protestos (endereço eletrônico: https://site.cenprotnacional.org.br/); § 6º Apresentada a Certidão de Crédito Judicial para o devido processamento do protesto, o credor deverá informar ao juiz competente, no prazo de 24 (vinte e quatro) horas, a serventia extrajudicial em que o título foi protestado.","v":["geral","civel","criminal","fazenda"],"th":["prazos","citacao","mandados","secretaria","execucao","atos_ordinatorios"]},{"n":"393","t":"Para a efetivação do protesto deverá o tabelião competente exigir a apresentação de Certidão de Crédito Judicial (CCJ), preenchida com todos os requisitos constantes do artigo 392 desta Consolidação, devidamente acompanhada de cópia da decisão judicial que gerou o débito e da certidão do trânsito em julgado. 157","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"394","t":"Apresentados os documentos necessários ao protesto, será lavrado o respectivo ato conforme a legislação pertinente, independente de prévio depósito de emolumentos ou outras despesas, inclusive com intimação do devedor, cujos valores serão pagos pelo devedor no ato do pedido de cancelamento do protesto, devendo o cálculo ser feito com base nos valores da tabela de emolumentos em vigor na data do efetivo cancelamento ou no ato do pagamento elisivo. § 1º Os valores relativos aos emolumentos, despesas cartorárias e selos, referente ao protesto de certidão de crédito regulamentada no presente normativo, serão pagos pelo devedor, nos termos do parágrafo anterior, não incidindo a referida cobrança em caso de desistência, cancelamento judicial ou sustação do protesto, quando então o adimplemento ficará sob a incumbência do credor; § 2º Na hipótese de ocorrer, por parte dos órgãos do Poder Judiciário, encaminhamento indevido para protesto ou equívoco na expedição da Certidão de Crédito Judicial (CCJ), sobre o pedido de desistência ou cancelamento, não incidirá o recolhimento de emolumentos e demais taxas; § 3º Havendo sustação da Certidão de Crédito Judicial (CCJ), por decisão judicial, seja de natureza temporária ou permanente, não incidirá o recolhimento de emolumentos e demais taxas, em relação aos órgãos do Poder Judiciário.","v":["geral","civel","criminal","fazenda"],"th":["citacao","mandados"]},{"n":"395","t":"O serviço extrajudicial que receber a Certidão de Crédito Judicial (CCJ) comunicará ao Juízo emitente, no prazo de 24 (vinte e quatro) horas, se houve o adimplemento do título ou a lavratura do protesto, através de ofício a ser encaminhado eletronicamente por meio de malote digital. § 1º A comunicação referida no caput, não obsta que o devedor apresente perante o juízo de origem a comprovação do adimplemento do débito, para fins de juntada nos autos. § 2º Eventual quitação da dívida por forma diversa, não desincumbirá a parte devedora do pagamento dos emolumentos e custas relacionadas ao protesto já em processamento.","v":["geral","civel","criminal","fazenda"],"th":["prazos"]},{"n":"396","t":"Na hipótese de quitação do título, os valores devidos deverão ser repassados ao credor e aos cofres do Poder Judiciário, do Ministério Público e da Defensoria Pública na forma e prazos previstos nas normas alusivas à matéria. Parágrafo único. Para fins de baixa e arquivamento do processo, será verificada a eventual existência de débitos processuais. Em caso positivo, e não verificado o pagamento, será realizado o processamento na conformidade da legislação pertinente.","v":["geral","civel","criminal","fazenda"],"th":["prazos"]},{"n":"397","t":"O devedor que estiver discutindo a validade da sentença judicial protestada, em sede de ação rescisória, poderá requerer, às suas expensas e responsabilidade, anotação à margem do título 158 protestado acerca da existência da referida ação (art. 517, §3º do CPC c/c art. 284, §4º do Provimento nº 08/2014/CGJCE).","v":["geral","civel","criminal","fazenda"],"th":[]}]},{"num":"XXV","title":"DO PROCESSAMENTO E RECUPERAÇÃO DAS DESPESAS PROCESSUAIS","articles":[{"n":"398","t":"É devida a verificação e o acompanhamento do recolhimento das despesas e custas processuais cabíveis nos processados judiciais.","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"399","t":"Cabe ao Gabinete da unidade judicial, após o trânsito em julgado da sentença, verificar a existência de custas judiciais pendentes de recolhimento e proceder à intimação da parte responsável, com informação do valor atualizado, para efetuar o pagamento, no prazo de 15 (quinze) dias, sob pena de inscrição na dívida ativa, com fulcro no art. 523 do CPC. §1º Efetuado o pagamento no prazo ou após a cobrança, os comprovantes deverão ser anexados ao processo, para os devidos fins de direito; § 2º Compete ao Gabinete da unidade judicial, em qualquer fase processual, acompanhar o regular pagamento das custas judiciais devidas; § 3º Nas comarcas que dispõem do sistema SAJ-PG com módulo de custas disponível, o monitoramento da regularidade dos pagamentos deve ocorrer pela emissão e análise do relatório denominado “Situação das Guias”, extraído do aludido sistema, procedendo-se à intimação imediata das partes responsáveis para pagamento quando identificadas guias pendentes; § 4º As custas serão atualizadas pelo Gabinete da unidade judicial, que providenciará ato ordinatório ou despacho determinando a intimação da parte para fins de pagamento, nos termos do caput deste artigo; 159 §5º Em caso de unidade judiciária assistida pela Secretaria Judiciária Única de Primeiro Grau (SEJUD) as intimações para fins de pagamento serão realizadas pela Coordenadoria de Monitoramento das Custas Judiciais a partir de sua implantação.","v":["geral","civel","criminal","fazenda"],"th":["prazos","citacao","secretaria","execucao","atos_ordinatorios"]},{"n":"400","t":"A apuração e atualização do valor devido das custas processuais, nos termos desta Consolidação, processam-se da seguinte forma: I - atualização do valor da causa, a partir da data do protocolo da ação até a data do trânsito em julgado da sentença; II - atualizado o valor da causa, cálculo da despesa processual pelo enquadramento do valor corrigido na tabela vigente na data do trânsito em julgado da sentença; III - no caso de custas ocasionais não recolhidas à época, atualização do valor é a partir da data de realização do ato processual eventual até a data do trânsito em julgado da sentença, considerando a tabela da época do ato; IV - verificada a existência de custas pagas parcialmente, após as providências dos incisos I e II, do correto valor apurado, deve-se subtrair a quantia paga a menor, também atualizada. § 1º A base de cálculo das custas iniciais é o valor atribuído à causa pela parte na petição inicial ou o ajustado pelo juízo; § 2º A atualização monetária definida neste artigo, ocorrerá pela variação do Índice Nacional de Preços ao Consumidor Amplo, IPCA-E do Instituto Brasileiro de Geografia e Estatística (IBGE), divulgado trimestralmente; § 3º A metodologia de cálculo indicada neste artigo será demonstrada no Anexo XIV, parte integrante desta Consolidação. 160","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"401","t":"Se a parte responsável, intimada, não pagar no prazo, competirá ao Gabinete da unidade judicial enviar, imediatamente, o valor do débito atualizado, apurado nos termos do artigo 400 desta Portaria, à Procuradoria-Geral do Estado do Ceará para a devida inscrição na dívida ativa e regular cobrança com os documentos a seguir listados: I - Termo de Solicitação de Inscrição de Débito na Dívida Ativa do Estado do Ceará, constante do Anexo XV desta Consolidação; II - cópia da sentença; III - cópia da certidão de trânsito em julgado da decisão; IV - cópia da intimação para pagamento não cumprida pelo devedor; § 1º Sobre o débito vencido de custas processuais inscritas ou não na dívida ativa, incide correção monetária, juros e multas, previstos no art. 5º da Lei nº 14.605/2010, calculados a partir do trânsito em julgado da sentença, até a data do efetivo pagamento; § 2º Em caso de unidade judiciária assistida pela Secretaria Judiciária Única de Primeiro Grau (SEJUD) o envio descrito no caput será realizado pela Coordenadoria de Monitoramento das Custas Judiciais a partir de sua implantação, através do modulo GECOF/SAJPG em intimação eletrônica para a Procuradoria-Geral do Estado do Ceará (código 10526873, portal ESAJ).","v":["geral","civel","criminal","fazenda"],"th":["prazos","citacao","secretaria","atos_ordinatorios"]},{"n":"402","t":"Os processos judiciais eletrônicos com custas não recolhidas e arquivados até 05/03/2020 serão inspecionados pelos Gabinetes das unidades judiciais e monitorados pela Corregedoria-Geral da Justiça, através da Gerência de Correição e Apoio às Unidades Judiciárias, quanto ao regular recolhimento das despesas processuais devidas. §1º Serão auditados os autos processuais em que proferida sentença transitada em julgado, respeitado o prazo prescricional; 161 § 2º Em caso de Unidade judiciária assistida pela Secretaria Judiciária Única de Primeiro Grau (SEJUD), competirá aos Gabinetes das Varas, a devida atualização do valor da causa e a consequente emissão da guia de recolhimento; § 3º O gerenciamento de cobrança e o monitoramento das custas processuais finais, por meio do Módulo GECOF/SAJPG, será realizado pela Coordenadoria de Monitoramento de Custas a partir de sua implantação até o regular recolhimento nos feitos ainda não arquivados; § 4º Entende-se por monitoramento das custas o acompanhamento, controle e fiscalização do processamento de cobrança e do pagamento das despesas processuais; §5º O procedimento descrito nos arts. 399 ao 401 do presente normativo, será realizado sem a necessidade de desarquivamento dos autos.","v":["geral","civel","criminal","fazenda"],"th":["prazos","secretaria"]},{"n":"403","t":"As unidades judiciárias em suas autoinspeções, nos termos desta Consolidação, deverão fiscalizar o atendimento das regras previstas acerca do pagamento das despesas processuais. (Redação conferida pelo Prov. nº 01/2024/CGJCE, republicado por incorreção no DJeA de 01/02/2024)","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"404","t":"Identificadas despesas processuais não recolhidas em processos arquivados, serão adotadas imediatamente medidas para recuperação dos valores. §1º Se o débito for levantado em auditoria realizada pela Corregedoria-Geral da Justiça, o valor com as respectivas informações necessárias serão encaminhadas, por meio do Módulo GECOF/SAJPG, à Coordenadoria de Monitoramento das Custas Judiciais, competente para que determine a intimação da parte para efetivar o pagamento das despesas, no prazo de 15 (quinze) dias; § 2º Não realizado o pagamento no prazo estipulado, será efetivado o procedimento previsto no artigo 401 desta Consolidação; § 3º Se o débito for identificado em fiscalização do juiz da unidade judiciária, o magistrado, de ofício, determinará a intimação da parte para efetivar o pagamento das despesas, no prazo de 15 (quinze) dias.","v":["geral","civel","criminal","fazenda"],"th":["prazos","citacao"]},{"n":"405","t":"Na comarca de Fortaleza, a Diretoria do Fórum poderá delegar as providências previstas na parte final do § 1º do artigo 404 desta Consolidação, aos juízes auxiliares coordenadores das unidades judiciais de forma contínua ou instituir comissões para este fim. 162","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"406","t":"Nas causas em que concedida gratuidade judiciária no início do processo, havendo revogação do benefício, o juiz deverá intimar a parte para proceder ao recolhimento das despesas processuais, calculadas tomando-se por base o valor da causa atualizado, da data do ajuizamento até a data da cobrança, considerada a tabela de custas vigente.","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"407","t":"No caso de interposição de recurso inominado, no âmbito dos Juizados Especiais, ao recolher as custas, conforme o parágrafo único do art. 54 da Lei 9.099, de 26 de setembro de 1995, o recorrente deverá atualizar o valor da causa até a data do trânsito em julgado da sentença, nos termos do artigo 398 desta Consolidação.","v":["geral","civel","criminal","fazenda"],"th":[]},{"n":"408","t":"No que diz respeito às execuções fiscais, o executado recolherá as custas de acordo com o valor do débito atualizado pela Procuradoria Geral do ente público, sendo, necessariamente, pagas concomitantemente à quitação da dívida objeto da execução. Parágrafo único. O Tribunal de Justiça poderá estabelecer convênios com as Procuradorias do Estado e dos Municípios visando à efetivação do disposto no caput deste artigo.","v":["geral","civel","criminal","fazenda"],"th":["execucao"]},{"n":"409","t":"Compete aos magistrados, ao sentenciar nos processos judiciais, atentar, quando cabível, para a condenação do pagamento das custas processuais devidas e assegurar o cumprimento das diretrizes estabelecidas nesta Consolidação. § 1º Na certidão de trânsito em julgado do processo em que houver condenação do pagamento de custas, e na intimação referida no caput do artigo 399, deverá conter o valor atualizado da causa indicado na inicial, conforme as regras estabelecidas nesta Consolidação, para fins de orientação ao devedor acerca da monta que servirá de base para o enquadramento na tabela de custas; § 2º Ocorrendo inscrição na dívida ativa do crédito de custas processuais na PGE, nos termos do artigo 401 desta Consolidação, o magistrado competente deverá remeter à Corregedoria-Geral relação dos processos encaminhados para tanto, mensalmente, via SAJ-ADM, até a completa implantação do PJeCOR. 163","v":["geral","civel","criminal","fazenda"],"th":["citacao","mandados"]}]},{"num":"XXVI","title":"DO RECOLHIMENTO E DESTINAÇÃO DE VALORES","articles":[{"n":"439","t":"As Secretarias das Unidades Judiciárias, onde tramitem processos físicos, adotarão os seguintes livros, obrigatoriamente: 164 I - Livro de Registro de Processos (Livro Tombo), com espaço para anotar, quando for o caso, a baixa na distribuição e o arquivamento dos autos; II - Livro de Registro de Termos de Audiências, Criminais e Cíveis; III - Livro de Registro de Sentenças, Criminais e Cíveis; IV - Livro de Carga de Autos para Advogados, Defensores Públicos e Promotores de Justiça, podendo ser desdobrado um para cada rol de profissionais; V - Livro de Entrega de Autos às Partes, sem traslado, nos casos em lei permitidos; VI - Livro para Devolução de Cartas Precatórias, com espaço para anexação dos avisos de recepção; VII - Livro de Entrega e devolução de Mandados; VIII - Livro de Entrega de Alvarás; IX - Livro “Rol dos Culpados”; X - Livro de Atas do Tribunal do Júri; XI - Livro de remessa de autos para a contadoria. § 1º Os livros serão abertos e encerrados mediante termo com a data da abertura e do encerramento sendo que, no caso de livro de folhas soltas, assim expresso no termo de abertura, a data de encerramento será a do último ato registrado. Os livros serão, também, enumerados em ordem crescente e terão todas as suas folhas numeradas e rubricadas pelo Juiz, constando da capa o fim a que se destina e, da lombada, o número de ordem; § 2º Quando do encerramento do expediente, os livros de “vista” de autos serão diariamente encerrados pelo supervisor da unidade judiciária através da aposição de carimbo com o Termo de Encerramento, ou inexistindo o carimbo, de forma manuscrita, para fins de servir de prova de contagem de prazo; § 3º Os livros poderão ser de folhas soltas, sem prejuízo das formalidades previstas no parágrafo primeiro, devendo o supervisor da unidade judiciária mantê-lo em local adequado e seguro, devidamente ordenado, respondendo por sua guarda e conservação; § 4º Os livros de registro de sentenças e de registro de audiências, com 300 (trezentas) folhas poderão ser escriturados mediante processo manual, mecânico, eletrônico ou informatizado, em 165 folhas soltas, não autenticadas, devendo o registro ser encerrado no mesmo livro, ainda que ultrapasse 300 (trezentas) folhas, evitando-se, assim, a fragmentação de peças processuais; § 5º As sentenças serão registradas em ordem crescente de data; § 6º Nos autos do processo será certificado pelo supervisor da unidade judiciária ao registro da sentença, consignando o livro e as folhas em que se encontra.","v":["geral"],"th":["audiencias","prazos","mandados","secretaria"]},{"n":"440","t":"A Secretaria é obrigada a manter atualizado o banco de dados correspondentes aos processos existentes, para tanto consignando todos os dados da movimentação a eles inerentes por meio de digitação no Sistema Informatizado de Atualização Processual, a fim de que a consulta dos dados armazenados seja fiel e efetiva.","v":["geral"],"th":["secretaria"]},{"n":"441","t":"A partir da implantação integral de Sistema Processual Eletrônico, resultando total virtualização da unidade judiciária, esta ficará desobrigada de escriturar os livros constantes do artigo 444, na forma física. § 1º (Revogado pelo Prov. nº 22/2024/CGJCE, publicado no DJeA de 18/12/2024) § 2º Os livros físicos em uso deverão ser encerrados, procedendo-se o devido arquivamento.","v":["geral"],"th":[]}]},{"num":"XXVIII","title":"DAS DISPOSIÇÕES FINAIS","articles":[{"n":"442","t":"Eventuais dúvidas e casos omissos serão resolvidos pelo Corregedor-Geral da Justiça do Estado do Ceará.","v":["geral"],"th":[]},{"n":"443","t":"O presente ato normativo institui o Código de Normas Judiciais, no âmbito do Estado do Ceará, em substituição aos provimentos anteriores que versem sobre o tema, em especial os artigos 1º a 138 do Provimento nº 01/2007, datado de 19 de janeiro de 2007, desta Corregedoria-Geral da Justiça do Estado do Ceará.","v":["geral"],"th":[]},{"n":"444","t":"Revogam-se as disposições em contrário e em especial os Provimentos nºs 03/2001/CGJCE, 01/2007/CGJCE, 08/2007/CGJCE, 05/2008/CGJCE, 06/2008/CGJCE, 01/2009/CGJCE, 03/2009/CGJCE, 05/2009/CGJCE, 07/2009/CGJCE, 05/2010/CGJCE, 08/2010/CGJCE, 07/2011/CGJCE, 01/2013/CGJCE, 03/2013/CGJCE, 04/2013/CGJCE, 07/2013/CGJCE, 09/2013/CGJCE, 13/2013/CGJCE, 02/2014/CGJCE, 03/2014/CGJCE, 05/2014/CGJCE, 07/2014/CGJCE, 09/2015/CGJCE, 02/2016/CGJCE,","v":["geral"],"th":[]},{"n":"445","t":"Esta Consolidação Normativa entrará em vigor na data de sua publicação. 167 ANEXOS – PROVIMENTO Nº 02/2021/CGJCE ANEXO I – FORMULÁRIO ELETRÔNICO DE INSPEÇÃO JUDICIAL (art. 42 do Provimento nº 02/2021/CGJCE) (Alterado pelo Prov.06/2025//CGJCE, DJeA de 04/08/2025) 1. IDENTIFICAÇÃO DA INSPEÇÃO Unidade Endereço Telefones 2. JUIZ/JUÍZA – DADOS FUNCIONAIS E PESSOAIS Nome: Matrícula: ( ) Titular ( ) Respondendo ( ) Auxiliando ( ) Juiz ou Juíza de Direito Se o Juiz ou a Juíza estiver respondendo ou auxiliando: ( ) Juiz Substituto ou Juíza Substituta Portaria designatória: Portaria nº ____/____ ( ) Sim ( ) Não Exercício cumulativo: Quais? Ingresso na Magistratura: Ingresso na Vara: O Juiz ou a Juíza reside na Comarca? ( ) Sim ( ) Não O Juiz ou a Juíza exerce a função de Diretor ou Diretora do Fórum? ( ) Sim ( ) Não O Juiz ou a Juíza exerce outra função administrativa (CEJUSC, COMAN, Distribuição, Vice-Diretor, Vice-Diretora)? O Juiz ou a Juíza exerce a função de Juiz ou Juíza","v":["geral"],"th":["secretaria","atos_ordinatorios"]}]}];

// Flatten all articles
